  76203: { id: 76203, title: "12 Years a Slave", release_date: "2013-10-18", poster_path: "/xdANQijuNrJaw1HA61rDccME4Tm.jpg", backdrop_path: "/4Bb1kMIfrT2tYRZ9M6Jhqy6gkeF.jpg", overview: "In the pre-Civil War United States, Solomon Northup, a free black man from upstate New York, is abducted and sold into slavery. Facing cruelty as well as unexpected kindnesses Solomon struggles not only to stay alive, but to retain his dignity. In the twelfth year of his unforgettable odyssey, Solomon’s chance meeting with a Canadian abolitionist will forever alter his life.", vote_average: 7.932, vote_count: 11939, genre_ids: [18, 36], runtime: 134, popularity: 8.1469, original_language: "en" },
