  179144: { id: 179144, title: "The Great Beauty", release_date: "2013-05-21", poster_path: "/7suf0vaQfv5E7X1GVh4HJwK90yo.jpg", backdrop_path: "/4T5d7KGrpx3BTDq9IKm6KpMeeNp.jpg", overview: "Jep Gambardella has seduced his way through the lavish nightlife of Rome for decades, but after his 65th birthday and a shock from the past, Jep looks past the nightclubs and parties to find a timeless landscape of absurd, exquisite beauty.", vote_average: 7.51, vote_count: 3308, genre_ids: [18], runtime: 142, popularity: 3.0732, original_language: "it" },
  64682: { id: 64682, title: "The Great Gatsby", release_date: "2013-05-09", poster_path: "/tyxfCBQv6Ap74jcu3xd7aBiaa29.jpg", backdrop_path: "/5mQZqk2qSJCsYmvw1cQJLEcLNYM.jpg", overview: "An adaptation of F. Scott Fitzgerald's Long Island-set novel, where Midwesterner Nick Carraway is lured into the lavish world of his neighbor, Jay Gatsby. Soon enough, however, Carraway will see through the cracks of Gatsby's nouveau riche existence, where obsession, madness, and tragedy await.", vote_average: 7.352, vote_count: 12913, genre_ids: [18, 10749], runtime: 143, popularity: 8.3386, original_language: "en" },
