  62177: { id: 62177, title: "Brave", release_date: "2012-06-21", poster_path: "/1XAuDtMWpL0sYSFK0R6EZate2Ux.jpg", backdrop_path: "/qx9ts2hBYJrkIQxhryitxnLlm2u.jpg", overview: "In the mystical Scottish Highlands, Merida is the princess of a kingdom ruled by King Fergus and Queen Elinor. An unruly daughter and an accomplished archer, Merida one day defies a sacred custom of the land and inadvertently brings turmoil to the kingdom. In an attempt to set things right, Merida seeks out an eccentric old Wise Woman and is granted an ill-fated wish. Also figuring into Merida's quest — and serving as comic relief — are the kingdom's three lords: the enormous Lord MacGuffin, the surly Lord Macintosh, and the disagreeable Lord Dingwall.", vote_average: 7.022, vote_count: 14103, genre_ids: [16, 10751, 14, 12], runtime: 93, popularity: 16.9942, original_language: "en" },
