  72976: { id: 72976, title: "Lincoln", release_date: "2012-11-09", poster_path: "/5KeUqW6DpVtf8G9VMuI2l0XIPCo.jpg", backdrop_path: "/hwOFrwHladQ8FktYn3aJNAt8KA1.jpg", overview: "The revealing story of the 16th US President's tumultuous final months in office. In a nation divided by war and the strong winds of change, Lincoln pursues a course of action designed to end the war, unite the country and abolish slavery. With the moral courage and fierce determination to succeed, his choices during this critical moment will change the fate of generations to come.", vote_average: 6.848, vote_count: 4039, genre_ids: [36, 18], runtime: 150, popularity: 5.9301, original_language: "en" },
