  37724: { id: 37724, title: "Skyfall", release_date: "2012-10-24", poster_path: "/d0IVecFQvsGdSbnMAHqiYsNYaJT.jpg", backdrop_path: "/qB2eFmGEh5YCzhXUpz7As2PaDCh.jpg", overview: "When Bond's latest assignment goes gravely wrong, agents around the world are exposed and MI6 headquarters is attacked. While M faces challenges to her authority and position from Gareth Mallory, the new Chairman of the Intelligence and Security Committee, it's up to Bond, aided only by field agent Eve, to locate the mastermind behind the attack.", vote_average: 7.3, vote_count: 16065, genre_ids: [28, 12, 53], runtime: 143, popularity: 8.5552, original_language: "en" },
