  44826: { id: 44826, title: "Hugo", release_date: "2011-11-22", poster_path: "/1dxRq3o3l3bVWNRvvSb7rRf68qp.jpg", backdrop_path: "/Aj81Gu3u1a64qXFOLDuF5gdxyy0.jpg", overview: "Orphaned and alone except for an uncle, Hugo Cabret lives in the walls of a train station in 1930s Paris. Hugo's job is to oil and maintain the station's clocks, but to him, his more important task is to protect a broken automaton and notebook left to him by his late father. Accompanied by the goddaughter of an embittered toy merchant, Hugo embarks on a quest to solve the mystery of the automaton and find a place he can call home.", vote_average: 7.174, vote_count: 7631, genre_ids: [12, 18, 10751], runtime: 126, popularity: 7.2303, original_language: "en" },
