  50014: { id: 50014, title: "The Help", release_date: "2011-08-09", poster_path: "/3kmfoWWEc9Vtyuaf9v5VipRgdjx.jpg", backdrop_path: "/wyvUmyzqGOBDyqLHRSukGDjI7bH.jpg", overview: "Aibileen Clark is a middle-aged African-American maid who has spent her life raising white children and has recently lost her only son; Minny Jackson is an African-American maid who has often offended her employers despite her family's struggles with money and her desperate need for jobs; and Eugenia \"Skeeter\" Phelan is a young white woman who has recently moved back home after graduating college to find out her childhood maid has mysteriously disappeared. These three stories intertwine to explain how life in Jackson, Mississippi revolves around \"the help\"; yet they are always kept at a certain distance because of racial lines.", vote_average: 8.198, vote_count: 8973, genre_ids: [18], runtime: 146, popularity: 11.1346, original_language: "en" },
