  45269: { id: 45269, title: "The King's Speech", release_date: "2010-11-26", poster_path: "/pVNKXVQFukBaCz6ML7GH3kiPlQP.jpg", backdrop_path: "/6dyqfaPdeM5Z22ylw9ZTyjROBo7.jpg", overview: "The King's Speech tells the story of the man who became King George VI, the father of Queen Elizabeth II. After his brother abdicates, George ('Bertie') reluctantly assumes the throne. Plagued by a dreaded stutter and considered unfit to be king, Bertie engages the help of an unorthodox speech therapist named Lionel Logue. Through a set of unexpected techniques, and as a result of an unlikely friendship, Bertie is able to find his voice and boldly lead the country into war.", vote_average: 7.733, vote_count: 9263, genre_ids: [18, 36], runtime: 118, popularity: 8.3208, original_language: "en" },
  37799: { id: 37799, title: "The Social Network", release_date: "2010-10-01", poster_path: "/n0ybibhJtQ5icDqTp8eRytcIHJx.jpg", backdrop_path: "/1GlZNA9L5trst3ItgRiyQTUH1uf.jpg", overview: "In 2003, Harvard undergrad and computer programmer Mark Zuckerberg begins work on a new concept that eventually turns into the global social network known as Facebook. Six years later, Mark is one of the youngest billionaires ever, but his unprecedented success leads to both personal and legal complications when he ends up on the receiving end of two lawsuits, one involving his former friend.", vote_average: 7.372, vote_count: 13091, genre_ids: [18], runtime: 121, popularity: 12.672, original_language: "en" },
  7978: { id: 7978, title: "The Wolfman", release_date: "2010-02-10", poster_path: "/fQqPoAHvHicie1ttuiV2q0yv9V7.jpg", backdrop_path: "/kTDunJrHYsH6o1wmD6iT4wXkuHo.jpg", overview: "Lawrence Talbot, an American man on a visit to Victorian London to make amends with his estranged father, gets bitten by a werewolf and, after a moonlight transformation, leaves him with a savage hunger for flesh.", vote_average: 5.884, vote_count: 2168, genre_ids: [27], runtime: 103, popularity: 5.1297, original_language: "en" },
