  16869: { id: 16869, title: "Inglourious Basterds", release_date: "2009-08-02", poster_path: "/7sfbEnaARXDDhKm0CZ7D7uc2sbo.jpg", backdrop_path: "/hwNtEmmugU5Yd7hpfprNWI0DGIn.jpg", overview: "In Nazi-occupied France during World War II, a group of Jewish-American soldiers known as \"The Basterds\" are chosen specifically to spread fear throughout the Third Reich by scalping and brutally killing Nazis. The Basterds, lead by Lt. Aldo Raine soon cross paths with a French-Jewish teenage girl who runs a movie theater in Paris which is targeted by the soldiers.", vote_average: 8.217, vote_count: 24053, genre_ids: [18, 53, 10752], runtime: 153, popularity: 17.6611, original_language: "en" },
  13475: { id: 13475, title: "Star Trek", release_date: "2009-05-06", poster_path: "/hN2ZtF3Uw6mhIHZiqL0SKzELtKn.jpg", backdrop_path: "/cqXEwYFcwyKPZCKl1jAPaG3cMsl.jpg", overview: "The fate of the galaxy rests in the hands of bitter rivals. One, James Kirk, is a delinquent, thrill-seeking Iowa farm boy. The other, Spock, a Vulcan, was raised in a logic-based society that rejects all emotion. As fiery instinct clashes with calm reason, their unlikely but powerful partnership is the only thing capable of leading their crew through unimaginable danger, boldly going where no one has gone before. The human adventure has begun again.", vote_average: 7.429, vote_count: 10442, genre_ids: [878, 28, 12], runtime: 127, popularity: 8.4411, original_language: "en" },
