  4922: { id: 4922, title: "The Curious Case of Benjamin Button", release_date: "2008-12-25", poster_path: "/26wEWZYt6yJkwRVkjcbwJEFh9IS.jpg", backdrop_path: "/2fswjyrY3GEzeoVn6mF8pNeNcgf.jpg", overview: "Born under unusual circumstances, Benjamin Button springs into being as an elderly man in a New Orleans nursing home and ages in reverse. Twelve years after his birth, he meets Daisy, a child who flits in and out of his life as she grows up to be a dancer. Though he has all sorts of unusual adventures over the course of his life, it is his relationship with Daisy, and the hope that they will come together at the right time, that drives Benjamin forward.", vote_average: 7.598, vote_count: 13659, genre_ids: [18, 14, 10749], runtime: 166, popularity: 8.6899, original_language: "en" },
