  1165: { id: 1165, title: "The Queen", release_date: "2006-09-15", poster_path: "/v08RH5Cx9EFAQMBWQuE5jHAgHYs.jpg", backdrop_path: "/zpBl7qfBB1ir1BVNQtPlPwQ6IFd.jpg", overview: "The Queen is an intimate behind the scenes glimpse at the interaction between HM Elizabeth II and Prime Minister Tony Blair during their struggle, following the death of Diana, to reach a compromise between what was a private tragedy for the Royal family and the public's demand for an overt display of mourning.", vote_average: 6.954, vote_count: 1423, genre_ids: [18, 36], runtime: 103, popularity: 3.7346, original_language: "en" },
