  254: { id: 254, title: "King Kong", release_date: "2005-12-12", poster_path: "/6a2HY6UmD7XiDD3NokgaBAXEsD2.jpg", backdrop_path: "/mRM2NB0i3wv4HqxXvwIjEVi4Qqq.jpg", overview: "In 1933 New York, an overly ambitious movie producer coerces his cast and hired ship crew to travel to mysterious Skull Island, where they encounter Kong, a giant ape who is immediately smitten with the leading lady.", vote_average: 6.888, vote_count: 8455, genre_ids: [12, 18, 28], runtime: 188, popularity: 11.6247, original_language: "en" },
