  10337: { id: 10337, title: "Bugsy", release_date: "1991-12-10", poster_path: "/hSGncpMByW8zx2aOSXdZB0e70yA.jpg", backdrop_path: "/w5q18zHh6Ql0yC2OIn5wk1Gs3Me.jpg", overview: "New York gangster Ben 'Bugsy' Siegel takes a brief business trip to Los Angeles. A sharp-dressing womanizer with a foul temper, Siegel doesn't hesitate to kill or maim anyone crossing him. In L.A. the life, the movies, and most of all strong-willed Virginia Hill detain him while his family wait back home. Then a trip to a run-down gambling joint at a spot in the desert known as Las Vegas gives him his big idea.", vote_average: 6.341, vote_count: 433, genre_ids: [80, 18, 9648], runtime: 136, popularity: 3.0304, original_language: "en" },
  1406: { id: 1406, title: "City Slickers", release_date: "1991-06-07", poster_path: "/9DVZpm9pQNB3M17cRo752zqUYhL.jpg", backdrop_path: "/6aavXoygR0nZP4kIKQLdaXLO3z0.jpg", overview: "Three New York businessmen decide to take a \"Wild West\" vacation that turns out not to be the relaxing vacation they had envisioned.", vote_average: 6.461, vote_count: 861, genre_ids: [35, 37], runtime: 114, popularity: 3.1509, original_language: "en" },
  820: { id: 820, title: "JFK", release_date: "1991-12-20", poster_path: "/r0VWVTYlqdRCK5ZoOdNnHdqM2gt.jpg", backdrop_path: "/77gjiDyD94aJfqZq6AJAcMLxZhd.jpg", overview: "Follows the investigation into the assassination of President John F. Kennedy led by New Orleans district attorney Jim Garrison.", vote_average: 7.602, vote_count: 2397, genre_ids: [18, 53, 36], runtime: 189, popularity: 5.7461, original_language: "en" },
  38251: { id: 38251, title: "Mediterraneo", release_date: "1991-02-02", poster_path: "/omFU47TZSR7xAAZcDHKM48SmVwe.jpg", backdrop_path: "/jM486vasW37coo58V7siUPEZKco.jpg", overview: "Greek Sea, World War II. An Italian ship leaves a handful of soldiers in a little island; their mission is to spot enemy ships and to hold the island in case of attack. The village of the island seems abandoned and there isn't a single enemy in sight, so the soldiers begin to relax a little. Things change when their ship is hit and destroyed by the enemy, and the soldiers find themselves abandoned there.", vote_average: 7.622, vote_count: 1064, genre_ids: [35, 10749, 10752], runtime: 96, popularity: 1.7952, original_language: "it" },
