  274: { id: 274, title: "The Silence of the Lambs", release_date: "1991-02-14", poster_path: "/uS9m8OBk1A8eM9I042bx8XXpqAq.jpg", backdrop_path: "/aYcnDyLMnpKce1FOYUpZrXtgUye.jpg", overview: "Clarice Starling is a top student at the FBI's training academy.  Jack Crawford wants Clarice to interview Dr. Hannibal Lecter, a brilliant psychiatrist who is also a violent psychopath, serving life behind bars for various acts of murder and cannibalism.  Crawford believes that Lecter may have insight into a case and that Starling, as an attractive young woman, may be just the bait to draw him out.", vote_average: 8.345, vote_count: 17877, genre_ids: [80, 53, 18], runtime: 119, popularity: 6.1799, original_language: "en" },
  11673: { id: 11673, title: "Cyrano de Bergerac", release_date: "1990-03-28", poster_path: "/80XJ5UkGuYTKDuALeG03BLk1OT1.jpg", backdrop_path: "/bvpYJgsC5jcMJd43HRHXUQw7j5O.jpg", overview: "Famed swordsman and poet Cyrano de Bergerac is in love with his cousin Roxane. He has never expressed his love for her as he his large nose undermines his self-confidence. Then he finds a way to express his love to her, indirectly.", vote_average: 7.319, vote_count: 823, genre_ids: [18, 35, 36, 10749], runtime: 137, popularity: 2.2457, original_language: "fr" },
  581: { id: 581, title: "Dances with Wolves", release_date: "1990-03-30", poster_path: "/hw0ZEHAaTqTxSXGVwUFX7uvanSA.jpg", backdrop_path: "/f6YvaVqqNjAHYI4uC64ChpwqrUg.jpg", overview: "Wounded Civil War soldier John Dunbar tries to commit suicide—and becomes a hero instead. As a reward, he's assigned to his dream post, a remote junction on the Western frontier, and soon makes unlikely friends with the local Sioux tribe.", vote_average: 7.837, vote_count: 4658, genre_ids: [12, 18, 37], runtime: 181, popularity: 13.0961, original_language: "en" },
