  251: { id: 251, title: "Ghost", release_date: "1990-07-13", poster_path: "/w9RaPHov8oM5cnzeE27isnFMsvS.jpg", backdrop_path: "/6nLdSON3ErniBZTXWG7WRqs5jGz.jpg", overview: "After a young man is murdered, his spirit stays behind to warn his lover of impending danger, with the help of a reluctant psychic.", vote_average: 7.232, vote_count: 5986, genre_ids: [14, 10749, 53], runtime: 127, popularity: 12.1954, original_language: "en" },
