  41834: { id: 41834, title: "Journey of Hope", release_date: "1990-09-28", poster_path: "/dbNpWp7sGGIN2Qk8v10oxvNKFfq.jpg", backdrop_path: "/6UyKfxOKWIDyoNIljjoXgo2F81B.jpg", overview: "In a village in eastern Turkey, tales of the economic success of Turks in Switzerland inspire Haydar to convince his wife Meryem that they must go. He sells their livestock and small plot of land in exchange for passage for two. He wants to leave their seven children in the care of the eldest and his parents; his father advises him to take one son to be educated in Europe. Will anyone reach the land of promise?", vote_average: 7.139, vote_count: 36, genre_ids: [18], runtime: 110, popularity: 0.8761, original_language: "de" },
