  1669: { id: 1669, title: "The Hunt for Red October", release_date: "1990-03-02", poster_path: "/yVl7zidse4KiWtGMqHFtZCx4X3N.jpg", backdrop_path: "/5jCpCFrku6wmCZOYZWhHOC2j8IU.jpg", overview: "A new technologically-superior Soviet nuclear sub, the Red October, is heading for the U.S. coast under the command of Captain Marko Ramius. The American government thinks Ramius is planning to attack. Lone CIA analyst Jack Ryan has a different idea: he thinks Ramius is planning to defect, but he has only a few hours to find him and prove it - because the entire Russian naval and air commands are trying to find Ramius, too. The hunt is on!", vote_average: 7.382, vote_count: 3600, genre_ids: [28, 53], runtime: 135, popularity: 6.1577, original_language: "en" },
