  268: { id: 268, title: "Batman", release_date: "1989-06-21", poster_path: "/cij4dd21v2Rk2YtUQbV5kW69WB2.jpg", backdrop_path: "/zlsaQEE26TS34ziXAiNIAqa0MLX.jpg", overview: "Having witnessed his parents' brutal murder as a child, millionaire philanthropist Bruce Wayne fights crime in Gotham City disguised as Batman, a costumed hero who strikes fear into the hearts of villains. But when a deformed madman known as 'The Joker' seizes control of Gotham's criminal underworld, Batman must face his most ruthless nemesis ever while protecting both his identity and his love interest, reporter Vicki Vale.", vote_average: 7.231, vote_count: 8520, genre_ids: [14, 28, 80], runtime: 126, popularity: 9.0863, original_language: "en" },
