  207: { id: 207, title: "Dead Poets Society", release_date: "1989-06-02", poster_path: "/erzbMlcNHOdx24AXOcn2ZKA7R1q.jpg", backdrop_path: "/yYvBNN96Ym3wtPxGCFl7F888WwB.jpg", overview: "At an elite, old-fashioned boarding school in New England, a passionate English teacher inspires his students to rebel against convention and seize the potential of every day, courting the disdain of the stern headmaster.", vote_average: 8.3, vote_count: 12523, genre_ids: [18], runtime: 129, popularity: 17.2475, original_language: "en" },
  403: { id: 403, title: "Driving Miss Daisy", release_date: "1989-12-13", poster_path: "/iaCzvcY42HihFxQBTZCTKMpsI0P.jpg", backdrop_path: "/4XC0HwRNOvub6xksENsOl68zHOn.jpg", overview: "The story of an old Jewish widow named Daisy Werthan and her relationship with her black chauffeur, Hoke. From an initial mere work relationship grew in 25 years a strong friendship between the two very different characters, in a time when those types of relationships were shunned.", vote_average: 7.235, vote_count: 1768, genre_ids: [18], runtime: 99, popularity: 3.0918, original_language: "en" },
