  10269: { id: 10269, title: "Yentl", release_date: "1983-11-18", poster_path: "/AcCX4tKqwP5BTfRTQEqZW3qabl3.jpg", backdrop_path: "/oMRr5B0OkOJ8vjwR2w5Xw7YNp9W.jpg", overview: "In a time when girls were forbidden to study religious scriptures, a Jewish girl masquerades as a boy to enter religious training and unexpectedly finds love along the way.", vote_average: 6.687, vote_count: 259, genre_ids: [10402, 18, 10749], runtime: 132, popularity: 2.0159, original_language: "en" },
