  783: { id: 783, title: "Gandhi", release_date: "1982-12-01", poster_path: "/rOXftt7SluxskrFrvU7qFJa5zeN.jpg", backdrop_path: "/AsXHPS2U58MDAkoEJUT7Vlxndfu.jpg", overview: "In the early years of the 20th century, Mohandas K. Gandhi, a British-trained lawyer, forsakes all worldly possessions to take up the cause of Indian independence. Faced with armed resistance from the British government, Gandhi adopts a policy of 'passive resistance', endeavouring to win freedom for his people without resorting to bloodshed.", vote_average: 7.561, vote_count: 2494, genre_ids: [18, 36], runtime: 192, popularity: 5.98, original_language: "en" },
  15600: { id: 15600, title: "Missing", release_date: "1982-02-12", poster_path: "/fAAhC4RkpXu7SJgIESWQwVxcelo.jpg", backdrop_path: "/49rQkLwYxUK7zQP69e87MspS4E2.jpg", overview: "Based on the real-life experiences of Ed Horman. A conservative American businessman travels to Chile to investigate the sudden disappearance of his son after a military takeover. Accompanied by his son's wife he uncovers a trail of cover-ups that implicate the US State department which supports the dictatorship.", vote_average: 7.246, vote_count: 424, genre_ids: [18, 9648, 53], runtime: 123, popularity: 2.4094, original_language: "en" },
  15764: { id: 15764, title: "Sophie's Choice", release_date: "1982-12-08", poster_path: "/rZDPbPTFwuKgr5b9jixGFNYkGYt.jpg", backdrop_path: "/uiUpvnv8zgA2pm1J7tT8DPLxh84.jpg", overview: "Stingo, a young writer, moves to Brooklyn in 1947 to begin work on his first novel. As he becomes friendly with Sophie and her lover Nathan, he learns that she is a Holocaust survivor. Flashbacks reveal her harrowing story, from pre-war prosperity to Auschwitz. In the present, Sophie and Nathan's relationship increasingly unravels as Stingo grows closer to Sophie and Nathan's fragile mental state becomes ever more apparent.", vote_average: 7.321, vote_count: 930, genre_ids: [18, 10749, 10752], runtime: 151, popularity: 4.0408, original_language: "en" },
