  9576: { id: 9576, title: "Tootsie", release_date: "1982-12-17", poster_path: "/ngyCzZwb9y5sMUCig5JQT4Y33Q.jpg", backdrop_path: "/dGRGes6Yw0vK1IymLatHBXGvvpS.jpg", overview: "When struggling, out of work actor Michael Dorsey secretly adopts a female alter ego – Dorothy Michaels – in order to land a part in a daytime drama, he unwittingly becomes a feminist icon and ends up in a romantic pickle.", vote_average: 7.2, vote_count: 1914, genre_ids: [35, 10749], runtime: 116, popularity: 3.667, original_language: "en" },
