  13665: { id: 13665, title: "Arthur", release_date: "1981-07-17", poster_path: "/m8yOFRDVZPxtsr4D2hVdzls6q6t.jpg", backdrop_path: "/tUwK3xxx6D5ygfC49K3AYiLxeII.jpg", overview: "Arthur is a 30-year-old child who will inherit $750 million if he complies with his family's demands and marries the woman of their choosing.", vote_average: 6.5, vote_count: 466, genre_ids: [35, 18, 10749], runtime: 97, popularity: 2.789, original_language: "en" },
  9443: { id: 9443, title: "Chariots of Fire", release_date: "1981-05-15", poster_path: "/qnRaum8k0HqGRml2i7OawFqUtEb.jpg", backdrop_path: "/nEeq7iQDbsj4qRt9E11PvQOWKvQ.jpg", overview: "In the class-obsessed and religiously divided UK of the early 1920s, two determined young runners train for the 1924 Paris Olympics. Eric Liddell, a devout Christian born to Scottish missionaries in China, sees running as part of his worship of God's glory and refuses to train or compete on the Sabbath. Harold Abrahams overcomes anti-Semitism and class bias, but neglects his beloved sweetheart in his single-minded quest.", vote_average: 6.8, vote_count: 1031, genre_ids: [18, 36], runtime: 123, popularity: 4.193, original_language: "en" },
  113815: { id: 113815, title: "From Mao to Mozart: Isaac Stern in China", release_date: "1981-02-23", poster_path: "/yZnnHlzQ8Q6dtylqlxDxbgHhz60.jpg", backdrop_path: "/kTjZD0pGsWZ5QdOyzEvJAufG4l7.jpg", overview: "A beautiful expression of two differing cultures brought together by the warmth and dedication of a great musician and humanitarian. In 1979, as China re-opened its doors to the West, virtuoso Isaac Stern received an unprecedented government invitation to tour the country.", vote_average: 5.9, vote_count: 10, genre_ids: [99, 10402, 10751], runtime: 84, popularity: 0.4624, original_language: "en" },
  537319: { id: 537319, title: "Behind Glass", release_date: "1981-02-19", poster_path: null, backdrop_path: null, overview: "A radio-reporter watches a window-washer and they become lovers. Their relationship starts fine but after a while it turns into a power struggle between the two guys of very different background and interests.", vote_average: 3.333, vote_count: 3, genre_ids: [10749], runtime: 70, popularity: 0.2857, original_language: "nl" },
  38772: { id: 38772, title: "Melvin and Howard", release_date: "1980-09-19", poster_path: "/1oN3ZQPyJcSqoj0An39FSD8VFmC.jpg", backdrop_path: "/lnRJEtthNXF3ded8aI0ND5ETjf9.jpg", overview: "The story of hard-luck Melvin Dummar, who claimed to have received a will naming him an heir to the fortune of Howard Hughes. Inspired by real events.", vote_average: 6.513, vote_count: 75, genre_ids: [35, 18], runtime: 95, popularity: 1.3872, original_language: "en" },
  11911: { id: 11911, title: "Mephisto", release_date: "1981-02-11", poster_path: "/SNJoUTU8PSxQlj3RkrwYGOQPyj.jpg", backdrop_path: "/ncO9pjB0PZ603Tp1LgbNpkeUxzL.jpg", overview: "A German stage actor finds unexpected success and mixed blessings in the popularity of his performance in a Faustian play as the Nazis take power in pre-WWII Germany. As his associates and friends flee or are ground under by the Nazi terror, the popularity of his character supercedes his own existence until he finds that his best performance is keeping up appearances for his Nazi patrons.", vote_average: 7.221, vote_count: 145, genre_ids: [18], runtime: 145, popularity: 1.3785, original_language: "de" },
  21028: { id: 21028, title: "Moscow Does Not Believe in Tears", release_date: "1980-02-11", poster_path: "/r0VULHcfJ2njqOI0GuQHe4TNF5e.jpg", backdrop_path: "/eVbDEVjNIj2fRBiWObMTcuI5bI3.jpg", overview: "Living together in a workers' dorm, Katerina and her friends are determined to make it in Moscow. But when a boorish cameraman forces himself on her, Katerina finds herself pregnant and alone as her friends move on. Twenty years later, Katerina is a factory director, outpacing her old roommates career-wise, yet still alone but for her daughter. Love seems possible again when she meets a genial mechanic.", vote_average: 7.559, vote_count: 279, genre_ids: [18, 35, 10749], runtime: 142, popularity: 2.2977, original_language: "ru" },
  11816: { id: 11816, title: "On Golden Pond", release_date: "1981-12-04", poster_path: "/ic4f03J6pnf9cpQmVDABFhUpbCU.jpg", backdrop_path: "/ydGY4z0hN8XebemBOJgnTD4ceiJ.jpg", overview: "For Norman and Ethel Thayer, this summer on golden pond is filled with conflict and resolution. When their daughter Chelsea arrives, the family is forced to renew the bonds of love and overcome the generational friction that has existed for years.", vote_average: 7.273, vote_count: 511, genre_ids: [18, 10749], runtime: 109, popularity: 2.4223, original_language: "en" },
  62204: { id: 62204, title: "Quest for Fire", release_date: "1981-12-16", poster_path: "/tyzW1M00xfHKNtmTlT6wJ3F4pNr.jpg", backdrop_path: "/5l3Xb2WQR0nXiVhbj5rAv0z4xsZ.jpg", overview: "In the prehistoric world, a Cro-Magnon tribe depends on an ever-burning source of fire, which eventually extinguishes. Lacking the knowledge to start a new fire, the tribe sends three warriors on a quest for more. With the tribe's future at stake, the warriors make their way across a treacherous landscape full of hostile tribes and monstrous beasts. On their journey, they encounter Ika, a woman who has the knowledge they seek.", vote_average: 7.037, vote_count: 573, genre_ids: [12, 18], runtime: 100, popularity: 3.3307, original_language: "fr" },
  85: { id: 85, title: "Raiders of the Lost Ark", release_date: "1981-06-12", poster_path: "/ceG9VzoRAVGwivFU403Wc3AHRys.jpg", backdrop_path: "/zPACwR32amTNvzId9qyapCWXYDJ.jpg", overview: "When Dr. Indiana Jones – the tweed-suited professor who just happens to be a celebrated archaeologist – is hired by the government to locate the legendary Ark of the Covenant, he finds himself up against the entire Nazi regime.", vote_average: 7.9, vote_count: 13565, genre_ids: [12, 28], runtime: 115, popularity: 14.174, original_language: "en" },
  18254: { id: 18254, title: "Reds", release_date: "1981-12-25", poster_path: "/AeiKdVVM93fwfQG1m3N0cgVZgHl.jpg", backdrop_path: "/cDdB8JBflT4vBYlftoopSdTf4Wz.jpg", overview: "An account of the revolutionary years of the legendary American journalist John Reed, who shared his adventurous professional life with his radical commitment to the socialist revolution in Russia, his dream of spreading its principles among the members of the American working class, and his troubled romantic relationship with the writer Louise Bryant.", vote_average: 6.874, vote_count: 374, genre_ids: [18, 36, 10749], runtime: 195, popularity: 2.7508, original_language: "en" },
  20813: { id: 20813, title: "A Little Romance", release_date: "1979-04-27", poster_path: "/i6M3sxY2jHVey55qWmgTPomSuvc.jpg", backdrop_path: "/z7cqP2bizuR0jUCDg57g9fKYrD0.jpg", overview: "Intellectually precocious teenager Lauren King lives in Paris with her somewhat ditzy mother. On a movie set, she strikes up a friendship with teenage film buff Daniel Michon. After Lauren's mother forbids her to date the outspoken Daniel, the young lovebirds team up with eccentric pickpocket Julius to run away to Venice, where, according to legend, a couple who kiss under the Bridge of Sighs will stay together forever.", vote_average: 6.835, vote_count: 82, genre_ids: [35, 10749], runtime: 108, popularity: 1.2765, original_language: "en" },
  348: { id: 348, title: "Alien", release_date: "1979-05-25", poster_path: "/vfrQk5IPloGg1v9Rzbh2Eg3VGyM.jpg", backdrop_path: "/cEobq5QrnOJjO6giDs8q4RxmMKh.jpg", overview: "During its return to the earth, commercial spaceship Nostromo intercepts a distress signal from a distant planet. When a three-member team of the crew discovers a chamber containing thousands of eggs on the planet, a creature inside one of the eggs attacks an explorer. The entire crew is unaware of the impending nightmare set to descend upon them when the alien parasite planted inside its unfortunate host is birthed.", vote_average: 8.17, vote_count: 16256, genre_ids: [27, 878], runtime: 117, popularity: 22.6329, original_language: "en" },
