  10322: { id: 10322, title: "Being There", release_date: "1979-12-19", poster_path: "/3RO3jbCKEey2T9bYFkYt9xpwen9.jpg", backdrop_path: "/lzB7ehFA3XQH1rD4kCE2aziAzFO.jpg", overview: "A simple-minded gardener named Chance has spent all his life in the Washington D.C. house of an old man. When the man dies, Chance is put out on the street with no knowledge of the world except what he has learned from television.", vote_average: 7.591, vote_count: 1118, genre_ids: [35, 18], runtime: 130, popularity: 2.8618, original_language: "en" },
