  40842: { id: 40842, title: "Norma Rae", release_date: "1979-03-02", poster_path: "/6au7WBVYoKhV1jORyFSIRszb46S.jpg", backdrop_path: "/5l58tPlYA1JaacBvcojq3YMQyL5.jpg", overview: "Norma Rae is a southern textile worker employed in a factory with intolerable working conditions. This concern about the situation gives her the gumption to be the key associate to a visiting labor union organizer. Together, they undertake the difficult, and possibly dangerous, struggle to unionize her factory.", vote_average: 7.214, vote_count: 199, genre_ids: [18], runtime: 110, popularity: 2.0304, original_language: "en" },
