  1891: { id: 1891, title: "The Empire Strikes Back", release_date: "1980-05-20", poster_path: "/nNAeTmF4CtdSgMDplXTDPOpYzsX.jpg", backdrop_path: "/aJCtkxLLzkk1pECehVjKHA2lBgw.jpg", overview: "The epic saga continues as Luke Skywalker, in hopes of defeating the evil Galactic Empire, learns the ways of the Jedi from aging master Yoda. But Darth Vader is more determined than ever to capture Luke. Meanwhile, rebel leader Princess Leia, cocky Han Solo, Chewbacca, and droids C-3PO and R2-D2 are thrown into various stages of capture, betrayal and despair.", vote_average: 8.4, vote_count: 18314, genre_ids: [12, 28, 878], runtime: 124, popularity: 13.6259, original_language: "en" },
