  4267: { id: 4267, title: "Get Out Your Handkerchiefs", release_date: "1978-01-11", poster_path: "/vS4BlPEJV9QBS7W0urYlomYNWG7.jpg", backdrop_path: "/vtasUI25QQHG8cwwk7dNyAdk6vh.jpg", overview: "Solange is seriously depressed, and her kindhearted husband, Raoul, makes it his mission to cure her doldrums. After many failed attempts to cheer her up, Raoul hits upon a possible solution: find his wife a lover. Unfortunately, his choice, Stéphane, proves to be just as ineffectual in restoring her flagging spirits. In the end, the gorgeous Solange finds her own, highly problematic tonic to her troubles in the form of a 13-year-old boy.", vote_average: 6.563, vote_count: 143, genre_ids: [10749, 35, 18], runtime: 108, popularity: 2.1914, original_language: "fr" },
  12185: { id: 12185, title: "Heaven Can Wait", release_date: "1978-06-28", poster_path: "/h1yOiO9cow6gwmGxSAWvPdY4lhJ.jpg", backdrop_path: "/yucBYHGAMaTu2HsxM2k9JWRxSlj.jpg", overview: "Joe Pendleton is a quarterback preparing to lead his team to the superbowl when he is almost killed in an accident. An overanxious angel plucks him to heaven only to discover that he wasn't ready to die, and that his body has been cremated. A new body must be found, and that of a recently-murdered millionaire is chosen. His wife and accountant—the murderers—are confused by this development, as he buys the L.A. Rams in order to once again quarterback them into the Superbowl.", vote_average: 6.636, vote_count: 439, genre_ids: [14, 35, 10749], runtime: 101, popularity: 2.7971, original_language: "en" },
  11327: { id: 11327, title: "Midnight Express", release_date: "1978-08-31", poster_path: "/mIzGfVCSWmmYjLIIbA2BX3rlV56.jpg", backdrop_path: "/f4dcx5U9X3w27e8iithmsaohF5t.jpg", overview: "Billy Hayes is caught attempting to smuggle drugs out of Turkey. The Turkish courts decide to make an example of him, sentencing him to more than 30 years in prison. Hayes has two opportunities for release: the appeals made by his lawyer, his family, and the American government, or the \"Midnight Express\".", vote_average: 7.449, vote_count: 1882, genre_ids: [18, 80], runtime: 121, popularity: 4.4857, original_language: "en" },
  92215: { id: 92215, title: "Scared Straight!", release_date: "1978-11-02", poster_path: "/gZsuFndUZlf12g71enRaO3y7vjq.jpg", backdrop_path: "/rJePnjeUmZ1znNGASCsbzkipSEc.jpg", overview: "The filmed depiction of a program where convicts tell troubled kids about the horrors of prison life.  Preserved by the Academy Film Archive in 2007.", vote_average: 7.455, vote_count: 11, genre_ids: [99], runtime: 52, popularity: 0.31, original_language: "en" },
  11121: { id: 11121, title: "Tess", release_date: "1979-10-06", poster_path: "/xejUFnoAVxzvU95o2jlzG2USmY.jpg", backdrop_path: "/hEVAABU2c86MU42jlnGRM9FcCq5.jpg", overview: "A strong-willed peasant girl is sent by her father to the estate of some local aristocrats to capitalize on a rumour that their families are from the same line. This fateful visit commences an epic narrative of sex, class, betrayal, and revenge.", vote_average: 7.082, vote_count: 377, genre_ids: [18, 10749], runtime: 172, popularity: 2.7797, original_language: "en" },
  17264: { id: 17264, title: "The Black Stallion", release_date: "1979-10-13", poster_path: "/uZtNc31LR5Ik3ZVo2jxwOvhkNRC.jpg", backdrop_path: "/am84QBW5S17uKUeuWvjLIS8urrr.jpg", overview: "While traveling with his father, young Alec becomes fascinated by a mysterious Arabian stallion that is brought on board and stabled in the ship he is sailing on. When it tragically sinks both he and the horse survive only to be stranded on a deserted island. He befriends it, so when finally rescued both return to his home where they soon meet Henry Dailey, a once successful trainer. Together they begin training the horse to race against the fastest ones in the world.", vote_average: 7.002, vote_count: 321, genre_ids: [10751, 12], runtime: 118, popularity: 2.1887, original_language: "en" },
  24153: { id: 24153, title: "The Buddy Holly Story", release_date: "1978-05-18", poster_path: "/4Zu9YdN5O4jnXJmqBMHckkKpJ2S.jpg", backdrop_path: "/tdpHGUxipEmJZvtEmTCcmpE2HMp.jpg", overview: "A chronicle of the rise and brief career of rock 'n' roll star Buddy Holly, who aspires to play music the way he wants it to sound. Holly and his band, the Crickets, are first invited to record in Nashville, where they encounter creative differences with the producing staff. Later they play a major booking at the Apollo Theater, scheduled there under the mistaken assumption that they're a black band. Holly's career eventually goes solo -- until the tragic day the music dies.", vote_average: 7.2, vote_count: 129, genre_ids: [18, 10402], runtime: 114, popularity: 1.7396, original_language: "en" },
  11778: { id: 11778, title: "The Deer Hunter", release_date: "1978-12-08", poster_path: "/bbGtogDZOg09bm42KIpCXUXICkh.jpg", backdrop_path: "/a5zBQfXmLk3qqRYF7AioWpiAxk2.jpg", overview: "Three steelworkers enlist in the army and are sent to Vietnam, one leaving behind a rushed marriage, the others a shared love. What they encounter during the war changes their lives forever.", vote_average: 7.974, vote_count: 4211, genre_ids: [18, 10752], runtime: 183, popularity: 7.6861, original_language: "en" },
