  25188: { id: 25188, title: "The Last Picture Show", release_date: "1971-10-03", poster_path: "/7NYePZc0lZrRomtmQsjOJMePTEb.jpg", backdrop_path: "/fhzwleXGmiqBuQdWxmEwpkydhm4.jpg", overview: "High school seniors and best friends, Sonny and Duane, live in a dying Texas town. The handsome Duane is dating a local beauty, while Sonny is having an affair with the coach's wife. As graduation nears and both boys contemplate their futures, Duane eyes the army and Sonny takes over a local business. Each struggles to figure out if he can escape this dead-end town and build a better life somewhere else.", vote_average: 7.623, vote_count: 766, genre_ids: [18, 10749], runtime: 119, popularity: 3.7137, original_language: "en" },
