  9062: { id: 9062, title: "Love Story", release_date: "1970-12-16", poster_path: "/5A7SGcT1GlhWfHsCRQQtGe0TpJB.jpg", backdrop_path: "/sIOIhwdWqplSpq62f1uP8yUpS2r.jpg", overview: "Harvard Law student Oliver Barrett IV and music student Jennifer Cavilleri share a chemistry they cannot deny - and a love they cannot ignore. Despite their opposite backgrounds, the young couple put their hearts on the line for each other. When they marry, Oliver's wealthy father threatens to disown him. Jenny tries to reconcile the Barrett men, but to no avail.", vote_average: 6.832, vote_count: 731, genre_ids: [10749, 18], runtime: 100, popularity: 4.0822, original_language: "en" },
  651: { id: 651, title: "M*A*S*H", release_date: "1970-02-18", poster_path: "/on8Q9LhtHYNhmITjUMpgOUkIG8o.jpg", backdrop_path: "/3YWL6rZmvZxCQw2qEwxPGrqhYku.jpg", overview: "One of the world's most acclaimed comedies, M*A*S*H focuses on three Korean War Army surgeons brilliantly brought to life by Donald Sutherland, Tom Skerritt and Elliott Gould. Though highly skilled and deeply dedicated, they adopt a hilarious, lunatic lifestyle as an antidote to the tragedies of their Mobile Army Surgical Hospital, and in the process infuriate Army bureaucrats. Robert Duvall, Gary Burghoff and Sally Kellerman co-star as a sanctimonious Major, an other-worldly Corporal, and a self-righteous yet lusty nurse.", vote_average: 6.952, vote_count: 1146, genre_ids: [35, 18, 10752], runtime: 116, popularity: 3.9233, original_language: "en" },
