  114511: { id: 114511, title: "Journey Into Self", release_date: "1969-03-20", poster_path: "/yE2LcX8SYH7m9hK5wsO8YhoS1vj.jpg", backdrop_path: null, overview: "Journey into Self is a 1968 documentary film introduced by Stanley Kramer, and produced and directed by Bill McGaw. The film portrays a 16-hour group-therapy session for eight well-adjusted people who had never met before. The session was led by psychologists Carl Rogers and Richard Farson. The participants included a cashier, a theology student, a teacher, a principal, a housewife, and three businessmen. It won the Academy Award for Best Documentary Feature in 1968.", vote_average: 5.6, vote_count: 10, genre_ids: [99], runtime: 47, popularity: 0.1135, original_language: "en" },
