  912: { id: 912, title: "The Thomas Crown Affair", release_date: "1968-06-26", poster_path: "/oODAwa2AK3fXvK93GCbq7dFLZPi.jpg", backdrop_path: "/dmNg4IfF8vNBSVO1GzJXqTZhBm5.jpg", overview: "Young businessman Thomas Crown is bored and decides to plan a robbery and assigns a professional agent with the right information to the job. However, Crown is soon betrayed yet cannot blow his cover because he’s in love.", vote_average: 6.778, vote_count: 571, genre_ids: [80, 10749], runtime: 102, popularity: 2.9388, original_language: "en" },
