  15347: { id: 15347, title: "Born Free", release_date: "1966-03-14", poster_path: "/xI5BkObQm7UtYEFTw7ZmiDGF7gT.jpg", backdrop_path: "/33kRnZfiYd6WPKpMge5OQhzxYGN.jpg", overview: "At a national park in Kenya, English game warden George Adamson and his wife, Joy, care for three orphaned lion cubs. After the two larger lions are shipped off to a zoo in the Netherlands, the smallest of the three, Elsa, stays with the couple. When Elsa is blamed for causing an elephant stampede in the nearby village, head warden John Kendall demands the young lion either be trained to survive in the wilds of the Serengeti or be sent to a zoo.", vote_average: 6.754, vote_count: 130, genre_ids: [12, 10751, 18, 36], runtime: 95, popularity: 1.7697, original_language: "en" },
