  11575: { id: 11575, title: "The Great Race", release_date: "1965-07-01", poster_path: "/9rL8GWuFdO3fLXcNV9rZRHskoOn.jpg", backdrop_path: "/vga7453tBLXDqxeTV2IGUpVgIgk.jpg", overview: "Professional daredevil and white-suited hero, The Great Leslie, convinces turn-of-the-century auto makers that a race from New York to Paris (westward across America, the Bering Straight and Russia) will help to promote automobile sales. Leslie's arch-rival, the mustached and black-attired Professor Fate vows to beat Leslie to the finish line in a car of Fate's own invention.", vote_average: 7.087, vote_count: 364, genre_ids: [35, 12, 28, 10749, 37], runtime: 160, popularity: 2.7986, original_language: "en" },
