  77915: { id: 77915, title: "The Sandpiper", release_date: "1965-06-23", poster_path: "/cOEIl9QjFe6Pt5W7hbkt2Hy7EfX.jpg", backdrop_path: "/x2dgbGQr4MAt6ljJHIsW0ObqwWD.jpg", overview: "A free-spirited single mother forms a connection with the wedded headmaster of an Episcopalian boarding school in Monterey, California.", vote_average: 6.389, vote_count: 54, genre_ids: [18, 10749], runtime: 117, popularity: 1.438, original_language: "en" },
  5052: { id: 5052, title: "Topkapi", release_date: "1964-09-02", poster_path: "/3Q5psd2bvCMWFdQp4RvRDgxSiwg.jpg", backdrop_path: "/kmstDi95LwdRAJwT6iwTTnB6igb.jpg", overview: "Arthur Simon Simpson is a small-time crook biding his time in Greece. One of his potential victims turns out to be a gentleman thief planning to steal the emerald-encrusted dagger of the Mehmed II from Istanbul's Topkapi Museum.", vote_average: 6.502, vote_count: 207, genre_ids: [35, 80, 12], runtime: 119, popularity: 2.1104, original_language: "en" },
