  33632: { id: 33632, title: "Sweet Bird of Youth", release_date: "1962-03-21", poster_path: "/uA9tl4o8P1hNB3lDBhHKHcNGdtr.jpg", backdrop_path: "/i5fqy8pN3Z1jF0rpsJGfPVARcnJ.jpg", overview: "Gigolo and drifter Chance Wayne returns to his hometown as the companion of a faded movie star, Alexandra Del Lago, whom he hopes to use to help him break into the movies. Chance runs into trouble when he finds his ex-girlfriend, the daughter of the local politician Tom \"Boss\" Finley, who more or less forced him to leave his daughter and the town many years ago.", vote_average: 6.785, vote_count: 130, genre_ids: [18, 10749], runtime: 120, popularity: 1.5367, original_language: "en" },
  9289: { id: 9289, title: "The Longest Day", release_date: "1962-09-25", poster_path: "/5zmvEofdIlgXrQl9A7e5IOzlnFU.jpg", backdrop_path: "/yt9FIS2Osm97M7w4dLFkBu7YxW8.jpg", overview: "The retelling of June 6, 1944, from the perspectives of the Germans, US, British, Canadians, and the Free French. Marshall Erwin Rommel, touring the defenses being established as part of the Reich's Atlantic Wall, notes to his officers that when the Allied invasion comes they must be stopped on the beach. \"For the Allies as well as the Germans, it will be the longest day\"", vote_average: 7.607, vote_count: 1010, genre_ids: [10752, 28, 18], runtime: 178, popularity: 5.3396, original_language: "en" },
  1162: { id: 1162, title: "The Miracle Worker", release_date: "1962-05-23", poster_path: "/3dI6UVM5W1sz3MU9gNK5nVDcAyQ.jpg", backdrop_path: "/5bvQEihHBKJ0Rs1J46HcG0wASDr.jpg", overview: "The true story of the frightening, lonely world of silence and darkness of 7-year-old Helen Keller who, since infancy, has never seen the sky, heard her mother's voice or expressed her innermost feelings. Then Annie Sullivan, a 20-year-old teacher from Boston, arrives. Having just recently regained her own sight, the no-nonsense Annie reaches out to Helen through the power of touch, the only tool they have in common, and leads her bold pupil on a miraculous journey from fear and isolation to happiness and light.", vote_average: 7.891, vote_count: 338, genre_ids: [18, 36], runtime: 106, popularity: 2.3416, original_language: "en" },
  13671: { id: 13671, title: "The Music Man", release_date: "1962-06-19", poster_path: "/4yo6qaqVF1IThXMapo4yW9BRWjV.jpg", backdrop_path: "/urXv48loBPvUDf8CF1YtYjmRECW.jpg", overview: "Traveling con artist Harold Hill targets the naïve residents of a small town in 1910s Iowa by posing as a boys' bandleader to raise money before he can skip town.", vote_average: 7.125, vote_count: 192, genre_ids: [35, 10751, 10402, 10749], runtime: 151, popularity: 2.0027, original_language: "en" },
  28367: { id: 28367, title: "The Wonderful World of the Brothers Grimm", release_date: "1962-08-07", poster_path: "/zElwCWdMG7A6xThgesRxNrgD2MP.jpg", backdrop_path: "/gUmxshmfbFC7zFBt9kwdkSdQCNy.jpg", overview: "The Grimm brothers Wilhelm and Jacob, known for their literary works in the nineteenth century, have their lives dramatized. Wilhelm fights to write something entertaining amongst the sea of dry, non-fiction books they write and he sets about collecting oral-tradition fairy tales to put into print. Their life story is countered with reenactments of three of their stories including \"The Dancing Princess,\" \"The Cobbler and the Elves\" and \"The Singing Bone.\"", vote_average: 5.853, vote_count: 34, genre_ids: [14, 10751, 10402, 35], runtime: 140, popularity: 1.2525, original_language: "en" },
  595: { id: 595, title: "To Kill a Mockingbird", release_date: "1962-12-20", poster_path: "/gZycFUMLx2110dzK3nBNai7gfpM.jpg", backdrop_path: "/zP6pqpSRRiOCjjC5oWKZKkHqoSB.jpg", overview: "Scout Finch, 6, and her older brother Jem live in sleepy Maycomb, Alabama, spending much of their time with their friend Dill and spying on their reclusive and mysterious neighbor, Boo Radley. When Atticus, their widowed father and a respected lawyer, defends a black man named Tom Robinson against fabricated rape charges, the trial and tangent events expose the children to evils of racism and stereotyping.", vote_average: 7.996, vote_count: 2843, genre_ids: [18], runtime: 129, popularity: 5.4154, original_language: "en" },
