  821: { id: 821, title: "Judgment at Nuremberg", release_date: "1961-12-18", poster_path: "/b6vYatvui1EXeFYfpDX4rcbueuP.jpg", backdrop_path: "/bDsXa3PV3biQ8ZK1tQyK4vlkvCc.jpg", overview: "In 1947, four German judges who served on the bench during the Nazi regime face a military tribunal to answer charges of crimes against humanity. Chief Justice Haywood hears evidence and testimony not only from lead defendant Ernst Janning and his defense attorney Hans Rolfe, but also from the widow of a Nazi general, an idealistic U.S. Army captain and reluctant witness Irene Wallner.", vote_average: 8.004, vote_count: 934, genre_ids: [18, 36], runtime: 191, popularity: 4.1127, original_language: "en" },
  439: { id: 439, title: "La Dolce Vita", release_date: "1960-02-05", poster_path: "/dZ2v0DAX4aCZartCzZdg4ZinSW2.jpg", backdrop_path: "/eN2NdMeJLNzLYzWIEEoaGzZAsiD.jpg", overview: "Episodic journey of journalist Marcello who struggles to find his place in the world, torn between the allure of Rome's elite social scene and the stifling domesticity offered by his girlfriend, all the while searching for a way to become a serious writer.", vote_average: 8.036, vote_count: 2026, genre_ids: [35, 18], runtime: 176, popularity: 5.1488, original_language: "it" },
  114507: { id: 114507, title: "Sky Above and Mud Beneath", release_date: "1961-05-05", poster_path: "/dNKcc97ZaoAGZvd00bWYJ5hKpp4.jpg", backdrop_path: "/b8wDyJHKj0AkvFhBbcebGK2X9Es.jpg", overview: "In September, 1959, six Europeans leave Cook's Bay on the southern coast of Dutch New Guinea, now West Papua or Irian Jaya, to trek north to the far side of the island. The journey (450 miles, as a crow flies) across unmapped territory took seven months; three Muyu porters died. Near both coasts, the expedition met villagers who invited them to observe rituals and live with them. In the interior, all villagers kept them at bay, and they depended on air lifts from Hollandia for food and supplies. They climbed above 10,000 feet, built 14 bridges, and fought leeches and malaria. The narrator focuses on describing Stone Age savages, headhunters, and cannibals.", vote_average: 5.667, vote_count: 12, genre_ids: [99], runtime: 92, popularity: 0.2252, original_language: "fr" },
  28569: { id: 28569, title: "Splendor in the Grass", release_date: "1961-10-10", poster_path: "/n6Kw8Ui93SMhrk1MupCFwUg04vq.jpg", backdrop_path: "/3VIlHshnxV6Vwxz6Ega6llvGZiF.jpg", overview: "A fragile Kansas girl's unrequited and forbidden love for a handsome young man from the town's most powerful family drives her to heartbreak and madness.", vote_average: 7.472, vote_count: 301, genre_ids: [18, 10749], runtime: 124, popularity: 2.2099, original_language: "en" },
  10911: { id: 10911, title: "The Guns of Navarone", release_date: "1961-04-27", poster_path: "/j6VSFnm20GlkUi8yb7hM5Qfc1fA.jpg", backdrop_path: "/AsBJ7JjNR7wcONrfkUW027C8D5c.jpg", overview: "A team of allied saboteurs are assigned an impossible mission: infiltrate an impregnable Nazi-held island and destroy the two enormous long-range field guns that prevent the rescue of 2,000 trapped British soldiers.", vote_average: 7.306, vote_count: 859, genre_ids: [28, 12, 18, 10752], runtime: 160, popularity: 4.5914, original_language: "en" },
