  11602: { id: 11602, title: "Through a Glass Darkly", release_date: "1961-10-16", poster_path: "/rYD30Fm4vAcBqk1kTsxHw1s8P29.jpg", backdrop_path: "/ziTptDmkMLIC50LB0to2OU3hwOy.jpg", overview: "Karin hopes to recover from her recent stay at a mental hospital by spending the summer at her family's cottage on a tiny island. Her husband, Martin, cares for her but is frustrated by her physical withdrawal. Her younger brother, Minus, is confused by Karin's vulnerability and his own budding sexuality. Their father, David, cannot overcome his haughty remoteness. Beset by visions, Karin descends further into madness.", vote_average: 7.772, vote_count: 535, genre_ids: [18], runtime: 91, popularity: 1.2884, original_language: "sv" },
