  967: { id: 967, title: "Spartacus", release_date: "1960-10-13", poster_path: "/r0Fgg1GyZgzokaiw2HFQv3oPaL2.jpg", backdrop_path: "/9caD0fGCrp96JTFFeGyI0CGNj7.jpg", overview: "The rebellious Thracian Spartacus, born and raised a slave, is sold to Gladiator trainer Batiatus. After weeks of being trained to kill for the arena, Spartacus turns on his owners and leads the other slaves in rebellion. As the rebels move from town to town, their numbers swell as escaped slaves join their ranks. Under the leadership of Spartacus, they make their way to southern Italy, where they will cross the sea and return to their homes.", vote_average: 7.536, vote_count: 2374, genre_ids: [36, 10752, 18, 12], runtime: 197, popularity: 11.9112, original_language: "en" },
