  39219: { id: 39219, title: "The Facts of Life", release_date: "1960-11-14", poster_path: "/jgduHeBEmpCdzHKo9wteKj8WO8l.jpg", backdrop_path: "/dMgs7I1TlmOLWhlK9IVtsVhzWP1.jpg", overview: "Middle-class suburbanites Larry and Kitty grow bored with their lives and respective marriages. Although each always found the other's manner grating, they fall in love when thrown together--without their spouses--on vacation. On returning home they try to break things off, only to grow closer. A holiday together will finally settle whether they should end their marriages.", vote_average: 5.232, vote_count: 28, genre_ids: [18, 35, 10749], runtime: 103, popularity: 0.9467, original_language: "en" },
  114506: { id: 114506, title: "The Horse with the Flying Tail", release_date: "1960-12-21", poster_path: "/jyDWALCsIicp7VMElh1VOPDrsW0.jpg", backdrop_path: "/hG1bySaPixx4howmzXvJzFzCPAg.jpg", overview: "A palimino cow pony, through a series of owners and adventures becomes a champion mount for one of the US equestrian team.", vote_average: 7.286, vote_count: 14, genre_ids: [99], runtime: 48, popularity: 0.1567, original_language: "en" },
  2134: { id: 2134, title: "The Time Machine", release_date: "1960-05-25", poster_path: "/sotBnRlFJ67cPisjAUXzbPxi9kC.jpg", backdrop_path: "/bUA6Fu0C2jGqrjn0A9AJwTRpq41.jpg", overview: "A Victorian Englishman travels to the far future and finds that humanity has divided into two hostile species.", vote_average: 7.351, vote_count: 904, genre_ids: [53, 12, 14, 878, 10749], runtime: 103, popularity: 3.7573, original_language: "en" },
  11656: { id: 11656, title: "The Virgin Spring", release_date: "1960-02-08", poster_path: "/z70YM3Y4pNYZATMhFMKonngaeMC.jpg", backdrop_path: "/pcBIabUibUmpOBggWckkjohXtiP.jpg", overview: "Devout Christians Töre and Märeta send their only daughter, the virginal Karin, and their foster daughter, the unrepentant Ingeri, to deliver candles to a distant church. On their way through the woods, the girls encounter a group of savage goat herders who brutally rape and murder Karin as Ingeri remains hidden. When the killers unwittingly seek refuge in the farmhouse of Töre and Märeta, Töre plots a fitting revenge.", vote_average: 7.848, vote_count: 673, genre_ids: [18, 36], runtime: 90, popularity: 2.1683, original_language: "sv" },
  665: { id: 665, title: "Ben-Hur", release_date: "1959-11-18", poster_path: "/m4WQ1dBIrEIHZNCoAjdpxwSKWyH.jpg", backdrop_path: "/sU3gFo7Gn67zjtKXIvzJ4omcUbH.jpg", overview: "In ancient Judea, a Jewish aristocrat opposing Roman occupation of his homeland reunites with his childhood friend, now a Roman commander — setting in motion a saga of betrayal, adventure, tragedy, revenge, and faith.", vote_average: 7.884, vote_count: 3118, genre_ids: [36, 18, 12], runtime: 212, popularity: 10.7742, original_language: "en" },
  40423: { id: 40423, title: "Black Orpheus", release_date: "1959-06-12", poster_path: "/fJWzdNRnfjcJuaZiKqaSURFV6Lg.jpg", backdrop_path: "/mXHZJu6wmmNIhbidSMp24PQ3WNw.jpg", overview: "Young lovers Orfeu and Eurydice run through the favelas of Rio during Carnaval, on the lam from a hitman dressed like Death and Orfeu's vengeful fiancée Mira and passing between moments of fantasy and stark reality. This impressionistic retelling of the Greek legend of Orpheus and Eurydice introduced bossa nova to the world with its soundtrack by young Brazilian composers Luiz Bonfá and Antonio Carlos Jobim.", vote_average: 6.991, vote_count: 235, genre_ids: [18, 10749], runtime: 100, popularity: 1.3924, original_language: "pt" },
  43039: { id: 43039, title: "Never on Sunday", release_date: "1960-05-24", poster_path: "/t9zLlS5O5GB57BKjJCtzB21VKZB.jpg", backdrop_path: "/6YgRhojLENb3y3ufWqC6SUH1IBE.jpg", overview: "An American scholar in Greece sets about improving the local prostitute with whom he is infatuated.", vote_average: 6.842, vote_count: 73, genre_ids: [35, 10749], runtime: 91, popularity: 0.9859, original_language: "el" },
  4952: { id: 4952, title: "Pillow Talk", release_date: "1959-10-07", poster_path: "/ugvyj5nl9QmTYuaGUTefVYBDePE.jpg", backdrop_path: "/cPDMOeafVmyguVlwE4ls6HER021.jpg", overview: "Playboy songwriter Brad Allen's succession of romances annoys his neighbor, interior designer Jan Morrow, who shares a telephone party line with him and hears all his breezy routines. After Jan unsuccessfully lodges a complaint against him, Brad sets about to seduce her in the guise of a sincere and upstanding Texas rancher. When mutual friend Jonathan discovers that his best friend is moving in on the girl he desires, however, sparks fly.", vote_average: 7.139, vote_count: 317, genre_ids: [35, 10749], runtime: 102, popularity: 3.2359, original_language: "en" },
