  1940: { id: 1940, title: "Porgy and Bess", release_date: "1959-06-24", poster_path: "/g4zwlj8bgRYsUoF0VEwPEgldCvn.jpg", backdrop_path: "/hFaFE7EpKTnjG3LDhoV40gd9vsU.jpg", overview: "In the early 1900s, the fictional Catfish Row section of Charleston, South Carolina serves as home to a black fishing community. Crippled beggar Porgy, who travels about in a goat-drawn cart, loves the drug-addicted Bess, who lives with stevedore Crown, the local bully.", vote_average: 6.25, vote_count: 26, genre_ids: [10402, 18, 10749], runtime: 138, popularity: 1.0952, original_language: "en" },
  43103: { id: 43103, title: "Room at the Top", release_date: "1958-12-29", poster_path: "/uuyruoqh7oBtjwN1mJyOF04CPjO.jpg", backdrop_path: "/3U5CUwhmJuPzWxlOfiIoJqy6dgi.jpg", overview: "An ambitious young accountant schemes to wed a wealthy factory owner's daughter, despite falling in love with a married older woman.", vote_average: 6.896, vote_count: 144, genre_ids: [18, 10749], runtime: 115, popularity: 1.7779, original_language: "en" },
  12552: { id: 12552, title: "Serengeti Shall Not Die", release_date: "1959-06-25", poster_path: "/vY1ngpl7pPkFjhiiuKNHSllSZF0.jpg", backdrop_path: "/1hyfCogEv59VYngDecpFBT1kfT.jpg", overview: "The film tells of the beginnings of the Serengeti National Park in Tanzania. At the end of the 1950s, the Tanzanian National Park Administration wanted to fence in the protected area around the Ngorongoro Crater. Bernhard and Michael Grzimek were invited by the national park administration in 1957 to get a precise picture of the animal migrations and to provide the national park administration with the values ​​they needed for their project. Using a new counting method with two airplanes, the Grzimeks found out that the migration of the herds was different than assumed.", vote_average: 6.464, vote_count: 14, genre_ids: [99], runtime: 85, popularity: 0.418, original_language: "de" },
  239: { id: 239, title: "Some Like It Hot", release_date: "1959-03-19", poster_path: "/hVIKyTK13AvOGv7ICmJjK44DTzp.jpg", backdrop_path: "/5zTwAcnI3zCJ0mucPPnoBtkSWEV.jpg", overview: "In Prohibition-era Chicago, musicians Joe and Jerry witness a mob hit, and flee the state in an all-female band disguised as Josephine and Daphne, but further complications set in.", vote_average: 8.081, vote_count: 3851, genre_ids: [35, 10749, 80], runtime: 123, popularity: 7.8354, original_language: "en" },
  2576: { id: 2576, title: "The Diary of Anne Frank", release_date: "1959-03-18", poster_path: "/i7kUdUAF9eTxQG7GdR6lKUK96En.jpg", backdrop_path: "/t5rUpe1MwGP0JwMLbfaMJvAfUsG.jpg", overview: "The true, harrowing story of a young Jewish girl who, with her family and their friends, is forced into hiding in an attic in Nazi-occupied Amsterdam.", vote_average: 7.173, vote_count: 372, genre_ids: [18, 36], runtime: 179, popularity: 2.3213, original_language: "en" },
  33725: { id: 33725, title: "A Hole in the Head", release_date: "1959-09-15", poster_path: "/BOgeA821uM0G2nrKj8rFSPYyGO.jpg", backdrop_path: "/37XokaTf9o6nazmKPlDP3LKTYQ6.jpg", overview: "An impractical widower tries to hang onto his Miami hotel and his 12-year-old son.", vote_average: 6.18, vote_count: 50, genre_ids: [35, 18], runtime: 120, popularity: 1.2928, original_language: "en" },
  17281: { id: 17281, title: "Gigi", release_date: "1958-05-15", poster_path: "/1sF5o9Cs5GMx3cYmXD64WEQBLJn.jpg", backdrop_path: "/fJ8KBr0WJGJyWcCriv5C0vtWqAj.jpg", overview: "A home, a motorcar, servants, the latest fashions: the most eligible and most finicky bachelor in Paris offers them all to Gigi. But she, who's gone from girlish gawkishness to cultured glamour before our eyes, yearns for that wonderful something money can't buy.", vote_average: 6.228, vote_count: 345, genre_ids: [35, 10749], runtime: 115, popularity: 2.3706, original_language: "en" },
