  427: { id: 427, title: "Mon Oncle", release_date: "1958-05-10", poster_path: "/wH6RyPiXFy8INLbViVkchLVOmBc.jpg", backdrop_path: "/hSbkxFnGi99pueUze7KUJuy9CWE.jpg", overview: "Genial, bumbling Monsieur Hulot loves his top-floor apartment in a grimy corner of the city, and cannot fathom why his sister's family has moved to the suburbs. Their house is an ultra-modern nightmare, which Hulot only visits for the sake of stealing away his rambunctious young nephew. Hulot's sister, however, wants to win him over to her new way of life, and conspires to set him up with a wife and job.", vote_average: 7.417, vote_count: 612, genre_ids: [35], runtime: 118, popularity: 1.551, original_language: "fr" },
  43136: { id: 43136, title: "Separate Tables", release_date: "1958-12-18", poster_path: "/y8exawP0Je3MXVIS3olpJ2fu07.jpg", backdrop_path: "/6jjv2DMqejxhp08mAJ0lrOWauz2.jpg", overview: "The lives of a disparate group of unfulfilled people converge at a small, seaside English hotel.", vote_average: 7.027, vote_count: 128, genre_ids: [18, 10749], runtime: 98, popularity: 1.5793, original_language: "en" },
  17352: { id: 17352, title: "South Pacific", release_date: "1958-03-19", poster_path: "/nYNltu2clFoRQGBz9BtZUTcCbUm.jpg", backdrop_path: "/1l0rx8cwekCKlGPO9iWFtHvQ7nL.jpg", overview: "Can a girl from Little Rock find happiness with a mature French planter she got to know one enchanted evening away from the military hospital where she is a nurse? Or should she just wash that man out of her hair? Bloody Mary is the philosopher of the island and it's hard to believe she could be the mother of Liat who has captured the heart of Lt. Joseph Cable USMC. While waiting for action in the war in the South Pacific, sailors and nurses put on a musical comedy show. The war gets closer and the saga of Nellie Forbush and Emile de Becque becomes serious drama.", vote_average: 6.147, vote_count: 116, genre_ids: [10402, 10749, 10752], runtime: 157, popularity: 2.2067, original_language: "en" },
  12501: { id: 12501, title: "The Big Country", release_date: "1958-08-13", poster_path: "/aTjIUBmo7qbiu5FuvSoBA0UONWk.jpg", backdrop_path: "/mqMCvFJ3fRc7RXa0w6A0VRZ1b7F.jpg", overview: "Retired wealthy sea captain Jim McKay arrives in the Old West, where he becomes embroiled in a feud between his future father-in-law, Major Terrill, and the rough and lawless Hannasseys over a valuable patch of land.", vote_average: 7.582, vote_count: 404, genre_ids: [18, 37, 10749], runtime: 167, popularity: 4.0078, original_language: "en" },
