  11331: { id: 11331, title: "The Old Man and the Sea", release_date: "1958-10-07", poster_path: "/6Q34dJL6m1vdzAr0jDDKDmNL52e.jpg", backdrop_path: "/5S916KQ6Wmn0pDFoeknIvpMgL9v.jpg", overview: "Santiago is an aging, down-on-his-luck, Cuban fisherman who, after catching nothing for nearly 3 months, hooks a huge Marlin and struggles to land it far out in the Gulf Stream.", vote_average: 6.519, vote_count: 163, genre_ids: [12, 18], runtime: 86, popularity: 2.257, original_language: "en" },
  125441: { id: 125441, title: "Tom Thumb", release_date: "1958-07-24", poster_path: "/p2SkPiRlcdqZ4VoR9RgWiYK2h3V.jpg", backdrop_path: "/A54jALt1PNY51QTdWNtMmc8yt5V.jpg", overview: "A young boy born extraordinarily small must rescue his older brothers from a wicked ogre.", vote_average: 7.154, vote_count: 26, genre_ids: [14, 10751], runtime: 85, popularity: 1.8831, original_language: "es" },
  33668: { id: 33668, title: "Designing Woman", release_date: "1957-05-16", poster_path: "/5iKj0fkip6j67iwejogjTGmkLZd.jpg", backdrop_path: "/cHQZurCTQd9YPlKewTL73t4EP4K.jpg", overview: "A sportswriter who marries a fashion designer discovers that their mutual interests are few, although each has an intriguing past which makes the other jealous.", vote_average: 6.644, vote_count: 80, genre_ids: [35, 10749], runtime: 118, popularity: 1.6234, original_language: "en" },
  43232: { id: 43232, title: "Les Girls", release_date: "1957-10-03", poster_path: "/78ot7b75r5yWKt0rW9XjXqH7GY1.jpg", backdrop_path: "/tFT34AaH8NPJsAGVVICf0J2ezm8.jpg", overview: "After writing a tell-all book about her days in the dance troupe \"Barry Nichols and Les Girls\", Sybil Wren is sued for libeling her fellow dancer Angele. A Rashômon style narrative presents the story from three points of view where Sybil accuses Angele of having an affair with Barry, while Angele insists that it was actually Sybil who was having the affair. Finally, Barry gives his side of the story.", vote_average: 6.424, vote_count: 59, genre_ids: [35, 10402, 10749], runtime: 114, popularity: 1.8226, original_language: "en" },
  19426: { id: 19426, title: "Nights of Cabiria", release_date: "1957-10-03", poster_path: "/xF4oCG3PLNbcrtPZbqB3BtkIbKg.jpg", backdrop_path: "/9yepEBnQNcKzWWyHdUiX8Mnqc6U.jpg", overview: "Rome, 1957. A woman, Cabiria, is robbed and left to drown by her boyfriend, Giorgio. Rescued, she resumes her life and tries her best to find happiness in a cynical world. Even when she thinks her struggles are over and she has found happiness and contentment, things may not be what they seem.", vote_average: 7.992, vote_count: 855, genre_ids: [18, 35], runtime: 110, popularity: 1.9349, original_language: "it" },
  40885: { id: 40885, title: "Sayonara", release_date: "1957-12-25", poster_path: "/xSXJDamf9vSb1qOiBhOMjB2soDE.jpg", backdrop_path: "/eYHkb8xNizPXXGXAFfg4Gvm974b.jpg", overview: "Air Force Major Lloyd Gruver is reassigned to a Japanese air base and is confronted with US racial prejudice against the Japanese people. The issue is compounded because a number of the soldiers become romantically involved with Japanese women, in defiance of US military policy. Ordinarily, a by-the-book officer, Gruver must take a position when a buddy of his, an enlisted man, Joe Kelly, falls in love with a Japanese woman, Katsumi, and marries her. Gruver risks his position by serving as best man at the wedding ceremony.", vote_average: 6.703, vote_count: 144, genre_ids: [18, 10749], runtime: 147, popularity: 2.007, original_language: "en" },
  826: { id: 826, title: "The Bridge on the River Kwai", release_date: "1957-10-11", poster_path: "/7paXMt2e3Tr5dLmEZOGgFEn2Vo7.jpg", backdrop_path: "/dRHfCeAoJ6SsMffQ6lavNU9E55z.jpg", overview: "The classic story of English POWs in Burma forced to build a bridge to aid the war effort of their Japanese captors. British and American intelligence officers conspire to blow up the structure, but Col. Nicholson, the commander who supervised the bridge's construction, has acquired a sense of pride in his creation and tries to foil their plans.", vote_average: 7.821, vote_count: 2357, genre_ids: [18, 36, 10752], runtime: 162, popularity: 3.6783, original_language: "en" },
  15876: { id: 15876, title: "The Enemy Below", release_date: "1957-12-25", poster_path: "/9IUUCfrEEkq92sCLznzSAjDPusk.jpg", backdrop_path: "/npUnoVQU6TqXhIZt5JmrpLvoR2i.jpg", overview: "The crew of the American destroyer escort, the USS Haynes, detects a German U-Boat—resulting in a prolonged, deadly battle of wits.", vote_average: 7.1, vote_count: 209, genre_ids: [10752], runtime: 97, popularity: 1.9643, original_language: "en" },
