  28285: { id: 28285, title: "The Three Faces of Eve", release_date: "1957-12-19", poster_path: "/jqfTPqaGYlz1ZR7YHjz5RTgPa8U.jpg", backdrop_path: "/8mOm5xjEJpQPYu3dMg3UuSETQpJ.jpg", overview: "A doctor treats a woman suffering from multiple personality disorder.", vote_average: 7.2, vote_count: 150, genre_ids: [18], runtime: 91, popularity: 2.134, original_language: "en" },
  38171: { id: 38171, title: "Anastasia", release_date: "1956-12-13", poster_path: "/26wHOXNt4XNn2lYT8i8pWx1JOP0.jpg", backdrop_path: "/4hjnRpLFFgIE76xb6mUc9PMVHaH.jpg", overview: "Russian exiles in Paris plot to collect ten million pounds from the Bank of England by grooming a destitute, suicidal girl to pose as heir to the Russian throne. While Bounin is coaching her, he comes to believe that she is really Anastasia. In the end, the Empress must decide her claim.", vote_average: 6.798, vote_count: 186, genre_ids: [18, 10749], runtime: 105, popularity: 2.0054, original_language: "en" },
