  29592: { id: 29592, title: "Lust for Life", release_date: "1956-09-15", poster_path: "/rlK3LG3W41eF3N1tk0SEM7Dln2x.jpg", backdrop_path: "/94Svsxxbww7xR7LrfDIjlQpJUeY.jpg", overview: "An intense and imaginative artist, revered Dutch painter Vincent van Gogh possesses undeniable talent, but he is plagued by mental problems and frustrations with failure. Supported by his brother, Theo, the tormented Van Gogh eventually leaves Holland for France, where he meets volatile fellow painter Paul Gauguin and struggles to find greater inspiration.", vote_average: 7.174, vote_count: 204, genre_ids: [18, 36], runtime: 122, popularity: 2.0411, original_language: "en" },
