  16520: { id: 16520, title: "The King and I", release_date: "1956-06-29", poster_path: "/wUfaP0lLaMpZzp5CrHyII5Vd7cp.jpg", backdrop_path: "/gjFI54BO9f6eZ2iQyNDhgVVnUCJ.jpg", overview: "Widowed Welsh mother Anna Leonowens becomes a governess and English tutor to the wives and many children of the stubborn King Mongkut of Siam. Anna and the King have a clash of personalities as she works to teach the royal family about the English language, customs and etiquette, and rushes to prepare a party for a group of European diplomats who must change their opinions about the King.", vote_average: 7.088, vote_count: 400, genre_ids: [10749, 36, 18], runtime: 133, popularity: 3.3617, original_language: "en" },
  574: { id: 574, title: "The Man Who Knew Too Much", release_date: "1956-05-16", poster_path: "/gy8YBRjCQRIT9x9G9F5fpnFD4xw.jpg", backdrop_path: "/bXPKTWAuRO8Mu5rLCORFagX0YZ1.jpg", overview: "An American doctor and his wife, a former singing star, witness a murder while vacationing in Morocco, and are drawn into a twisting plot of international intrigue when their young son is kidnapped.", vote_average: 7.441, vote_count: 1547, genre_ids: [53, 9648, 18], runtime: 121, popularity: 3.1371, original_language: "en" },
