  6844: { id: 6844, title: "The Ten Commandments", release_date: "1956-10-05", poster_path: "/n7baShuR4TVdV4xgsvAFf59y0aR.jpg", backdrop_path: "/ivF1pzU7JaZ7K35UNLl7rTIKfDV.jpg", overview: "Escaping death, a Hebrew infant is raised in a royal household to become a prince. Upon discovery of his true heritage, Moses embarks on a personal quest to reclaim his destiny as the leader and liberator of the Hebrew people.", vote_average: 7.8, vote_count: 1841, genre_ids: [18, 36], runtime: 220, popularity: 9.8424, original_language: "en" },
  69605: { id: 69605, title: "Written on the Wind", release_date: "1956-10-04", poster_path: "/paeBU70fHsFAOooWM5V35q562f2.jpg", backdrop_path: "/gb7CnfONI8mWuUsxuqkafWEO71N.jpg", overview: "Mitch Wayne is a geologist working for the Hadleys, an oil-rich Texas family. While the patriarch, Jasper, works hard to establish the family business, his irresponsible son, Kyle, is an alcoholic playboy, and his daughter, Marylee, is the town tramp. Mitch harbors a secret love for Kyle's unsatisfied wife, Lucy -- a fact that leaves him exposed when the jealous Marylee accuses him of murder.", vote_average: 6.944, vote_count: 269, genre_ids: [18, 10749], runtime: 99, popularity: 2.0184, original_language: "en" },
  220: { id: 220, title: "East of Eden", release_date: "1955-04-10", poster_path: "/xv1MZVIop0SQqwLUymgE5eb2LFl.jpg", backdrop_path: "/u7i1XtbOubq0xwRy2Zbgmox6g9W.jpg", overview: "In the Salinas Valley in and around World War I, Cal Trask feels he must compete against overwhelming odds with his brother for the love of their father. Cal is frustrated at every turn, from his reaction to the war, how to get ahead in business and in life, and how to relate to his estranged mother.", vote_average: 7.537, vote_count: 811, genre_ids: [18], runtime: 115, popularity: 3.3026, original_language: "en" },
