  43318: { id: 43318, title: "Interrupted Melody", release_date: "1955-05-05", poster_path: "/fD8XlQnGGmtbIVr5mWDkVokKNAF.jpg", backdrop_path: "/xuSKrBLrgGxRBfyhj4u0mptnnNe.jpg", overview: "Interrupted Melody is the inspirational filmed biography of world-renowned Australian soprano Marjorie Lawrence. She’s a foremost Wagnerian, equal to the vocal and physical demands of the composer’s oeuvre. And she’s a beacon of triumph to anyone who fights back when personal tragedy strikes.", vote_average: 5.769, vote_count: 13, genre_ids: [18, 10402], runtime: 106, popularity: 1.663, original_language: "en" },
