  40633: { id: 40633, title: "Love Me or Leave Me", release_date: "1955-05-26", poster_path: "/rIT21pBwDQxrKyhmUiwoZCs1IFS.jpg", backdrop_path: "/l4hnzWUc7Xmx4H9A4cYrBaoUcN1.jpg", overview: "A fictionalized account of the career of jazz singer Ruth Etting and her tempestuous marriage to gangster Marty Snyder, who helped propel her to stardom.", vote_average: 6.852, vote_count: 54, genre_ids: [10402, 18, 10749], runtime: 122, popularity: 1.3895, original_language: "en" },
  15919: { id: 15919, title: "Marty", release_date: "1955-04-11", poster_path: "/8tnGO5VoAQII4DbE3hozWKhV4BY.jpg", backdrop_path: "/uOHoIVsmdWV1cslPJ0tekzTdSIv.jpg", overview: "Marty, a butcher who lives in the Bronx with his mother is unmarried at 34. Good-natured but socially awkward he faces constant badgering from family and friends to get married but has reluctantly resigned himself to bachelorhood. Marty meets Clara, an unattractive school teacher, realising their emotional connection, he promises to call but family and friends try to convince him not to.", vote_average: 7.46, vote_count: 446, genre_ids: [18, 10749], runtime: 90, popularity: 2.9372, original_language: "en" },
  37853: { id: 37853, title: "Mister Roberts", release_date: "1955-07-10", poster_path: "/5B8Gc1N2S3CDWHBzm0VxaMPTyzJ.jpg", backdrop_path: "/tWzWYnlvrUFwcEeRNKbsXPpjiRS.jpg", overview: "Mr. Roberts is a Navy officer who's yearning for battle but is stuck in the backwaters of World War II on a non-commissioned ship run by the bullying Captain Morton.", vote_average: 7.072, vote_count: 174, genre_ids: [35, 18, 10752], runtime: 123, popularity: 2.2119, original_language: "en" },
  13936: { id: 13936, title: "Oklahoma!", release_date: "1955-10-10", poster_path: "/ztqT5GmJVI2o8vShGWRVVqykQqA.jpg", backdrop_path: "/scjRKib0bVVQEZv1lCutko4tlY4.jpg", overview: "In the Oklahoma territory at the turn of the twentieth century, two young cowboys vie with a violent ranch hand and a traveling peddler for the hearts of the women they love.", vote_average: 6.632, vote_count: 185, genre_ids: [37, 10402, 10749], runtime: 145, popularity: 2.877, original_language: "en" },
  39940: { id: 39940, title: "Picnic", release_date: "1955-11-18", poster_path: "/aKCSA9JUp9JkztAjzODPTrtZmzC.jpg", backdrop_path: "/pI4l6pRclnUWUSE1YGbLghvymCc.jpg", overview: "Labor Day in a small Kansas farm town. Hal, a burly and resolute drifter, jumps off a dusty freight train car with the purpose of visiting Alan, a former college classmate and son of the richest man in town.", vote_average: 6.341, vote_count: 110, genre_ids: [18, 10749], runtime: 114, popularity: 1.8601, original_language: "en" },
  31374: { id: 31374, title: "Samurai II: Duel at Ichijoji Temple", release_date: "1955-07-12", poster_path: "/nybLbDfegJOUMzsdrWWvLTD4kY0.jpg", backdrop_path: "/gp5MCnItJgQ5qzSs5W3bJMDXbVM.jpg", overview: "After years on the road establishing his reputation as Japan's greatest fencer, Takezo returns to Kyoto. Otsu waits for him, yet he has come not for her but to challenge the leader of the region's finest school of fencing. To prove his valor and skill, he walks deliberately into ambushes set up by the school's followers.", vote_average: 7.146, vote_count: 140, genre_ids: [18, 28, 12], runtime: 103, popularity: 1.599, original_language: "ja" },
  65550: { id: 65550, title: "The Rose Tattoo", release_date: "1955-12-12", poster_path: "/3W3dgP2l24JJWq6sVEl6TddLwbe.jpg", backdrop_path: "/zIlbxtVlyz223BiOQZ6sWhJTLoU.jpg", overview: "A grieving widow embarks on a new romance when she discovers her late husband had been cheating on her.", vote_average: 6.9, vote_count: 85, genre_ids: [18, 10749], runtime: 117, popularity: 1.3758, original_language: "en" },
