  34689: { id: 34689, title: "The Barefoot Contessa", release_date: "1954-09-29", poster_path: "/eSRBlHu9didl6MdFQdIYpU9YdFD.jpg", backdrop_path: "/2yK59yDiP4P5hsENbGYSPc3YA5I.jpg", overview: "A washed-up filmmaker gets a second chance at stardom when he discovers stunning peasant Maria Vargas dancing in a Madrid nightclub. Goaded by his producer, the director convinces Maria to screen test for, and then star in, his next big picture. But as the producer's possessive nature and the realities of stardom weigh on Maria, she seeks a genuine lover with whom she can escape.", vote_average: 6.745, vote_count: 276, genre_ids: [18], runtime: 128, popularity: 1.524, original_language: "en" },
