  41503: { id: 41503, title: "Three Coins in the Fountain", release_date: "1954-05-01", poster_path: "/3y6aNrQd8K2bQjI2gRpmmDJGr99.jpg", backdrop_path: "/91jVA9ITFrX0Mr6xHhvI1EAz9gC.jpg", overview: "Three American roommates working in Italy wish for the man of their dreams after throwing coins into Rome's magnificent Trevi Fountain. Frances, a secretary at a government agency, sets out to win the heart of her smooth-talking novelist employer; Anita, her coworker, defies office regulations by romancing an Italian who works at the agency; and office newcomer Maria meets a real Italian Prince Charming and falls madly in love. The only thing the three hopeful ladies need to do is seal their fate.", vote_average: 5.905, vote_count: 58, genre_ids: [18, 10749], runtime: 102, popularity: 1.5953, original_language: "en" },
