  18019: { id: 18019, title: "Julius Caesar", release_date: "1953-06-04", poster_path: "/2nzpmJ9MIdd5TKXJd53KgKdZ6eT.jpg", backdrop_path: "/7gCIJ4D2T9vmgN7dVdhdmZVwSPk.jpg", overview: "The growing ambition of Julius Caesar is a source of major concern to his close friend Brutus. Cassius persuades him to participate in his plot to assassinate Caesar but both have sorely underestimated Mark Antony.", vote_average: 7.098, vote_count: 234, genre_ids: [18, 36], runtime: 121, popularity: 2.1712, original_language: "en" },
  43350: { id: 43350, title: "Lili", release_date: "1953-03-10", poster_path: "/3vcaVT09imU0XlxClUlgMAYMexu.jpg", backdrop_path: "/9sb3ZuRM7QM5ubaEk0cCJfv4JvN.jpg", overview: "Members of a circus troupe \"adopt\" Lili Daurier when she finds herself stranded in a strange town. The magician who first comes to her rescue already has romantic entanglements and thinks of her as a little girl. Who can she turn to but the puppets, singing to them her troubles, forgetting that there are puppeteers? A crowd gathers around Lili as she sings. The circus has a new act. She now has a job. Will she get her heart's desire?", vote_average: 6.694, vote_count: 62, genre_ids: [10749, 18, 10402], runtime: 81, popularity: 2.2404, original_language: "en" },
  804: { id: 804, title: "Roman Holiday", release_date: "1953-08-26", poster_path: "/8lI9dmz1RH20FAqltkGelY1v4BE.jpg", backdrop_path: "/n0MyuZW9WJBGCYhzhfCI3d4zlRo.jpg", overview: "Overwhelmed by her suffocating schedule, touring European princess Ann takes off for a night while in Rome. When a sedative she took from her doctor kicks in, however, she falls asleep on a park bench and is found by an American reporter, Joe Bradley, who takes her back to his apartment for safety. At work the next morning, Joe finds out Ann's regal identity and bets his editor he can get exclusive interview with her, but romance soon gets in the way.", vote_average: 7.888, vote_count: 2248, genre_ids: [10749, 35, 18], runtime: 119, popularity: 7.6436, original_language: "en" },
