  632: { id: 632, title: "Stalag 17", release_date: "1953-05-29", poster_path: "/lfve9FDKjT7JPbWI9NCs5340F79.jpg", backdrop_path: "/rM3C9s0b9oiOQDdrfLSOoE0sjWl.jpg", overview: "After two American prisoners are killed by guards in the act of escaping from a German POW camp in World War II, barracks black marketeer J.J. Sefton is suspected of being an informer.", vote_average: 7.683, vote_count: 660, genre_ids: [35, 18, 10752], runtime: 120, popularity: 2.4783, original_language: "en" },
  47675: { id: 47675, title: "The Kidnappers", release_date: "1953-12-01", poster_path: "/sVXE6qp0rI73yWxFqZTrxsTeoDR.jpg", backdrop_path: "/y3bNlUYmHu6b6AiUsaRuaXKl4wN.jpg", overview: "After losing their father in the Boer War, orphaned brothers Harry and Davy must leave their home in Scotland to live with their grandmother and cantankerous grandfather in Nova Scotia. The boys want nothing more than a pet dog, but their grandfather refuses to get them one. Then, when the brothers find an abandoned baby, they decide to keep it – but the foundling may not have been abandoned after all.", vote_average: 6.667, vote_count: 15, genre_ids: [18, 35, 10751], runtime: 93, popularity: 0.8946, original_language: "en" },
  29912: { id: 29912, title: "The Robe", release_date: "1953-09-16", poster_path: "/qFYZNGzftIM8dqGMJBToGraAFJp.jpg", backdrop_path: "/sW414ljsyNH2g4BWb1Zg1Sbkflp.jpg", overview: "Drunk and disillusioned Roman, Marcellus Gallio, wins Jesus' robe in a dice game after the crucifixion. Marcellus has never been a man of faith like his slave, Demetrius, but when Demetrius escapes with the robe, Marcellus experiences disturbing visions and feels guilty for his actions. Convinced that destroying the robe will cure him, Marcellus sets out to find Demetrius — and discovers his Christian faith along the way.", vote_average: 6.9, vote_count: 278, genre_ids: [18, 36], runtime: 135, popularity: 3.961, original_language: "en" },
  8974: { id: 8974, title: "The War of the Worlds", release_date: "1953-04-03", poster_path: "/gzc75Za4ArqfXIIr7STNnIE5rnA.jpg", backdrop_path: "/74Q8M90Tg2TsV3iKjoDpJ77WPMJ.jpg", overview: "The residents of a small town are excited when a flaming meteor lands in the hills, until they discover it is the first of many transport devices from Mars bringing an army of invaders invincible to any man-made weapon, even the atomic bomb.", vote_average: 6.809, vote_count: 690, genre_ids: [878, 28], runtime: 85, popularity: 3.5807, original_language: "en" },
  51619: { id: 51619, title: "The Sound Barrier", release_date: "1952-07-22", poster_path: "/cExgxdISr0gEvVr74mmpEL4yLh4.jpg", backdrop_path: "/ycw1LTBimIrYIKegutP0SGULZG8.jpg", overview: "A young RAF pilot tests his father-in-law’s prototype supersonic aircraft to the limit, at a time of intense development in the field of aviation, just as commercial jet airliners are about to enter service.", vote_average: 6.5, vote_count: 58, genre_ids: [18, 10749, 10752], runtime: 117, popularity: 0.7704, original_language: "en" },
  5000: { id: 5000, title: "Forbidden Games", release_date: "1952-05-09", poster_path: "/nby91GNVXQAv1NmKvqlpEEdhcMQ.jpg", backdrop_path: "/iNkgF4uBzcFTrY3NN6JrlCD5Ho.jpg", overview: "Orphaned after a Nazi air raid, Paulette, a young Parisian girl, runs into Michel, an older peasant boy, and the two quickly become close. Together, they try to make sense of the chaotic and crumbling world around them, attempting to cope with death as they create a burial ground for Paulette's deceased pet dog. Eventually, however, Paulette's stay with Michel's family is threatened by the harsh realities of wartime.", vote_average: 7.756, vote_count: 351, genre_ids: [18, 10752], runtime: 87, popularity: 2.1461, original_language: "fr" },
  288: { id: 288, title: "High Noon", release_date: "1952-06-09", poster_path: "/qETSMQ4IXBSAS409Z9OL0ppXWTW.jpg", backdrop_path: "/raYHhtIDyh3qDS6WdyRzeqjLyIK.jpg", overview: "Will Kane, the sheriff of a small town in New Mexico, learns a notorious outlaw he put in jail has been freed, and will be arriving on the noon train. Knowing the outlaw and his gang are coming to kill him, Kane is determined to stand his ground, so he attempts to gather a posse from among the local townspeople.", vote_average: 7.667, vote_count: 1564, genre_ids: [37, 18, 53], runtime: 85, popularity: 5.6146, original_language: "en" },
