  90968: { id: 90968, title: "Plymouth Adventure", release_date: "1952-11-28", poster_path: "/p1bBvxJ4hD8MnLRlpH11wIOYyvA.jpg", backdrop_path: "/9dRmnUEVqzWx1CGXO49Xcif5MJY.jpg", overview: "During the Mayflower pilgrims' long voyage across the Atlantic Ocean on their way to America, Captain Christopher Jones falls in love with William Bradford's wife Dorothy.", vote_average: 5.913, vote_count: 23, genre_ids: [18, 12, 36], runtime: 105, popularity: 1.3225, original_language: "en" },
  488: { id: 488, title: "The African Queen", release_date: "1952-01-07", poster_path: "/2Ypg0KhQfFYWILelvHGtSHHR0dk.jpg", backdrop_path: "/doTKdtLfn2b7ZmeElmT6ZDW3XIk.jpg", overview: "At the start of the First World War, in the middle of Africa’s nowhere, a gin soaked riverboat captain is persuaded by a strong-willed missionary to go down river and face-off a German warship.", vote_average: 7.364, vote_count: 1050, genre_ids: [10749, 12, 18], runtime: 105, popularity: 2.8881, original_language: "en" },
  32499: { id: 32499, title: "The Bad and the Beautiful", release_date: "1952-12-25", poster_path: "/ajAXzTiPkL7JxeCRw5lQBqrKNGx.jpg", backdrop_path: "/jVyVSD0w4Bg3r67geP0LvkizfC5.jpg", overview: "Told in flashback form, the film traces the rise and fall of a tough, ambitious Hollywood producer, Jonathan Shields, as seen through the eyes of various acquaintances, including a writer, James Lee Bartlow; a star, Georgia Lorrison; and a director, Fred Amiel. He is a hard-driving, ambitious man who ruthlessly uses everyone on the way to becoming one of Hollywood's top movie makers.", vote_average: 7.285, vote_count: 291, genre_ids: [18, 10749], runtime: 118, popularity: 2.033, original_language: "en" },
  27191: { id: 27191, title: "The Greatest Show on Earth", release_date: "1952-02-16", poster_path: "/cKI0yGPRh1IlvRKKJRoMZruior8.jpg", backdrop_path: "/y22C1YyK8YXjU8LHoyA06MclOs6.jpg", overview: "To ensure a full profitable season, circus manager Brad Braden engages The Great Sebastian, though this moves his girlfriend Holly from her hard-won center trapeze spot. Holly and Sebastian begin a dangerous one-upmanship duel in the ring, while he pursues her on the ground.", vote_average: 6.363, vote_count: 274, genre_ids: [18, 10749], runtime: 152, popularity: 2.5112, original_language: "en" },
  3109: { id: 3109, title: "The Quiet Man", release_date: "1952-07-21", poster_path: "/u3B1hVKHE56yBRoxF3Nk9uxHdYN.jpg", backdrop_path: "/x67V2BApRy3XURCh6jccMT2GbIO.jpg", overview: "An American man returns to the village of his birth in Ireland, where he finds love and conflict.", vote_average: 7.316, vote_count: 602, genre_ids: [10749, 35, 18], runtime: 129, popularity: 3.3046, original_language: "en" },
  1810: { id: 1810, title: "Viva Zapata!", release_date: "1952-02-07", poster_path: "/vfarxn9ddiaZpRDml8FGhB46Qrc.jpg", backdrop_path: "/7aX2mfTcQArKS9PufnngjexnaQY.jpg", overview: "The story of Mexican revolutionary Emiliano Zapata, who led a rebellion against the corrupt, oppressive dictatorship of president Porfirio Díaz in the early 20th century.", vote_average: 6.854, vote_count: 236, genre_ids: [36, 18, 37], runtime: 113, popularity: 2.5874, original_language: "en" },
  65787: { id: 65787, title: "With a Song in My Heart", release_date: "1952-04-03", poster_path: "/KePfsUc63Z9J0xEKxwydlzNOkP.jpg", backdrop_path: "/jliwdbenSCvfkAJiXmNGJ25NRpa.jpg", overview: "Jane Froman, an aspiring songstress, lands a job in radio with help from pianist Don Ross, whom she later marries. Jane's popularity soars, and she leaves on a European tour... but her plane crashes in Lisbon, and she is partially crippled. Unable to walk without crutches, Jane nevertheless goes on to entertain the Allied troops in World War II.", vote_average: 6.059, vote_count: 17, genre_ids: [10402, 18], runtime: 117, popularity: 0.9226, original_language: "en" },
