  702: { id: 702, title: "A Streetcar Named Desire", release_date: "1951-09-18", poster_path: "/aicdlO5vt7z2ARm279eGzJeYCLQ.jpg", backdrop_path: "/or90vNrOVnYwi07fYYpQ3pbnjxP.jpg", overview: "A disturbed, aging Southern belle moves in with her sister for solace — but being face-to-face with her brutish brother-in-law accelerates her downward spiral.", vote_average: 7.618, vote_count: 1468, genre_ids: [18, 53], runtime: 125, popularity: 4.1205, original_language: "en" },
  2769: { id: 2769, title: "An American in Paris", release_date: "1951-09-26", poster_path: "/lyDXkvG53ldz6Cf7dbjJl7TaoP5.jpg", backdrop_path: "/hVvW015x8cD2X0KthGovw27EpF2.jpg", overview: "Jerry Mulligan is an exuberant American expatriate in Paris trying to make a reputation as a painter. His friend Adam is a struggling concert pianist who's a long time associate of a famous French singer, Henri Baurel. A lonely society woman, Milo Roberts, takes Jerry under her wing and supports him, but is interested in more than his art.", vote_average: 7.018, vote_count: 639, genre_ids: [10402, 10749, 35], runtime: 113, popularity: 2.6354, original_language: "en" },
  27629: { id: 27629, title: "Here Comes the Groom", release_date: "1951-09-20", poster_path: "/eboMQGKcRQJC1ZuYfeCudi0eiwY.jpg", backdrop_path: "/1oQavPqCmNKN4LBW5mGh3RYYKId.jpg", overview: "Foreign correspondent Pete Garvey has 5 days to win back his former fiancée, or he'll lose the orphans he adopted.", vote_average: 5.444, vote_count: 18, genre_ids: [35, 10402, 10749], runtime: 113, popularity: 0.8805, original_language: "en" },
  98328: { id: 98328, title: "The Great Caruso", release_date: "1951-04-16", poster_path: "/yNPl1UGjzXQCaQqdlB4CblFjsyl.jpg", backdrop_path: "/opIsf7BFQNPvMeBBvJQYxjJvI8u.jpg", overview: "Enrico Caruso's only passion is to sing. For that, he leaves his hometown of Naples, Italy, and travels to America to sing for the Metropolitan Opera. At first, his lack of education and poor background make him an outcast in the high-class opera world. Eventually, his voice wins him both fans and the hand of his love, Dorothy. But his nonstop pace and desire to perform at any cost eventually take their toll on the singer's health.", vote_average: 5.9, vote_count: 20, genre_ids: [18, 10402], runtime: 109, popularity: 1.0222, original_language: "en" },
  32961: { id: 32961, title: "The Lavender Hill Mob", release_date: "1951-06-28", poster_path: "/u4mZyim3CwXHu0zVhXjfK8fqoN7.jpg", backdrop_path: "/vPA53RF6clLSWlpoCLgYvmygiOl.jpg", overview: "A meek bank clerk who oversees the shipments of bullion joins with an eccentric neighbor to steal gold bars and smuggle them out of the country.", vote_average: 7.2, vote_count: 282, genre_ids: [35, 80], runtime: 78, popularity: 1.3936, original_language: "en" },
  16380: { id: 16380, title: "When Worlds Collide", release_date: "1951-09-14", poster_path: "/zVBEXGxtnD83t0PfKm9uZbnpDbA.jpg", backdrop_path: "/jETCGG40ffjUCH2SpZFGpqZ7w7g.jpg", overview: "When a group of astronomers calculate a star is on a course to slam into Earth, a few days before, it's accompanying planet will first pass close enough to the Earth to cause havoc on land and sea. They set about building a rocket so a few selected individuals can escape to the planet.", vote_average: 6.369, vote_count: 202, genre_ids: [878, 18], runtime: 83, popularity: 2.4175, original_language: "en" },
  705: { id: 705, title: "All About Eve", release_date: "1950-11-09", poster_path: "/blBzZaatPWVuWpXEnPscMA4Xp6m.jpg", backdrop_path: "/zAL3LOswagN9onjN8DPcNFTqKuD.jpg", overview: "From the moment she glimpses her idol at the stage door, Eve Harrington is determined to take the reins of power away from the great actress Margo Channing. Eve maneuvers her way into Margo's Broadway role, becomes a sensation and even causes turmoil in the lives of Margo's director boyfriend, her playwright and his wife. Only the cynical drama critic sees through Eve, admiring her audacity and perfect pattern of deceit.", vote_average: 8.078, vote_count: 1684, genre_ids: [18], runtime: 139, popularity: 3.7521, original_language: "en" },
