  24481: { id: 24481, title: "Born Yesterday", release_date: "1950-12-26", poster_path: "/hPiQUhnkgp2O9bQz9KhSyOjLvGl.jpg", backdrop_path: "/hX8pUUpUes6lwt4yN857eZRfNef.jpg", overview: "Uncouth, loud-mouth junkyard tycoon Harry Brock descends upon Washington D.C. to buy himself a congressman or two, bringing with him his mistress, ex-showgirl Billie Dawn.", vote_average: 7.246, vote_count: 185, genre_ids: [35, 10749], runtime: 103, popularity: 1.7342, original_language: "en" },
  129529: { id: 129529, title: "Captain Carey, U.S.A.", release_date: "1950-02-21", poster_path: "/54VkPpMmkZM4GQcESIG6s0PuvHs.jpg", backdrop_path: "/nzZJnSbFcuBaKFw1gUqHaK7rFUD.jpg", overview: "Near the end of World War II, a secret American raid on an enemy transportation hub goes very wrong when a turncoat warns the enemy. Led by Capt. Webster Carey, the mission causes the deaths of many bystanders -- among them, Carey believes, his Italian girlfriend, Giulia de Graffi. Back home, Carey stumbles across evidence that might uncover the identity of the informant. But, when he returns to Italy to get even, Carey is stunned by what he finds.", vote_average: 5.778, vote_count: 18, genre_ids: [9648, 53, 10752], runtime: 82, popularity: 1.2388, original_language: "en" },
  25392: { id: 25392, title: "Destination Moon", release_date: "1950-06-27", poster_path: "/2dsJUooqTX5BkOmkfnuuFlkmbB6.jpg", backdrop_path: "/3RKBbSG68HdAeXmVa3h9G7nBMbh.jpg", overview: "A team composed of an aerospace scientist, an ex-Air Force general, and an industrialist conceives an ambitious plan to land Americans on the moon. From their base in the Mojave Desert, they construct and successfully launch a spacecraft named \"Luna\" that contains a cargo of four astronauts. But a critical miscalculation of needed power to escape the moon's gravitational pull may put the astronauts' lives in danger.", vote_average: 5.911, vote_count: 96, genre_ids: [878, 12, 18], runtime: 91, popularity: 1.4465, original_language: "en" },
  11787: { id: 11787, title: "Harvey", release_date: "1950-12-04", poster_path: "/dgd82hYmpiXDM1G867HqNaWe8wj.jpg", backdrop_path: "/Ah7uiN6ws2QcBZhLdDfkiSJIX35.jpg", overview: "The story of Elwood P. Dowd who makes friends with a spirit taking the form of a human-sized rabbit named Harvey that only he sees (and a few privileged others on occasion also.) After his sister tries to commit him to a mental institution, a comedy of errors ensues. Elwood and Harvey become the catalysts for a family mending its wounds and for romance blossoming in unexpected places.", vote_average: 7.671, vote_count: 680, genre_ids: [35, 14], runtime: 104, popularity: 2.9426, original_language: "en" },
  43388: { id: 43388, title: "King Solomon's Mines", release_date: "1950-11-09", poster_path: "/s5T4Da7d3f255YRyaWfhMWfoBKK.jpg", backdrop_path: "/mZOrVI6HyFLpVVxAj6brA3LDEw.jpg", overview: "Fortune hunter Allan Quatermain teams up with a resourceful woman to help her find her missing husband lost in the wilds of 1900s Africa while being pursued by hostile tribes and a rival German explorer.", vote_average: 6.5, vote_count: 128, genre_ids: [12, 28, 10749], runtime: 103, popularity: 1.8801, original_language: "en" },
  32078: { id: 32078, title: "Panic in the Streets", release_date: "1950-07-27", poster_path: "/79jfETdOonIFL8UEjBxptPS27yo.jpg", backdrop_path: "/4Od8hhDwKRzMdKcdi1nJz2p7HWw.jpg", overview: "A medical examiner discovers that an innocent shooting victim in a robbery died of bubonic plague. With only 48 hours to find the killer, who is now a ticking time bomb threatening the entire city, a grisly manhunt through the seamy underworld of the New Orleans Waterfront is underway.", vote_average: 6.891, vote_count: 165, genre_ids: [53, 80], runtime: 96, popularity: 1.3932, original_language: "en" },
