  46932: { id: 46932, title: "Seven Days to Noon", release_date: "1950-10-30", poster_path: "/aDvEMfWqgCzMMBwKp1J2GashTga.jpg", backdrop_path: "/2Y6cQJRD0NuMjfSDFg697KfqtU5.jpg", overview: "When Professor Willingdon becomes wary of the nuclear weapons he is helping build, he steals a warhead and threatens to detonate it in London in seven days unless the government begins nuclear disarmament. As Willingdon goes into hiding, Detective Folland of Scotland Yard sets out to find him. Willingdon's daughter Ann also joins the cause, hoping she can talk sense into her father before he causes a catastrophe.", vote_average: 6.802, vote_count: 43, genre_ids: [53], runtime: 94, popularity: 0.8683, original_language: "en" },
