  31623: { id: 31623, title: "Battleground", release_date: "1949-11-09", poster_path: "/qSrcs7zmF61aRtzmOVPxeBBowap.jpg", backdrop_path: "/bam6RudCnYDj8YIZt2vi3bUTxSp.jpg", overview: "Members of the U.S. Army's 101st Airborne Division are fighting for their country amidst the rugged terrain of Bastogne, Belgium, in December 1944. Holley and his American compatriots have already seen one of their own, Roderigues, perish under enemy fire. The men try to rebuff another series of Nazi attacks, but what they really need is a change in the weather. Without clear skies, they'll never get the air support they need.", vote_average: 6.72, vote_count: 100, genre_ids: [28, 12, 18, 10752], runtime: 118, popularity: 2.1169, original_language: "en" },
