  39314: { id: 39314, title: "Mighty Joe Young", release_date: "1949-07-13", poster_path: "/tTTS9Bi7JReyGpCKyDuyZNSLTT4.jpg", backdrop_path: "/a2KwDRJyXFk4fFI9GccAozOEVLx.jpg", overview: "A young woman, Jill Young, grew up on her father's ranch in Africa, raising a large gorilla named Joe from an infant. Years later, she brings him to Hollywood to become a star.", vote_average: 6.41, vote_count: 122, genre_ids: [12, 14, 18, 28], runtime: 94, popularity: 2.5315, original_language: "en" },
  43437: { id: 43437, title: "Neptune's Daughter", release_date: "1949-06-10", poster_path: "/d9O19EfkPl9FCmGh6QfklCDcoIv.jpg", backdrop_path: "/woQsr8PpVmkaUFogenmzesq4h5l.jpg", overview: "Scatterbrained Betty Barrett mistakes masseur Jack Spratt for Jose O'Rourke, the captain of the South American polo team. Spratt goes along with the charade, but the situation becomes more complicated when they fall in love. Meanwhile, Betty's sensible older sister Eve fears Betty's heart will be broken when Jose returns to South America. She arranges to meet with the real O'Rourke and love soon blossoms between them as well.", vote_average: 6.063, vote_count: 32, genre_ids: [35, 10402, 10749], runtime: 95, popularity: 1.2102, original_language: "en" },
