  29993: { id: 29993, title: "Samson and Delilah", release_date: "1949-12-21", poster_path: "/d2AHCe6WzvshD7ucKuUWgugExjc.jpg", backdrop_path: "/vH5jfiKPG8N5suLbGLutZZulYAH.jpg", overview: "When strongman Samson rejects the love of the beautiful Philistine woman Delilah, she seeks vengeance that brings horrible consequences they both regret.", vote_average: 6.605, vote_count: 244, genre_ids: [10749, 18, 36], runtime: 134, popularity: 3.3626, original_language: "en" },
  13909: { id: 13909, title: "She Wore a Yellow Ribbon", release_date: "1949-10-22", poster_path: "/2IXtuwkTVcDsaa09AiQnlkfxe7I.jpg", backdrop_path: "/45tJCXfr3S08qb5fVP86duFUUzx.jpg", overview: "On the eve of retirement, Captain Nathan Brittles takes out a last patrol to stop an impending massive Indian attack. Encumbered by women who must be evacuated, Brittles finds his mission imperiled.", vote_average: 6.923, vote_count: 403, genre_ids: [18, 37], runtime: 104, popularity: 2.3801, original_language: "en" },
  28571: { id: 28571, title: "The Heiress", release_date: "1949-10-06", poster_path: "/1oN0zsjw3iS1HaOLoZbmptzrD1W.jpg", backdrop_path: "/56eHAxXfZTz5pGiVDCFnuiHw2fp.jpg", overview: "In 1840s New York, the uneventful and boring days of the daughter of a wealthy doctor come to an end when she meets a dashing poorer man — who may or may not be after her inheritance.", vote_average: 7.771, vote_count: 277, genre_ids: [18, 10749, 36], runtime: 115, popularity: 2.6934, original_language: "en" },
