  15497: { id: 15497, title: "Twelve O'Clock High", release_date: "1949-12-21", poster_path: "/g9VeQUobhofLwxSIbKM4ia5biAX.jpg", backdrop_path: "/fVnphXrYJTH8xPKvJCtzSwZycFC.jpg", overview: "In the early days of daylight bombing raids over Germany, General Frank Savage must take command of a 'hard luck' bomber group. Much of the story deals with his struggle to whip his group into a disciplined fighting unit in spite of heavy losses, and withering attacks by German fighters over their targets.", vote_average: 7.13, vote_count: 158, genre_ids: [10752, 28, 18], runtime: 132, popularity: 1.8461, original_language: "en" },
  34233: { id: 34233, title: "Adventures of Don Juan", release_date: "1948-12-24", poster_path: "/5kI8MwkTQWBGsFqwDTVkvMDOHg2.jpg", backdrop_path: "/urfEevdzNXukF7ygoHZzDDgGHCa.jpg", overview: "Spanish Lothario Don Juan, the legendary lover and adventurer returns to Spain following a scandal and comes to the aid of his queen, who is under threat from sinister forces.", vote_average: 6.744, vote_count: 43, genre_ids: [12, 10749, 28], runtime: 106, popularity: 1.3675, original_language: "en" },
  5156: { id: 5156, title: "Bicycle Thieves", release_date: "1948-07-21", poster_path: "/iPdVqIpmR3bRvOQJPrn4pr2KR3q.jpg", backdrop_path: "/nd6ItWuWGmTKhHXuxVC8kp86CmQ.jpg", overview: "Unemployed Antonio is elated when he finally finds work hanging posters around war-torn Rome. However on his first day, his bicycle—essential to his work—gets stolen. His job is doomed unless he can find the thief. With the help of his son, Antonio combs the city, becoming desperate for justice.", vote_average: 8.172, vote_count: 2643, genre_ids: [18], runtime: 89, popularity: 4.4619, original_language: "it" },
  126805: { id: 126805, title: "Bill and Coo", release_date: "1948-03-28", poster_path: "/rgwc4jYyS4TWwfYMweSA2pAb2hM.jpg", backdrop_path: "/jqMCY0OT8JirKGGUkHac2Zm4HuT.jpg", overview: "The feathered residents of Chirpendale are terrorized by an evil black crow by the name of \"The Black Menace\". But to the citizen's rescue comes a brave young taxi puller named Bill!  In other words, every single role in this film is played by birds. Actual birds.", vote_average: 6.667, vote_count: 12, genre_ids: [10751, 14], runtime: 61, popularity: 0.5311, original_language: "en" },
  29380: { id: 29380, title: "Easter Parade", release_date: "1948-07-08", poster_path: "/aLgvafQvb6D6at4khC0b7kn0h8f.jpg", backdrop_path: "/g2MffH3EQXvjSnFF8ol1VkuAKci.jpg", overview: "On the day before Easter in 1911, Don Hewes is crushed when his dancing partner (and object of affection) Nadine Hale refuses to start a new contract with him. To prove Nadine's not important to him, Don acquires innocent new protege Hannah Brown, vowing to make her a star in time for next year's Easter parade.", vote_average: 7.03, vote_count: 152, genre_ids: [10749, 10402], runtime: 103, popularity: 2.08, original_language: "en" },
  23383: { id: 23383, title: "Hamlet", release_date: "1948-12-10", poster_path: "/woO9SgU2vTRMZeG0YqOLeoIqlzC.jpg", backdrop_path: "/tFfucMJh4Me1JYBIRJcOokWWuLs.jpg", overview: "Winner of four Academy Awards, including Best Picture and Best Actor, Sir Laurence Olivier’s Hamlet continues to be the most compelling version of Shakespeare’s beloved tragedy. Olivier is at his most inspired—both as director and as the melancholy Dane himself—as he breathes new life into the words of one of the world’s greatest dramatists.", vote_average: 7.436, vote_count: 288, genre_ids: [18], runtime: 153, popularity: 2.0067, original_language: "en" },
