  11016: { id: 11016, title: "Key Largo", release_date: "1948-07-16", poster_path: "/rySfmQQZhS7RswOiJcJrww6FcHy.jpg", backdrop_path: "/m2SXRnAd0d5N6qH2cbgluRgMX4z.jpg", overview: "A hurricane swells outside, but it's nothing compared to the storm within the hotel at Key Largo. There, sadistic mobster Johnny Rocco holes up - and holds at gunpoint hotel owner James Temple, his widowed daughter-in-law Nora, and ex-GI Frank McCloud.", vote_average: 7.5, vote_count: 583, genre_ids: [80, 53], runtime: 100, popularity: 1.9706, original_language: "en" },
