  19542: { id: 19542, title: "The Red Shoes", release_date: "1948-09-06", poster_path: "/vPvpBWFWDvEXuQBkoYgA6A89GVp.jpg", backdrop_path: "/cSbBSHHiy849SUhyTW6FX4Dbj43.jpg", overview: "A fledgling ballerina falls in love with a brilliant composer, but the jealous head of the ballet company plots to drive them apart.", vote_average: 7.981, vote_count: 742, genre_ids: [18, 10749], runtime: 133, popularity: 2.844, original_language: "en" },
  41131: { id: 41131, title: "The Search", release_date: "1948-03-26", poster_path: "/jDP8XxQUJTTofJPkhFER3aBYDqR.jpg", backdrop_path: "/4wjo1gxtDzavaqEPEK3gT4lmXG2.jpg", overview: "In postwar Germany, a displaced Czech boy, separated from his family during wartime, is befriended by an American GI while the boy's mother desperately searches for him.", vote_average: 6.963, vote_count: 82, genre_ids: [18, 10752], runtime: 104, popularity: 1.2252, original_language: "en" },
  62694: { id: 62694, title: "The Snake Pit", release_date: "1948-11-04", poster_path: "/wLO2TVjM4UUQUwOq7RqfS8PCdMC.jpg", backdrop_path: "/xyPp8XpOozFfpZmYSlz0h9SpOpO.jpg", overview: "Virginia Cunningham is confused upon finding herself in a mental hospital, with no memory of her arrival at the institution. Tormented by delusions and unable to even recognize her husband, Robert, she is treated by Dr. Mark Kik, who is determined to get to the root of her mental illness. As her treatment progresses, flashbacks depict events in Virginia's life that may have contributed to her instability.", vote_average: 7.098, vote_count: 117, genre_ids: [18, 9648], runtime: 108, popularity: 1.5706, original_language: "en" },
  3090: { id: 3090, title: "The Treasure of the Sierra Madre", release_date: "1948-01-15", poster_path: "/pWcst7zVbi8Z8W6GFrdNE7HHRxL.jpg", backdrop_path: "/osytHgkv86CTFKxo46l9P7ACEjm.jpg", overview: "Two jobless Americans convince a prospector to travel to the mountains of Mexico with them in search of gold. But the hostile wilderness, local bandits, and greed all get in the way of their journey.", vote_average: 7.959, vote_count: 1332, genre_ids: [12, 18, 37], runtime: 126, popularity: 3.5126, original_language: "en" },
  41206: { id: 41206, title: "A Double Life", release_date: "1947-12-25", poster_path: "/rYa7JZN5PnpxXpR4oXAcefP9YXa.jpg", backdrop_path: "/r9xIDDGz1AsKkPWiFGCTmFlVkWN.jpg", overview: "A Shakespearian actor starring as Othello opposite his wife finds the character's jealous rage taking over his mind off-stage.", vote_average: 6.348, vote_count: 82, genre_ids: [18, 53], runtime: 104, popularity: 1.3354, original_language: "en" },
  16391: { id: 16391, title: "Black Narcissus", release_date: "1947-05-26", poster_path: "/jSbFWWbkUq5N5ikewJHNATcWnxS.jpg", backdrop_path: "/hAyWibhJjMHyWXrMVX8N2MrEqF8.jpg", overview: "A group of Anglican nuns, led by Sister Clodagh, are sent to a mountain in the Himalayas. The climate in the region is hostile and the nuns are housed in an odd old palace. They work to establish a school and a hospital, but slowly their focus shifts. Sister Ruth falls for a government worker, Mr. Dean, and begins to question her vow of celibacy. As Sister Ruth obsesses over Mr. Dean, Sister Clodagh becomes immersed in her own memories of love.", vote_average: 7.514, vote_count: 544, genre_ids: [18], runtime: 100, popularity: 2.077, original_language: "en" },
  17487: { id: 17487, title: "Body and Soul", release_date: "1947-11-11", poster_path: "/lnKYS1A1k78X5v5IpLA96e6EYoe.jpg", backdrop_path: "/wbky6s7YnNgUBE9ENAe4pJfFaUr.jpg", overview: "Charley Davis, against the wishes of his mother, becomes a boxer. As he becomes more successful the fighter becomes surrounded by shady characters, including an unethical promoter named Roberts, who tempt the man with a number of vices. Charley finds himself faced with increasingly difficult choices.", vote_average: 6.703, vote_count: 118, genre_ids: [18], runtime: 104, popularity: 1.2228, original_language: "en" },
  33667: { id: 33667, title: "Gentleman's Agreement", release_date: "1947-11-11", poster_path: "/aCCRbcmigPk00f34hpJuWZuvABo.jpg", backdrop_path: "/4XMEwQVADrym6XWcxudH11caLCA.jpg", overview: "A magazine writer poses as a Jew to expose anti-Semitism.", vote_average: 6.989, vote_count: 273, genre_ids: [18], runtime: 118, popularity: 1.7444, original_language: "en" },
  108994: { id: 108994, title: "Green Dolphin Street", release_date: "1947-01-15", poster_path: "/otyQj68iZSm3ezzaQJOJa3rfRsW.jpg", backdrop_path: "/jnrHsz0meZoJwcshhxqoMkXLgQC.jpg", overview: "Sophie loved Edmund, but he left town when her parents forced her to marry wealthy Octavius. Years later, Edmund returns with his son, William. Sophie's daughter, Marguerite, and William fall in love. Marguerite's sister, Marianne, also loves William. Timothy, a lowly carpenter, secretly loves Marianne. He kills a man in a fight, and Edmund helps him flee to New Zealand. William deserts inadvertently from the navy, and also flees in disgrace to New Zealand, where he and Timothy start a profitable business. One night, drunk, William writes Octavius, demanding his daughter's hand; but, being drunk, he asks for the wrong sister.", vote_average: 6.275, vote_count: 20, genre_ids: [18, 36, 10749], runtime: 141, popularity: 0.817, original_language: "en" },
  11881: { id: 11881, title: "Miracle on 34th Street", release_date: "1947-06-04", poster_path: "/vehuIm3y6BeMI7mYjxzaA1H8M0k.jpg", backdrop_path: "/hHYoUYgto562dcQRjVuuVlosBKz.jpg", overview: "Kris Kringle, seemingly the embodiment of Santa Claus, is asked to portray the jolly old fellow at Macy's following his performance in the Thanksgiving Day parade. His portrayal is so complete that many begin to question if he truly is Santa Claus, while others question his sanity.", vote_average: 7.372, vote_count: 839, genre_ids: [35, 18, 10751], runtime: 96, popularity: 3.9535, original_language: "en" },
