  106825: { id: 106825, title: "Mother Wore Tights", release_date: "1947-08-20", poster_path: "/60FY8mXol3sRdbH4o12ylYPtQKE.jpg", backdrop_path: "/etd7TEKWJVTu8Ll0BIKYMV0UVqm.jpg", overview: "In this chronicle of a vaudeville family, Myrtle McKinley (class of 1900) goes to San Francisco to attend business school, but ends up in a chorus line. Soon, star Frank Burt notices her talent, hires her for a \"two-act\", then marries her. Incidents of the marriage and the growing pains of eldest daughter Miriam are followed, interspersed with nostalgic musical numbers.", vote_average: 5.727, vote_count: 11, genre_ids: [10402, 18], runtime: 107, popularity: 1.0714, original_language: "en" },
  27437: { id: 27437, title: "The Bachelor and the Bobby-Soxer", release_date: "1947-09-01", poster_path: "/eeBn5yhOBMBq2qQ9x2xQHyP1ZJk.jpg", backdrop_path: "/bibt7aP2Cf6Mtp43eriWadryE9f.jpg", overview: "Teenager Susan Turner, with a severe crush on playboy artist Richard Nugent, sneaks into his apartment to model for him and is found there by her sister Judge Margaret Turner. Threatened with jail, Nugent agrees to date Susan until the crush abates.", vote_average: 6.896, vote_count: 139, genre_ids: [35, 10749], runtime: 95, popularity: 1.2586, original_language: "en" },
  19490: { id: 19490, title: "The Bishop's Wife", release_date: "1947-12-25", poster_path: "/2sMpffmvoJlW7WBcvyHTPR9DEsj.jpg", backdrop_path: "/fVEynIdJC8gRpslMfGXyZXrz5ar.jpg", overview: "An Episcopal Bishop, Henry Brougham, has been working for months on the plans for an elaborate new cathedral which he hopes will be paid for primarily by a wealthy, stubborn widow. He is losing sight of his family and of why he became a churchman in the first place. Enter Dudley, an angel sent to help him. Dudley does help everyone he meets, but not necessarily in the way they would have preferred. With the exception of Henry, everyone loves him, but Henry begins to believe that Dudley is there to replace him, both at work and in his family's affections, as Christmas approaches.", vote_average: 7.094, vote_count: 277, genre_ids: [35, 14, 18, 10749], runtime: 109, popularity: 1.8735, original_language: "en" },
