  43471: { id: 43471, title: "Anna and the King of Siam", release_date: "1946-08-11", poster_path: "/yg4hXEWzWsLI3rgzqrC1KzCYzM1.jpg", backdrop_path: "/wcuLN4VaPWb59Q0l9edUjmqQuW4.jpg", overview: "In 1862, a young Englishwoman becomes royal tutor in Siam and befriends the King.", vote_average: 6.179, vote_count: 42, genre_ids: [18, 10749], runtime: 128, popularity: 0.9971, original_language: "en" },
  14320: { id: 14320, title: "Great Expectations", release_date: "1946-12-26", poster_path: "/ynaFuVvW2jaG06pMV67dOhzMYfJ.jpg", backdrop_path: "/5SdVucbeGF5xAHT496uPRPZVJD6.jpg", overview: "In this Dickens adaptation, orphan Pip discovers through lawyer Mr. Jaggers that a mysterious benefactor wishes to ensure that he becomes a gentleman. Reunited with his childhood patron, Miss Havisham, and his first love, the beautiful but emotionally cold Estella, he discovers that the elderly spinster has gone mad from having been left at the altar as a young woman, and has made her charge into a warped, unfeeling heartbreaker.", vote_average: 7.301, vote_count: 370, genre_ids: [18, 10749], runtime: 118, popularity: 2.5301, original_language: "en" },
