  31206: { id: 31206, title: "The Jolson Story", release_date: "1946-10-10", poster_path: "/TA8OqACOphikMD16HLeohJqPk.jpg", backdrop_path: "/cxQ1yRHsxotDjiyk5TB8JgP8YWt.jpg", overview: "At the turn of the 20th century, young Asa Yoelson decides to go against the wishes of his cantor father and pursue a career in show business. Gradually working his way up through the vaudeville ranks, Asa — now calling himself Al Jolson — joins a blackface minstrel troupe and soon builds a reputation as a consummate performer. But as his career grows in size, so does his ego, resulting in battles in business as well as in his personal life.", vote_average: 6.75, vote_count: 18, genre_ids: [18, 10402], runtime: 128, popularity: 0.8908, original_language: "en" },
