  52679: { id: 52679, title: "The Last Command", release_date: "1928-01-21", poster_path: "/uKb5bFIwEzDtT3km99lqQBGNFCx.jpg", backdrop_path: "/n3rEkTewthP1VIhwTCaJXYrEE0n.jpg", overview: "A former Imperial Russian general and cousin of the Czar ends up in Hollywood as an extra in a movie directed by a former revolutionary.", vote_average: 7.333, vote_count: 90, genre_ids: [18, 36, 10752, 10749], runtime: 88, popularity: 1.0419, original_language: "en" },
  83990: { id: 83990, title: "The Patriot", release_date: "1928-09-01", poster_path: "/2eDSqz95WrPKLMPllZlEe2iKpYE.jpg", backdrop_path: "/pW223GtoBXdhYxdux4YohErWetZ.jpg", overview: "In 18th-Century Russia, the Czar, Paul, is surrounded by murderous plots and trusts only Count Pahlen. Pahlen wishes to protect his friend, the mad king, but because of the horror of the king's acts, he feels that he must remove him from the throne.", vote_average: 5.75, vote_count: 4, genre_ids: [18, 36], runtime: 113, popularity: 0.9038, original_language: "en" },
  53161: { id: 53161, title: "White Shadows in the South Seas", release_date: "1928-11-11", poster_path: "/5iIGEpnUrhlPALt7geqnFbhSTj3.jpg", backdrop_path: "/twa5pQHucDuDPqDfsEYtB2WC2UF.jpg", overview: "An alcoholic doctor on a Polynesian island, disgusted by white exploitation of the natives, finds himself marooned on a pristinely beautiful island.", vote_average: 6.712, vote_count: 26, genre_ids: [10749, 12, 18], runtime: 88, popularity: 0.5937, original_language: "en" },
