  79760: { id: 79760, title: "The Dove", release_date: "1927-12-31", poster_path: "/ttnc8Rd4hdHj8soNqKmyDXnIJtd.jpg", backdrop_path: null, overview: "Norma Talmadge plays a Mexican saloon singer, known as 'The Dove.' She is romanced by a young caballero and menaced by a Villa-like brute of a dictator, played by Noah Beery.", vote_average: 6.833, vote_count: 6, genre_ids: [10749], runtime: 90, popularity: 0.7146, original_language: "en" },
  939: { id: 939, title: "The Jazz Singer", release_date: "1927-10-06", poster_path: "/wr8Pt1GO87cwB3210TO3JTNDsUc.jpg", backdrop_path: "/515FMUnY7irFM0zsMKPvclMUUnJ.jpg", overview: "A young Jewish man is torn between tradition and individuality when his old-fashioned family objects to his career as a jazz singer. This is the first full length feature film to use synchronized sound, and is the original film musical.", vote_average: 6.118, vote_count: 250, genre_ids: [18, 10402], runtime: 96, popularity: 1.8412, original_language: "en" },
