  42565: { id: 42565, title: "Underworld", release_date: "1927-08-20", poster_path: "/6ZjgbeCwS7sipil1J221lbjaqGG.jpg", backdrop_path: "/1NYCVTVWmwy0r5KYD1CXk8RcRyj.jpg", overview: "Boisterous gangster kingpin Bull Weed rehabilitates his former lawyer from his alcoholic haze, but complications arise when he falls for Weed's girlfriend.", vote_average: 7.017, vote_count: 88, genre_ids: [18, 80, 10749], runtime: 87, popularity: 1.4397, original_language: "en" },
  28966: { id: 28966, title: "Wings", release_date: "1927-08-12", poster_path: "/kEl6KCBgdmT1Nex3ka0EIWAOmtm.jpg", backdrop_path: "/u90ajspDd9911ISbx74rtofQZfO.jpg", overview: "Two young men, one rich, one middle class, both in love with the same woman, become US Air Corps fighter pilots and, eventually, heroic flying aces during World War I. Devoted best friends, their mutual love of the girl eventually threatens their bond. Meanwhile, a hometown girl who's the lovestruck lifelong next door neighbor of one of them pines away.", vote_average: 7.222, vote_count: 322, genre_ids: [18, 28, 10752, 10749], runtime: 144, popularity: 3.4108, original_language: "en" },
  24428: { id: 24428, title: "The Avengers", release_date: "2012-04-25", poster_path: "/RYMX2wcKCBAr24UyPD7xwmjaTn.jpg", backdrop_path: "/9BBTo63ANSmhC4e6r62OJFuK2GL.jpg", overview: "When an unexpected enemy emerges and threatens global safety and security, Nick Fury, director of the international peacekeeping agency known as S.H.I.E.L.D., finds himself in need of a team to pull the world back from the brink of disaster. Spanning the globe, a daring recruitment effort begins!", vote_average: 8.012, vote_count: 37535, genre_ids: [878, 28, 12], runtime: 143, popularity: 54.2112, original_language: "en" },
  293660: { id: 293660, title: "Deadpool", release_date: "2016-02-09", poster_path: "/3E53WEZJqP6aM84D8CckXx4pIHw.jpg", backdrop_path: "/en971MEXui9diirXlogOrPKmsEn.jpg", overview: "The origin story of former Special Forces operative turned mercenary Wade Wilson, who, after being subjected to a rogue experiment that leaves him with accelerated healing powers, adopts the alter ego Deadpool. Armed with his new abilities and a dark, twisted sense of humor, Deadpool hunts down the man who nearly destroyed his life.", vote_average: 7.623, vote_count: 32627, genre_ids: [28, 12, 35], runtime: 108, popularity: 18.5577, original_language: "en" },
  299536: { id: 299536, title: "Avengers: Infinity War", release_date: "2018-04-25", poster_path: "/7WsyChQLEftFiDOVTGkv3hFpyyt.jpg", backdrop_path: "/mDfJG3LC3Dqb67AZ52x3Z0jU0uB.jpg", overview: "As the Avengers and their allies have continued to protect the world from threats too large for any one hero to handle, a new danger has emerged from the cosmic shadows: Thanos. A despot of intergalactic infamy, his goal is to collect all six Infinity Stones, artifacts of unimaginable power, and use them to inflict his twisted will on all of reality. Everything the Avengers have fought for has led up to this moment - the fate of Earth and existence itself has never been more uncertain.", vote_average: 8.234, vote_count: 31811, genre_ids: [12, 28, 878], runtime: 149, popularity: 50.409, original_language: "en" },
