  64688: { id: 64688, title: "21 Jump Street", release_date: "2012-03-14", poster_path: "/8v3Sqv9UcIUC4ebmpKWROqPBINZ.jpg", backdrop_path: "/d1ACwtoBygLKkGjCq9LUXnmcki.jpg", overview: "When cops Schmidt and Jenko join the secret Jump Street unit, they use their youthful appearances to go undercover as high school students. They trade in their guns and badges for backpacks, and set out to shut down a dangerous drug ring. But, as time goes on, Schmidt and Jenko discover that high school is nothing like it was just a few years earlier -- and, what's more, they must again confront the teenage terror and anxiety they thought they had left behind.", vote_average: 6.886, vote_count: 10964, genre_ids: [28, 35, 80], runtime: 109, popularity: 7.8296, original_language: "en" },
  41154: { id: 41154, title: "Men in Black 3", release_date: "2012-05-23", poster_path: "/90DdoEStzeObs96fsYf4GG544iN.jpg", backdrop_path: "/5AhpUb8CAP0jZ4Wrn7AsRUYjZxB.jpg", overview: "Agents J and K are back...in time. J has seen some inexplicable things in his 15 years with the Men in Black, but nothing, not even aliens, perplexes him as much as his wry, reticent partner. But when K's life and the fate of the planet are put at stake, Agent J will have to travel back in time to put things right. J discovers that there are secrets to the universe that K never told him - secrets that will reveal themselves as he teams up with the young Agent K to save his partner, the agency, and the future of humankind.", vote_average: 6.541, vote_count: 10932, genre_ids: [28, 35, 878], runtime: 106, popularity: 7.1425, original_language: "en" },
