  420818: { id: 420818, title: "The Lion King", release_date: "2019-07-12", poster_path: "/dzBtMocZuJbjLOXvrl4zGYigDzh.jpg", backdrop_path: "/1TUg5pO1VZ4B0Q1amk3OlXvlpXV.jpg", overview: "Simba idolizes his father, King Mufasa, and takes to heart his own royal destiny. But not everyone in the kingdom celebrates the new cub's arrival. Scar, Mufasa's brother—and former heir to the throne—has plans of his own. The battle for Pride Rock is ravaged with betrayal, tragedy and drama, ultimately resulting in Simba's exile. With help from a curious pair of newfound friends, Simba will have to figure out how to grow up and take back what is rightfully his.", vote_average: 7.098, vote_count: 10715, genre_ids: [12, 18, 10751, 16], runtime: 118, popularity: 15.9622, original_language: "en" },
  56292: { id: 56292, title: "Mission: Impossible - Ghost Protocol", release_date: "2011-12-07", poster_path: "/eRZTGx7GsiKqPch96k27LK005ZL.jpg", backdrop_path: "/ih4lZkUpmSE7AP3maymiO72xJ1z.jpg", overview: "Ethan Hunt and his team are racing against time to track down a dangerous terrorist named Hendricks, who has gained access to Russian nuclear launch codes and is planning a strike on the United States. An attempt to stop him ends in an explosion causing severe destruction to the Kremlin and the IMF to be implicated in the bombing, forcing the President to disavow them. No longer being aided by the government, Ethan and his team chase Hendricks around the globe, although they might still be too late to stop a disaster.", vote_average: 7.111, vote_count: 10717, genre_ids: [28, 53, 12], runtime: 133, popularity: 10.0365, original_language: "en" },
