  772: { id: 772, title: "Home Alone 2: Lost in New York", release_date: "1992-11-15", poster_path: "/uuitWHpJwxD1wruFl2nZHIb4UGN.jpg", backdrop_path: "/8fnYJPoXxwAN4valDLgz2whMGTH.jpg", overview: "Instead of flying to Florida with his folks, Kevin ends up alone in New York, where he gets a hotel room with his dad's credit card—despite problems from a clerk and meddling bellboy. But when Kevin runs into his old nemeses, the Wet Bandits, he's determined to foil their plans to rob a toy store on Christmas Eve.", vote_average: 6.785, vote_count: 10564, genre_ids: [35, 10751, 12], runtime: 120, popularity: 15.5958, original_language: "en" },
