  176: { id: 176, title: "Saw", release_date: "2004-10-01", poster_path: "/rLNSOudrayDBo1uqXjrhxcjODIC.jpg", backdrop_path: "/ok4ot3YbfDYZcINXf91JUfq3maB.jpg", overview: "Two men wake up to find themselves shackled in a grimy, abandoned bathroom. As they struggle to comprehend their predicament, they discover a disturbing tape left behind by the sadistic mastermind known as Jigsaw. With a chilling voice and cryptic instructions, Jigsaw informs them that they must partake in a gruesome game in order to secure their freedom.", vote_average: 7.421, vote_count: 9995, genre_ids: [27, 9648, 80], runtime: 103, popularity: 11.7952, original_language: "en" },
  954: { id: 954, title: "Mission: Impossible", release_date: "1996-05-22", poster_path: "/l5uxY5m5OInWpcExIpKG6AR3rgL.jpg", backdrop_path: "/sra8XnL96OyLHENcglmZJg6HA8z.jpg", overview: "When Ethan Hunt, the leader of a crack espionage team whose perilous operation has gone awry with no explanation, discovers that a mole has penetrated the CIA, he's surprised to learn that he's the prime suspect. To clear his name, Hunt now must ferret out the real double agent and, in the process, even the score.", vote_average: 7.024, vote_count: 9923, genre_ids: [12, 28, 53], runtime: 111, popularity: 11.8075, original_language: "en" },
  564: { id: 564, title: "The Mummy", release_date: "1999-04-16", poster_path: "/yhIsVvcUm7QxzLfT6HW2wLf5ajY.jpg", backdrop_path: "/8zLS8p1tRyWFLRFfmgQq0j5WE6z.jpg", overview: "Dashing legionnaire Rick O'Connell stumbles upon the hidden ruins of Hamunaptra while in the midst of a battle to claim the area in 1920s Egypt. It has been over three thousand years since former High Priest Imhotep suffered a fate worse than death as a punishment for a forbidden love—along with a curse that guarantees eternal doom upon the world if he is ever awoken.", vote_average: 6.966, vote_count: 9918, genre_ids: [12, 28, 14], runtime: 124, popularity: 21.6071, original_language: "en" },
  156022: { id: 156022, title: "The Equalizer", release_date: "2014-09-24", poster_path: "/9u4yW7yPA0BQ2pv9XwiNzItwvp8.jpg", backdrop_path: "/wNAfVj1ObGNye5fQM4tJXJGtU0.jpg", overview: "McCall believes he has put his mysterious past behind him and dedicated himself to beginning a new, quiet life. But when he meets Teri, a young girl under the control of ultra-violent Russian gangsters, he can’t stand idly by – he has to help her. Armed with hidden skills that allow him to serve vengeance against anyone who would brutalize the helpless, McCall comes out of his self-imposed retirement and finds his desire for justice reawakened. If someone has a problem, if the odds are stacked against them, if they have nowhere else to turn, McCall will help. He is The Equalizer.", vote_average: 7.284, vote_count: 9888, genre_ids: [53, 28, 80], runtime: 132, popularity: 18.4612, original_language: "en" },
  810: { id: 810, title: "Shrek the Third", release_date: "2007-05-17", poster_path: "/n4SexGGQzI26E269tfpa80MZaGV.jpg", backdrop_path: "/wvXxKpFGXvQJRB0nvvfURhRD3C0.jpg", overview: "The King of Far Far Away has died and Shrek and Fiona are to become King & Queen. However, Shrek wants to return to his cozy swamp and live in peace and quiet, so when he finds out there is another heir to the throne, they set off to bring him back to rule the kingdom.", vote_average: 6.3, vote_count: 9730, genre_ids: [14, 12, 16, 35, 10751], runtime: 93, popularity: 9.8724, original_language: "en" },
  124905: { id: 124905, title: "Godzilla", release_date: "2014-05-14", poster_path: "/tphkjmQq8WebuVwNXelmjLUXuPJ.jpg", backdrop_path: "/cHvwgJPaT59H1HiQsvBrGD5I46g.jpg", overview: "Ford Brody, a Navy bomb expert, has just reunited with his family in San Francisco when he is forced to go to Japan to help his estranged father, Joe. Soon, both men are swept up in an escalating crisis when an ancient alpha predator arises from the sea to combat malevolent adversaries that threaten the survival of humanity. The creatures leave colossal destruction in their wake, as they make their way toward their final battleground: San Francisco.", vote_average: 6.353, vote_count: 9726, genre_ids: [28, 18, 878], runtime: 123, popularity: 9.5697, original_language: "en" },
