  18289: { id: 18289, title: "Godzilla vs. Biollante", release_date: "1989-12-16", poster_path: "/me4CanEAtNm03LXlFJOyhX3FsMF.jpg", backdrop_path: "/wh832wXrqIVdSC5271fkJIuyji4.jpg", overview: "After the previous Godzilla attack, a miniature arms race ensues to collect his cells. Concerned over Godzilla's possible return, the Japanese government uses the cells to create a new bio-weapon, ANEB (Anti-Nuclear Energy Bacteria). They seeks the aid of geneticist Genshiro Shiragami, who's experiments result in a new mutation.", vote_average: 7.4, vote_count: 296, genre_ids: [28, 27, 878], runtime: 105, popularity: 3.1501, original_language: "ja" },
