  64131: { id: 64131, title: "Mauvais Sang", release_date: "1986-11-26", poster_path: "/yjUmAFx8Z3E0K1IUpQSyUilL5P9.jpg", backdrop_path: "/sRY16xQIV5lHL1yTotyqPyyjsju.jpg", overview: "Two aging crooks are given two weeks to repay a debt to a woman named The American. They recruit their recently deceased partner's son to help them break into a laboratory and steal the vaccine against STBO, a sexually transmitted disease that is sweeping the country. It's spread by having sex without emotional involvement, and most of its victims are teenagers who make love out of curiosity rather than commitment.", vote_average: 7.111, vote_count: 279, genre_ids: [80, 878, 10749], runtime: 119, popularity: 1.5897, original_language: "fr" },
