  29343: { id: 29343, title: "Humanoids from the Deep", release_date: "1980-05-01", poster_path: "/jVqNWDvTIwjcHsMyNSUT0sfGrq9.jpg", backdrop_path: "/r8yPArXK4Wbn0MTmSn4E4ibI7a2.jpg", overview: "After a new cannery introduces scientifically augmented salmon to a seaside town in the Pacific Northwest, a species of mysterious, mutated sea creatures begin killing the men and raping the women.", vote_average: 5.8, vote_count: 273, genre_ids: [27, 878], runtime: 80, popularity: 1.5605, original_language: "en" },
