  31769: { id: 31769, title: "Venus Wars", release_date: "1989-03-11", poster_path: "/jiinIVM64yRulfzxzZAfZKV9LmY.jpg", backdrop_path: "/eEyCiluDMwk61LsH9aZvnsNvYDj.jpg", overview: "The new frontier of Venus has degenerated into a dystopia ravaged by the civil war between Ishtar and Aphrodia. Bubbly reporter Susan Sommers arrives in the capitol of Aphrodia just before it's captured by Ishtar. She falls in with a bunch of teen-agers who live for a sort of motorcycle version of Roller Derby. Daredevil rider Hiro and his friends reluctantly join the struggle to free Aphrodia from the invaders. Not surprisingly, Hiro proves an ace at piloting the mono-cycles that are the Aphrodians' secret weapon in the key battle.", vote_average: 6.734, vote_count: 64, genre_ids: [28, 16, 878], runtime: 102, popularity: 2.1839, original_language: "ja" },
