  29173: { id: 29173, title: "Raiders of Atlantis", release_date: "1983-11-25", poster_path: "/qNeaKk9Wy345IvoU1h67J2IdldS.jpg", backdrop_path: "/5FROgu8ovhUAJmxlssfs4c6GvCo.jpg", overview: "A team of scientists working to raise a sunken Russian nuclear submarine on an ocean platform off the coast of Miami, Florida, unearth an ancient Atlantean relic from the sea floor and bring in an expert to make some sense of it. But while attempting to raise the sub, radioactive leakage from its missles triggers the re-emergence of Atlantis, and the resulting tidal wave destroys the platform and leaves only a small group of survivors. Rescued by two Vietnamvets-turned-heavies who are out relaxing after their latest job, their boat eventually runs aground on a Carribean island nearby where, upon going ashore, it is discovered that everything has been destroyed and everybody killed. The culprits, a vicious group of well-armed raiders, and their leader, Crystal Skull, are descendants of Atlantis' original race who set about reclaiming the world and adding the survivors to the list of victims as they struggle to stay alive and defeat the raiders and send Atlantis back to the ocean floor.", vote_average: 4.952, vote_count: 61, genre_ids: [878, 28], runtime: 92, popularity: 0.9714, original_language: "it" },
