  9454: { id: 9454, title: "EverAfter", release_date: "1998-07-31", poster_path: "/9TspO5dThMBioF0DFrvy6YqrngH.jpg", backdrop_path: "/lhpokM60CnLWcNETQqKMz2q9ryL.jpg", overview: "Danielle, a vibrant young woman, was forced into servitude after the death of her father when she was a young girl. Danielle's stepmother, Rodmilla, is a heartless woman who forces Danielle to do the cooking and cleaning, while she tries to marry off the eldest of her two daughters to the prince. But Danielle's life takes a wonderful turn when, under the guise of a visiting royal, she meets the charming Prince Henry.", vote_average: 7.431, vote_count: 1554, genre_ids: [18, 10749, 35], runtime: 121, popularity: 4.3784, original_language: "en" },
  10215: { id: 10215, title: "Sliding Doors", release_date: "1998-04-23", poster_path: "/s8VOVTywXZIIHqdEjkCZziH0ebq.jpg", backdrop_path: "/1dApwEEMrk7QnUb1EpyYWrG6nRh.jpg", overview: "Helen, a London ad executive, is fired from her job and rushes out to catch a train, but, as she runs down, her life suddenly splits off. In one version she catches the train; in the second, she misses it. Her whole life changes in that one second, and the rest of the film depicts what happens in each scenario.", vote_average: 6.564, vote_count: 1408, genre_ids: [35, 18, 14, 10749], runtime: 99, popularity: 3.2797, original_language: "en" },
  11220: { id: 11220, title: "Fallen Angels", release_date: "1995-09-06", poster_path: "/yyM9BPdwttK5LKZSLvHae7QPKo1.jpg", backdrop_path: "/v4FepSc09TsRy2fQtUg6vvzrTq0.jpg", overview: "An assassin goes through obstacles as he attempts to escape his violent lifestyle despite the opposition of his partner, who is secretly attracted to him.", vote_average: 7.68, vote_count: 1286, genre_ids: [28, 10749, 80], runtime: 98, popularity: 7.329, original_language: "cn" },
  11971: { id: 11971, title: "Much Ado About Nothing", release_date: "1993-05-07", poster_path: "/tvltGP6vYOkHdURag0jPSjhPUAV.jpg", backdrop_path: "/vzCzttEsymFY8hSDYsAzgSrBYEN.jpg", overview: "In this Shakespearean farce, Hero and her groom-to-be, Claudio, team up with Claudio's commanding officer, Don Pedro, the week before their wedding to hatch a matchmaking scheme. Their targets are sharp-witted duo Benedick and Beatrice -- a tough task indeed, considering their corresponding distaste for love and each other. Meanwhile, meddling Don John plots to ruin the wedding.", vote_average: 6.946, vote_count: 803, genre_ids: [18, 35, 10749], runtime: 111, popularity: 3.6985, original_language: "en" },
  2064: { id: 2064, title: "While You Were Sleeping", release_date: "1995-04-21", poster_path: "/qNGO3ETcNwlWqK2kNRpbJSJRlos.jpg", backdrop_path: "/gCYvQJ1MhyK4kYFnjpNbNqQtaYc.jpg", overview: "A transit worker pulls commuter Peter off railway tracks after he's mugged, but—while he's in a coma—his family mistakenly thinks she's Peter's fiancée, and she doesn't correct them. Things get more complicated when she falls for his brother, who's not quite sure that she's who she claims to be.", vote_average: 7.022, vote_count: 1989, genre_ids: [10749, 35], runtime: 103, popularity: 4.4021, original_language: "en" },
  10207: { id: 10207, title: "Message in a Bottle", release_date: "1999-02-22", poster_path: "/ulUjszY6YJFsDUd0E3WolJg6sOp.jpg", backdrop_path: "/bHTAGzPTQ0aBm7gmfkSnqaHiajM.jpg", overview: "A woman finds a romantic letter in a bottle washed ashore and tracks down the author, a widowed shipbuilder whose wife died tragically early. As a deep and mutual attraction blossoms, the man struggles to make peace with his past so that he can move on and find happiness.", vote_average: 6.27, vote_count: 824, genre_ids: [10749, 18], runtime: 131, popularity: 3.7826, original_language: "en" },
