  13701: { id: 13701, title: "Immortal Beloved", release_date: "1994-12-16", poster_path: "/lkqz2R5pjXeDaiIjR3Z6JTGjtg6.jpg", backdrop_path: "/4wrdhfmmv9fQkmiPRl3d8NACjh9.jpg", overview: "A chronicle of the life of infamous classical composer Ludwig van Beethoven and his painful struggle with hearing loss. Following Beethoven's death in 1827, his assistant, Schindler, searches for an elusive woman referred to in the composer's love letters as \"immortal beloved.\" As Schindler solves the mystery, a series of flashbacks reveal Beethoven's transformation from passionate young man to troubled musical genius.", vote_average: 7.11, vote_count: 370, genre_ids: [18, 10402, 10749], runtime: 121, popularity: 2.3915, original_language: "en" },
  2767: { id: 2767, title: "The Lovers on the Bridge", release_date: "1991-10-16", poster_path: "/un81oln6mAv66sqnkgPSpWONUqP.jpg", backdrop_path: "/6vWdQxx4yqV5kEeAqtzBHndo3Eg.jpg", overview: "Set against Paris' oldest bridge, the Pont Neuf, while it was closed for repairs, this film is a love story between two young vagrants: Alex, a would be circus performer addicted to alcohol and sedatives and Michele, a painter driven to a life on the streets because of a failed relationship and an affliction which is slowly turning her blind.", vote_average: 7.395, vote_count: 377, genre_ids: [18, 10749], runtime: 126, popularity: 1.8655, original_language: "fr" },
  114: { id: 114, title: "Pretty Woman", release_date: "1990-03-23", poster_path: "/hVHUfT801LQATGd26VPzhorIYza.jpg", backdrop_path: "/sGEqHTylawwS6hwKultk1mKUjdB.jpg", overview: "Vivian is a carefree, streetwise diamond in the rough when she meets sophisticated billionaire Edward in a chance encounter that turns into a week-long business arrangement. But Vivian's energetic spirit challenges Edward's no-nonsense approach to life, and soon they are teaching each other – and falling in love!", vote_average: 7.447, vote_count: 8941, genre_ids: [10749, 35], runtime: 120, popularity: 10.5507, original_language: "en" },
  2105: { id: 2105, title: "American Pie", release_date: "1999-07-09", poster_path: "/5P68by2Thn8wHAziyWGEw2O7hco.jpg", backdrop_path: "/cvH1gNIMRITdLzoWv1HNAbRyH3n.jpg", overview: "At a high-school party, four friends find that losing their collective virginity isn't as easy as they had thought. But they still believe that they need to do so before college. To motivate themselves, they enter a pact to all \"score\" by their senior prom.", vote_average: 6.605, vote_count: 8251, genre_ids: [35, 10749], runtime: 95, popularity: 13.7035, original_language: "en" },
  782: { id: 782, title: "Gattaca", release_date: "1997-07-09", poster_path: "/eSKr5Fl1MEC7zpAXaLWBWSBjgJq.jpg", backdrop_path: "/hPsCR1ny6GnctJkWqeJwihTDD7T.jpg", overview: "Vincent is an all-too-human man who dares to defy a system obsessed with genetic perfection. He is an \"In-Valid\" who assumes the identity of a member of the genetic elite to pursue his goal of traveling into space with the Gattaca Aerospace Corporation.", vote_average: 7.564, vote_count: 6885, genre_ids: [53, 878, 9648, 10749], runtime: 107, popularity: 9.5988, original_language: "en" },
  9603: { id: 9603, title: "Clueless", release_date: "1995-07-19", poster_path: "/8AwVTcgpTnmeOs4TdTWqcFDXEsA.jpg", backdrop_path: "/65d0MccsiRSPTVicregKQL8owoo.jpg", overview: "Shallow, rich and socially successful Cher is at the top of her Beverly Hills high school's pecking scale. Seeing herself as a matchmaker, Cher first coaxes two teachers into dating each other. Emboldened by her success, she decides to give hopelessly klutzy new student Tai a makeover. When Tai becomes more popular than she is, Cher realizes that her disapproving ex-stepbrother was right about how misguided she was -- and falls for him.", vote_average: 7.25, vote_count: 4775, genre_ids: [35, 10749], runtime: 97, popularity: 8.2804, original_language: "en" },
  1587: { id: 1587, title: "What's Eating Gilbert Grape", release_date: "1993-12-17", poster_path: "/8FxWgsfDNosewo7H65oE4QkOb7g.jpg", backdrop_path: "/m05zMH2I7aEOP4zc0JYOdqR4JUD.jpg", overview: "Gilbert Grape is a small-town young man with a lot of responsibility. Chief among his concerns are his mother, who is so overweight that she can't leave the house, and his mentally impaired younger brother, Arnie, who has a knack for finding trouble. Settled into a job at a grocery store and an ongoing affair with local woman Betty Carver, Gilbert finally has his life shaken up by the free-spirited Becky.", vote_average: 7.663, vote_count: 4255, genre_ids: [10749, 18], runtime: 118, popularity: 5.9641, original_language: "en" },
  10603: { id: 10603, title: "George of the Jungle", release_date: "1997-07-15", poster_path: "/lWp8hUqE4oLPxsYgilXoYoVThfU.jpg", backdrop_path: "/zqkfvhbBf3IftOr1g7qjtwpFy6d.jpg", overview: "Deep in the African jungle, a baby named George, the sole survivor of a plane crash, is raised by gorillas. George grows up to be a buff and lovable klutz who has a rainforest full of animal friends: Tookie, his big-beaked toucan messenger; Ape, a witty talking gorilla; and Shep, a peanut-loving pooch of an elephant. But when poachers mess with George's pals, the King of Swing swings into action.", vote_average: 5.658, vote_count: 2237, genre_ids: [12, 35, 10751, 10749], runtime: 92, popularity: 6.3262, original_language: "en" },
