  16270: { id: 16270, title: "Career Opportunities", release_date: "1991-03-29", poster_path: "/x2sSRi8ZqOIjtk2fpGMTuMf4qJv.jpg", backdrop_path: "/y9UU2JNjoFPI7ZvCuiWzpN9GJHZ.jpg", overview: "Josie, the daughter of the town's wealthiest businessman, faces problems at home and wishes to leave town but is disoriented. Her decision is finalized after she falls asleep in a Target dressing room. She awakens to find herself locked in the store overnight with the janitor, Jim, the town \"no hoper\" and liar.", vote_average: 6.867, vote_count: 749, genre_ids: [10749, 35], runtime: 83, popularity: 4.9278, original_language: "en" },
  6552: { id: 6552, title: "Idle Hands", release_date: "1999-04-30", poster_path: "/mCO4gU1lkViGXTkoRBEYrvjDIJu.jpg", backdrop_path: "/vSX4JjjifAUnF4PD5J9czE4Fz0C.jpg", overview: "Anton is a cheerful but exceedingly non-ambitious 17-year-old stoner who lives to stay buzzed, watch TV, and moon over Molly, the beautiful girl who lives next door. However, it turns out that the old cliché about idle hands being the devil's playground has a kernel of truth after all.", vote_average: 6.188, vote_count: 735, genre_ids: [35, 27, 14, 10749], runtime: 92, popularity: 3.2381, original_language: "en" },
  267: { id: 267, title: "Live Flesh", release_date: "1997-10-10", poster_path: "/7YPGYeamF6AuyxhKqbd5oNKKCCy.jpg", backdrop_path: "/gDekB0OnIYbKhqzzdArfSQpcAvH.jpg", overview: "When Victor attempts to seduce Elena, all he gets for his trouble is a one-way, six-year ticket to prison, where he concentrates on strengthening his mind, his body... and his desire for vengeance on the man who put him there. After his release and still madly in love with her, Victor will stop at nothing to win her over even if means revenge, for Elena has married David, the cop who sent him to prison!", vote_average: 7.04, vote_count: 733, genre_ids: [18, 10749, 53], runtime: 103, popularity: 2.8196, original_language: "es" },
