  236: { id: 236, title: "Muriel's Wedding", release_date: "1994-09-29", poster_path: "/zJyTr8Fo412a2OIfJGXTRAm4IwX.jpg", backdrop_path: "/x4sqnmV2nAKIG6cmt9WAF9xRA2M.jpg", overview: "Socially awkward Muriel Heslop wants nothing more than to get married. Unfortunately, due to her oppressive politician father, Muriel has never even been on a date. Ostracized by her more socially adept friends, Muriel runs into fellow outcast Rhonda Epinstalk, and the two move from their small Australian town to the big city of Sydney, where Muriel changes her name and begins the arduous task of redesigning her life to match her fantasies.", vote_average: 6.838, vote_count: 487, genre_ids: [35, 18, 10749], runtime: 106, popularity: 2.9726, original_language: "en" },
