  14249: { id: 14249, title: "Revenge", release_date: "1990-02-16", poster_path: "/83diOZcg6ZiY8voNy2k4BX9TsMf.jpg", backdrop_path: "/jCJ4CVxg5Ic21FlpWIlz11mxNMh.jpg", overview: "Michael ‘Jay’ Cochran has just left the Navy after 12 years and he's not quite sure what he's going to do, except that he knows he wants a holiday. He decides to visit Tiburon Mendez, a powerful but shady Mexican businessman who he once flew to Alaska for a hunting trip. Arriving at the Mendez mansion in Mexico, he is immediately surprised by the beauty and youth of Mendez’s wife, Miryea.", vote_average: 6.5, vote_count: 475, genre_ids: [53, 10749, 18], runtime: 123, popularity: 5.0758, original_language: "en" },
  10442: { id: 10442, title: "So I Married an Axe Murderer", release_date: "1993-07-30", poster_path: "/zQlpQDKDADKlgqfMs1E191ofDJU.jpg", backdrop_path: "/iVweNwFhEtlJlPxOkaDh8VboE9b.jpg", overview: "Just after a bad breakup, Charlie MacKenzie falls for lovely butcher Harriet Michaels and introduces her to his parents. But, as voracious consumers of sensational tabloids, his parents soon come to suspect that Harriet is actually a notorious serial killer -- \"Mrs. X\" -- wanted in connection with a string of bizarre honeymoon killings. Thinking his parents foolish, Charlie proposes to Harriet. But while on his honeymoon with her, he begins to fear they were right.", vote_average: 6.114, vote_count: 473, genre_ids: [35, 80, 10749], runtime: 93, popularity: 2.0081, original_language: "en" },
