  2058: { id: 2058, title: "Addicted to Love", release_date: "1997-05-23", poster_path: "/sRfuSc6E9GvVaOHdPv4vG3ywfMw.jpg", backdrop_path: "/35b11n97MKmmkjJoJcx8tqHIVJ2.jpg", overview: "Good-natured astronomer Sam is devastated when the love of his life leaves him for a suave Frenchman. He therefore does what every other normal dumpee would do — go to New York and set up home in the abandoned building opposite his ex-girlfriend's apartment, wait until she decides to leave her current lover, and then win her back.", vote_average: 6.2, vote_count: 442, genre_ids: [35, 10749], runtime: 100, popularity: 1.964, original_language: "en" },
