  1049: { id: 1049, title: "Sommersby", release_date: "1993-02-05", poster_path: "/tAgQKLv0GK97Tr0bvdI66oXlEVb.jpg", backdrop_path: "/jWAK7ONCE1Kski7SsAJvcNBQMyv.jpg", overview: "Set in the South just after the US Civil War, Laurel Sommersby is just managing to work the farm without her husband, believed killed in battle. By all accounts, Jack Sommersby was not a pleasant man, thus when he suddenly returns, Laurel has mixed emotions. It appears that Jack has changed a great deal, leading some people to believe that this is not actually Jack but an imposter. Laurel herself is unsure, but willing to take the man into her home, and perhaps later into her heart.", vote_average: 6.346, vote_count: 422, genre_ids: [18, 53, 9648, 10749], runtime: 109, popularity: 3.6455, original_language: "en" },
