  10908: { id: 10908, title: "Inferno", release_date: "1999-09-25", poster_path: "/n5C3PSYfjpUqBhyVWEWJQmM3Sr9.jpg", backdrop_path: "/vRx6kzCItpqwnYCcj2z8qf70gv3.jpg", overview: "Eddie Lomax is a drifter who has been in a suicidal funk since the death of his close friend Johnny. Riding his motorcycle into a small desert town where Johnny once lived, Lomax is confronted by a gang of toughs, who beat him and steal his bike. However, Lomax is not a man to take an injustice lying down, and soon he begins exacting a violent revenge on the men who stole his motorcycle, with local handyman Jubal Early lending a hand and several area ladies offering aid and comfort.", vote_average: 6.141, vote_count: 351, genre_ids: [28, 18, 10749], runtime: 95, popularity: 4.4013, original_language: "en" },
