  8217: { id: 8217, title: "Alice", release_date: "1990-12-25", poster_path: "/g6PGzYqXNofrrGKS7dixoc2P5M7.jpg", backdrop_path: "/ofIyN1TZJFvoCePNpbJebsg54D4.jpg", overview: "Alice Tate, mother of two, with a marriage of 16 years, finds herself falling for a handsome sax player, Joe. Stricken with a backache, she consults herbalist Dr. Yang, who realizes that her problems are not related to her back, but in her mind and heart. Dr. Yang's magical herbs give Alice wondrous powers, taking her out of her well-established rut.", vote_average: 6.384, vote_count: 337, genre_ids: [14, 18, 10749, 35], runtime: 102, popularity: 2.174, original_language: "en" },
