  10170: { id: 10170, title: "The Russia House", release_date: "1990-12-21", poster_path: "/fFvwQGcpEdXkuPJaS15Xtl6h6P4.jpg", backdrop_path: "/120TJwjOG5ShzYQIW9E61l6SvUL.jpg", overview: "Barley Scott Blair, a Lisbon-based editor of Russian literature who unexpectedly begins working for British intelligence, is commissioned to investigate the purposes of Dante, a dissident scientist trapped in the decaying Soviet Union that is crumbling under the new open-minded policies.", vote_average: 6.061, vote_count: 327, genre_ids: [18, 53, 10749], runtime: 118, popularity: 2.7178, original_language: "en" },
  2020: { id: 2020, title: "The Bachelor", release_date: "1999-11-05", poster_path: "/zAF7cDx3SNqx6vjqgH2FLFM9pcm.jpg", backdrop_path: "/1tRrXYZ5pMJOW57SFTHetL6f5Ay.jpg", overview: "Jimmie is seeing his single friends get married one by one. He isn't too worried until his girlfriend Anne catches the bouquet at his friend Marco's wedding. Suddenly, his wild mustang days are numbered. He finally decides to propose to her, but he sticks his foot in his mouth and botches the proposal. Being insulted by the defeatist proposal, Anne leaves town on an assignment. After she's gone, he finds out that his recently-deceased grandfather's will stipulates that he gets nothing of a multi-million dollar fortune unless he's married by 6:05pm on his 30th birthday: tomorrow! Not being able to find Anne, Jimmie begins backtracking through his past girlfriends to find a wife.", vote_average: 5.15, vote_count: 326, genre_ids: [35, 10749], runtime: 101, popularity: 2.4931, original_language: "en" },
  4482: { id: 4482, title: "French Twist", release_date: "1995-01-18", poster_path: "/xlLnHizshGBwMiNrnop2kg2nYzE.jpg", backdrop_path: "/eAexMnPNZG0Q9QNHNWWfr9iHLMf.jpg", overview: "After learning of her husband's infidelities, a housewife invites an itinerant lesbian to move in with them. None of their lives will ever be the same again.", vote_average: 6.059, vote_count: 321, genre_ids: [35, 10749], runtime: 95, popularity: 1.9273, original_language: "fr" },
  12518: { id: 12518, title: "Honeymoon in Vegas", release_date: "1992-08-28", poster_path: "/qZPay0VF5Bq2PiUvC09WwM5blmj.jpg", backdrop_path: "/jkbZjRYcAQMrlFllsPFxYNfsGAE.jpg", overview: "On her deathbed, a mother makes her son promise never to get married, which scars him with psychological blocks to a commitment with his girlfriend. They finally decide to tie the knot in Vegas, but a wealthy gambler arranges for the man to lose $65K in a poker game and offers to clear the debt for a weekend with his fiancée.", vote_average: 5.653, vote_count: 318, genre_ids: [35, 10749], runtime: 96, popularity: 1.8764, original_language: "en" },
  10612: { id: 10612, title: "The Englishman Who Went Up a Hill But Came Down a Mountain", release_date: "1995-05-12", poster_path: "/s96XNz6eBsYDK3A9nVyEuHdv7BG.jpg", backdrop_path: "/wY1Rn2DnmDt7QKnGSH5be3JM7u7.jpg", overview: "When an English cartographer arrives in Wales to tell the residents of the Welsh village of Ffynnon Garw  that their 'mountain' is only a hill, the offended community sets out to remedy the situation.", vote_average: 6.322, vote_count: 315, genre_ids: [18, 35, 10749], runtime: 91, popularity: 2.067, original_language: "en" },
  10278: { id: 10278, title: "Return to Paradise", release_date: "1998-08-10", poster_path: "/t4lmZtx1zLUijwO2oHHEbUQ7j41.jpg", backdrop_path: "/oyozrAwuzpXIhxvsCA688SFcIEw.jpg", overview: "Lewis, Sheriff and Tony are three friends vacationing in Malaysia. Sheriff and Tony eventually leave to pursue careers in New York, but Lewis stays behind to work with orangutans. Two years later, Sheriff and Tony learn that, because of their past actions, Lewis has been arrested for drug possession. With Lewis facing a death sentence, the friends are left with a difficult decision: return to Malaysia and split Lewis' sentence, or let him die.", vote_average: 6.486, vote_count: 313, genre_ids: [18, 53, 10749], runtime: 109, popularity: 2.4802, original_language: "en" },
