  9066: { id: 9066, title: "The Brady Bunch Movie", release_date: "1995-02-16", poster_path: "/kbJfBJh5vEf5356Jlm6P37H48hD.jpg", backdrop_path: "/aKKJttuN9RD8yTU8NHL9UkdJwip.jpg", overview: "The original '70s TV family is now placed in the 1990s, where they're even more square and out of place than ever.", vote_average: 6.109, vote_count: 313, genre_ids: [10751, 35, 10749], runtime: 89, popularity: 2.4186, original_language: "en" },
  4823: { id: 4823, title: "Final Analysis", release_date: "1992-02-07", poster_path: "/xR6T30U2nyyjygNnElQJpedbpck.jpg", backdrop_path: "/1hMdzWs6s48ySNruPDW9gc33exw.jpg", overview: "A psychiatrist becomes romantically involved with the sister of one of his patients, but the influence of her controlling gangster husband threatens to destroy them both.", vote_average: 5.746, vote_count: 311, genre_ids: [18, 53, 10749], runtime: 124, popularity: 2.8001, original_language: "en" },
  25095: { id: 25095, title: "Wuthering Heights", release_date: "1992-10-16", poster_path: "/lV8zMPqaK8Qg39zKLzfvnYkiBiC.jpg", backdrop_path: "/60OypzgF62FE8PWxXi5zSI1bLyS.jpg", overview: "Young orphan Heathcliff is adopted by the wealthy Earnshaw family and moves into their estate, Wuthering Heights. Soon, the new resident falls for his compassionate foster sister, Cathy. The two share a remarkable bond that seems unbreakable until Cathy, feeling the pressure of social convention, suppresses her feelings and marries Edgar Linton, a man of means who befits her stature. Heathcliff vows to win her back.", vote_average: 6.641, vote_count: 309, genre_ids: [18, 10749], runtime: 105, popularity: 4.9458, original_language: "en" },
