  13203: { id: 13203, title: "Son in Law", release_date: "1993-07-02", poster_path: "/gj4afHL9bMQ18opZzMp77tlPkAq.jpg", backdrop_path: "/pV1Kdxjk05NfTUtfXB3ZZyD95s0.jpg", overview: "Country girl Rebecca has spent most of her life on a farm in South Dakota, and, when she goes away to college in Los Angeles, Rebecca immediately feels out of place in the daunting urban setting. She is befriended by a savvy party animal named Crawl, who convinces the ambivalent Rebecca to stay in the city. When Thanksgiving break rolls around, Rebecca, no longer an innocent farm girl, invites Crawl back to South Dakota, where he pretends to be her fiancé.", vote_average: 6.043, vote_count: 300, genre_ids: [35, 18, 10749], runtime: 95, popularity: 2.5952, original_language: "en" },
