  8291: { id: 8291, title: "Poetic Justice", release_date: "1993-07-23", poster_path: "/6jE7Vzh3edBQtbbDcF4AC5gMX2g.jpg", backdrop_path: "/lNvlerKoYwboltmK7hQfgxsYtNP.jpg", overview: "Still grieving after the murder of her boyfriend, hairdresser Justice writes poetry to deal with the pain of her loss. Unable to get to Oakland to attend a convention because of her broken-down car, Justice gets a lift with her friend, Iesha, and Iesha's postal worker boyfriend, Chicago. Along for the ride is Chicago's co-worker, Lucky, to whom Justice grows close after some initial problems. But is she ready to open her heart again?", vote_average: 6.756, vote_count: 275, genre_ids: [18, 10749], runtime: 109, popularity: 4.0334, original_language: "en" },
