  11363: { id: 11363, title: "She's the One", release_date: "1996-08-26", poster_path: "/wNd6qM8Qa8tLFOiUOiEivh0qBkH.jpg", backdrop_path: "/4zXhWqspo9EqAMxIkMWrENfIDQe.jpg", overview: "Mickey, a free-spirited New York cabbie, and Francis, a materialistic Wall Street stockbroker, are extremely competitive and confused about women as a result of their father's influence. They disagree on everything, but they have one thing in common: Mickey's ex-fiance Heather is Francis's secret love. Although both brothers are already married, Heather triggers their longtime sibling rivalry.", vote_average: 5.483, vote_count: 266, genre_ids: [10749, 35], runtime: 96, popularity: 1.932, original_language: "en" },
