  47002: { id: 47002, title: "Love Letter", release_date: "1995-03-25", poster_path: "/9iAgQSkt9z34DTYQfpG0M69SyiL.jpg", backdrop_path: "/j0H799tVVLesjskDbL5FKcV5Nfr.jpg", overview: "Hiroko attends the memorial service of her fiancé, Itsuki Fujii, who died in a mountain-climbing incident. Although Itsuki's mother says that their old house is gone, Hiroko records the address listed under his name in his yearbook and sends him a letter. Surprisingly, she receives a reply, and discovers it came from his old classmate, a girl who also happens to be called Itsuki Fujii.", vote_average: 7.819, vote_count: 259, genre_ids: [18, 10749], runtime: 117, popularity: 5.3953, original_language: "ja" },
  37563: { id: 37563, title: "A Summer's Tale", release_date: "1996-06-05", poster_path: "/l3syqgYqqfqPVheINI5jOBN5hXL.jpg", backdrop_path: "/h7jewTP4Q0fPAiufeFTGZF04P39.jpg", overview: "Awaiting his girlfriend Léna’s arrival at the Breton seaside resort of Dinard, Gaspard befriends — and flirts heavily with — two other women, the companionable ethnology student Margot and the sensual townie Solène, making for a rather complicated situation when Léna finally arrives.", vote_average: 7.361, vote_count: 259, genre_ids: [10749, 18, 35], runtime: 114, popularity: 1.4343, original_language: "fr" },
  1610: { id: 1610, title: "Fever Pitch", release_date: "1997-04-04", poster_path: "/xTpZGWVo5DDk1oQUrUJcRjqGzGg.jpg", backdrop_path: "/yAJkaaxujWGz39AGeP4e8aBSLEW.jpg", overview: "A romantic comedy about a man, a woman and a football team. Based on Nick Hornby's best selling autobiographical novel, Fever Pitch. English teacher Paul Ashworth believes his long standing obsession with Arsenal serves him well. But then he meets Sarah. Their relationship develops in tandem with Arsenal's roller coaster fortunes in the football league, both leading to a nail biting climax.", vote_average: 6.461, vote_count: 259, genre_ids: [35, 10749], runtime: 102, popularity: 1.7772, original_language: "en" },
  12723: { id: 12723, title: "Inventing the Abbotts", release_date: "1997-04-04", poster_path: "/ysfD96fF56BEzpktyDWChC8Epgs.jpg", backdrop_path: "/tL8c4Oz3fXqRP3oquUpHWqpEC6B.jpg", overview: "In the 1950s, brothers Jacey and Doug Holt, who come from the poorer side of their sleepy Midwestern town, vie for the affections of the wealthy, lovely Abbott sisters. Lady-killer Jacey alternates between Eleanor and Alice, wanting simply to break the hearts of rich young women. But sensitive Doug has a real romance with Pamela, which Jacey and the Abbott patriarch, Lloyd, both frown upon.", vote_average: 6.304, vote_count: 258, genre_ids: [18, 10749], runtime: 110, popularity: 3.0176, original_language: "en" },
  4307: { id: 4307, title: "The Flower of My Secret", release_date: "1995-09-22", poster_path: "/u172NHV9SvqgVDSyRayJIPK2Brl.jpg", backdrop_path: "/kbY2KsmwyFiRYtO0f9Xwd3cV9tZ.jpg", overview: "Middle-aged romance author Leo writes under a pseudonym, since she despises her own work. At home, her husband, who works overseas, is distant both physically and emotionally. As she reevaluates her life and writing, Leo is led to an unexpected relationship with Ángel, a sensitive newspaper editor.", vote_average: 6.785, vote_count: 256, genre_ids: [18, 10749], runtime: 106, popularity: 1.3213, original_language: "es" },
