  10371: { id: 10371, title: "For Richer or Poorer", release_date: "1997-12-11", poster_path: "/tPjqY9Qp5WOIBFKnyEpMBVwGr01.jpg", backdrop_path: "/19pPgJa9c3zxDGIcyoTH0IvWU2n.jpg", overview: "Brad Sexton and his wife, Caroline, are wealthy New Yorkers with both marital and financial problems. The latter issue becomes a pressing matter when they discover that their accountant has embezzled millions and pinned the blame on them. Forced to go on the lam, Brad and Caroline end up in an Amish area of Pennsylvania and decide to pose as members of the religious group to evade the IRS. As the two adapt to the simple Amish lifestyle, they begin to reconnect.", vote_average: 6.006, vote_count: 254, genre_ids: [35, 10749], runtime: 115, popularity: 2.3734, original_language: "en" },
  36758: { id: 36758, title: "The Portrait of a Lady", release_date: "1996-10-17", poster_path: "/yoUuMtWTQXzfARYE0nF7Nn7gRuS.jpg", backdrop_path: "/8Dc6WVeJjJcl9muNJmuuoOgkiB7.jpg", overview: "Ms. Isabel Archer isn't afraid to challenge societal norms. Impressed by her free spirit, her kindhearted cousin writes her into his fatally ill father's will. Suddenly rich and independent, Isabelle ventures into the world, along the way befriending a cynical intellectual and romancing an art enthusiast. However, the advantage of her affluence is called into question when she realizes the extent to which her money colors her relationships.", vote_average: 5.982, vote_count: 253, genre_ids: [18, 10749], runtime: 144, popularity: 2.2223, original_language: "en" },
