  10635: { id: 10635, title: "Threesome", release_date: "1994-04-08", poster_path: "/vR6qwjChOV4Z9940VA9chucNpne.jpg", backdrop_path: "/xs7v0o0p4VWQ7BMa1XWYZ3coAor.jpg", overview: "At a sizable public college, high-minded student Eddy is forced to room with the slovenly Stuart, but the pair strike up a surprising friendship. When attractive co-ed Alex is assigned to live with the two male students because of her gender-neutral name, a roundabout love triangle ensues. Eddy secretly yearns for Stuart, who wants Alex, but she prefers Eddy. The complex situation leads to sexual experimentation and strained relationships.", vote_average: 6.388, vote_count: 240, genre_ids: [35, 18, 10749], runtime: 93, popularity: 2.5362, original_language: "en" },
  1413: { id: 1413, title: "M. Butterfly", release_date: "1993-10-01", poster_path: "/vfutnJ9sgpAtNuPemksd26gd5dC.jpg", backdrop_path: "/pxZG68WgGqijh1TjxLEJqTRt5jw.jpg", overview: "In 1960s China, French diplomat Rene Gallimard falls in love with an opera singer, Song Liling – but Song is not at all who Gallimard thinks.", vote_average: 6.585, vote_count: 240, genre_ids: [10749, 18, 36], runtime: 101, popularity: 1.7638, original_language: "en" },
  9302: { id: 9302, title: "Up Close & Personal", release_date: "1996-03-01", poster_path: "/zF67qcf7skMHLpXnifodinUqCFr.jpg", backdrop_path: "/wqD5zMFFITtzySK7fuYX42AtbJE.jpg", overview: "Tally Atwater has a dream: to be a prime-time network newscaster. She pursues this dream with nothing but ambition, raw talent and a homemade demo tape. Warren Justice is a brilliant, hard edged, veteran newsman. He sees Tally has talent and becomes her mentor. Tally’s career takes a meteoric rise and she and Warren fall in love. The romance that results is as intense and revealing as television news itself. Yet, each breaking story, every videotaped crisis that brings them together, also threatens to drive them apart...", vote_average: 6.278, vote_count: 237, genre_ids: [18, 10749], runtime: 119, popularity: 2.089, original_language: "en" },
  28387: { id: 28387, title: "Kicking and Screaming", release_date: "1995-10-06", poster_path: "/ynAtSpTou7snNOq32djzILw9VCA.jpg", backdrop_path: "/hyG7Y6r0aQnE5ssoTyq8xSQmS25.jpg", overview: "After college graduation, Grover's girlfriend Jane tells him she's moving to Prague to study writing. Grover declines to accompany her, deciding instead to move in with several friends, all of whom can't quite work up the inertia to escape their university's pull. Nobody wants to make any big decisions that would radically alter his life, yet none of them wants to end up like Chet, the professional student who tends bar and is in his tenth year of university studies.", vote_average: 6.186, vote_count: 236, genre_ids: [35, 18, 10749], runtime: 96, popularity: 1.7904, original_language: "en" },
  12772: { id: 12772, title: "Leap of Faith", release_date: "1992-12-18", poster_path: "/iqIKuwQYdvoKKGFjjEPdXlUKYvk.jpg", backdrop_path: "/dn0FKCIJB0J5TI0yvE62uGOd75z.jpg", overview: "Jonas Nightengale is a fraudulent Christian faith healer who makes a living travelling around America holding revival meetings and conducting 'miracles' with the help of his friend and manager, Jane, and their entourage.", vote_average: 5.828, vote_count: 229, genre_ids: [35, 18, 10749], runtime: 108, popularity: 2.2754, original_language: "en" },
  41659: { id: 41659, title: "My Life", release_date: "1993-11-12", poster_path: "/eF8wNMMqY3kukUTTAVXLLx94UhB.jpg", backdrop_path: "/5ccAivPcFEJazxwZZnr5QOGNcz6.jpg", overview: "It seems that Bob Jones has everything a man could want, namely a fulfilling job and a beautiful, pregnant wife, Gail. But Bob's life is turned upside-down when he is diagnosed with cancer and given four months to live -- not even enough time to see his first child's birth. To cleanse himself of demons in his remaining days, Bob makes a video diary, hoping to pass along some wisdom to his future child. Along the way, he discovers a lot about himself.", vote_average: 6.689, vote_count: 228, genre_ids: [18, 10749], runtime: 114, popularity: 2.1914, original_language: "en" },
  17993: { id: 17993, title: "Henry & June", release_date: "1990-09-28", poster_path: "/cDMQLwT5LpdbA4dc4Twn43sbGRw.jpg", backdrop_path: "/6jF3HdLkHsEJtw8qKoEyZ9oJ7qB.jpg", overview: "While traveling in Paris, author Henry Miller and his wife, June, meet Anais Nin, and sexual sparks fly as Nin starts an affair with the openly bisexual June. When June is forced to return to the U.S., she gives Nin her blessing to sleep with her husband. Then, when June returns to France, an unexpected, and sometimes contentious, threesome forms.", vote_average: 6.067, vote_count: 228, genre_ids: [10749], runtime: 136, popularity: 2.9826, original_language: "en" },
  11796: { id: 11796, title: "The Hairdresser's Husband", release_date: "1990-10-03", poster_path: "/d0CCZOP1VILxL33O6OiVzUYVNPT.jpg", backdrop_path: "/bkyugLf910U8TahWO9ChTunSMfU.jpg", overview: "Antoine has always been fascinated by a hairdresser's delicate touch, the beguiling perfume, and the enticing figure of a woman with an opulent bosom. After all, he had always known he would marry one, completing his idealized love fantasy.", vote_average: 6.804, vote_count: 227, genre_ids: [35, 18, 10749], runtime: 82, popularity: 1.6873, original_language: "fr" },
  10879: { id: 10879, title: "I Love Trouble", release_date: "1994-06-29", poster_path: "/2uyytK3XFRPFXoTchFDtsWiSujn.jpg", backdrop_path: "/lnO0pcgCyzirR2QRt1XNPBTgjNB.jpg", overview: "Rival Chicago reporters Sabrina Peterson and Peter Brackett join forces to uncover a train wreck conspiracy.", vote_average: 5.489, vote_count: 225, genre_ids: [10749, 35], runtime: 123, popularity: 1.376, original_language: "en" },
  10401: { id: 10401, title: "The Girl on the Bridge", release_date: "1999-03-31", poster_path: "/t5hKllCsmpWWA7XpxBXPjx0Gfct.jpg", backdrop_path: "/jlxwZ7XHK17U4sZUxmDP8iHThC8.jpg", overview: "It's night on a Paris bridge. A girl leans over Seine River with tears in her eyes and a violent yearning to drown her sorrows. Out of nowhere someone takes an interest in her. He is Gabor, a knife thrower who needs a human target for his show. The girl, Adele, has never been lucky and nowhere else to go. So she follows him. They travel along the northern bank of the Mediterranean to perform.", vote_average: 7.031, vote_count: 225, genre_ids: [18, 35, 10749], runtime: 90, popularity: 1.0502, original_language: "fr" },
