  31962: { id: 31962, title: "Shining Through", release_date: "1992-01-31", poster_path: "/wAnvljbemUQluLjCcjgTZs0PXW1.jpg", backdrop_path: "/8rdRjdlQMYNdwDX38VkTH4BXorI.jpg", overview: "Spirited New Yorker Linda Voss goes to work for international lawyer and secret Office of Strategic Services operative Ed Leland just before World War II. As they fall in love, the United States enters the fight against Hitler, and Linda volunteers to work for Ed spying undercover behind Nazi lines. Assigned to uncover information about a German bomb, Linda also has personal motives to fulfill: discovering the fate of her Jewish family members in Berlin.", vote_average: 6.496, vote_count: 223, genre_ids: [18, 10749, 53, 10752], runtime: 132, popularity: 2.2548, original_language: "en" },
  48150: { id: 48150, title: "A Heart in Winter", release_date: "1992-09-02", poster_path: "/hR1NHf5tOAKbTO3KuJc6LliBGa3.jpg", backdrop_path: "/rWkuu1S6oAE6OPA1KtwdXP61NFL.jpg", overview: "Beautiful violin virtuoso Camille has two obsessions: the music of Ravel, and a friend of her husband's who crafts violins. But his heart seems to be as cold as her playing is passionate.", vote_average: 7.245, vote_count: 222, genre_ids: [18, 10749], runtime: 105, popularity: 1.8257, original_language: "fr" },
