  22804: { id: 22804, title: "Saw VI", release_date: "2009-10-22", poster_path: "/9JtluosCbioSXJSABZByaODyPpa.jpg", backdrop_path: "/gqR59DjJGr6i8mxRD1VfOzCueTI.jpg", overview: "Special Agent Strahm is dead, and Detective Hoffman has emerged as the unchallenged successor to Jigsaw's legacy. However, when the FBI draws closer to Hoffman, he is forced to set a game into motion, and Jigsaw's grand scheme is finally understood.", vote_average: 6.291, vote_count: 3485, genre_ids: [27, 53], runtime: 90, popularity: 4.4696, original_language: "en" },
