  17609: { id: 17609, title: "Antichrist", release_date: "2009-05-20", poster_path: "/ge7zbYvpfsDP3luKi0iSpzOgncM.jpg", backdrop_path: "/utABPVjXBlM8NUOBecCyLLuzQSe.jpg", overview: "A grieving couple retreats to their cabin 'Eden' in the woods, hoping to repair their broken hearts and troubled marriage. But nature takes its course and things go from bad to worse.", vote_average: 6.628, vote_count: 2821, genre_ids: [18, 27, 53], runtime: 104, popularity: 5.6733, original_language: "en" },
  9645: { id: 9645, title: "Ghost Ship", release_date: "2002-10-25", poster_path: "/kIlzZJqV4SCGHrrjoGLBhmsO7z2.jpg", backdrop_path: "/r4yVwsLF2pJr4C50pWizn9fYNbF.jpg", overview: "After discovering a passenger ship missing since 1962 floating adrift on the Bering Sea, salvagers claim the vessel as their own. Once they begin towing the ghost ship towards harbor, a series of bizarre occurrences happen and the group becomes trapped inside the ship, which they soon learn is inhabited by a demonic creature.", vote_average: 6, vote_count: 2640, genre_ids: [27, 9648, 53], runtime: 91, popularity: 6.1081, original_language: "en" },
  4970: { id: 4970, title: "Gothika", release_date: "2003-11-21", poster_path: "/frSGNQcWx1ek8dCduFYCux1ho7n.jpg", backdrop_path: "/eLBHPVQkJZyaSEUAGAFWNJJwmeo.jpg", overview: "After a car crash, criminal psychologist Dr. Miranda Grey regains consciousness only to find that she's a patient in the same mental institution that currently employs her. She's been accused of murdering her husband Dr. Douglas Grey — but she has no memory of committing the crime. As she tries to regain her memory and convince her co-worker, Dr. Pete Graham, of her innocence, a vengeful spirit uses her as an earthly pawn, which further convinces everyone of her guilt.", vote_average: 6.1, vote_count: 2476, genre_ids: [27, 53, 9648], runtime: 98, popularity: 3.7832, original_language: "en" },
  14001: { id: 14001, title: "Dead Silence", release_date: "2007-03-16", poster_path: "/rvcUVdATIHKZt7BSSttUkKbeBXN.jpg", backdrop_path: "/xMjAkXpCb55FTAV7By31p3TQMxb.jpg", overview: "Jamie returns to his hometown in search of answers to his wife's murder, which occurred after receiving a weird package containing a ventriloquist dummy named Billy, which may be linked to the legend of ventriloquist Mary Shaw. Destined to find out the truth, Jamie goes to the town of Raven's Fair, where Shaw used to perform and is buried. But Jamie is in for more than he expected.", vote_average: 6.448, vote_count: 2434, genre_ids: [27], runtime: 89, popularity: 7.1123, original_language: "en" },
  8814: { id: 8814, title: "Doom", release_date: "2005-10-20", poster_path: "/y50lH061yWOvEstoZRn7lYs0huk.jpg", backdrop_path: "/9EpgaLS44zlXoTSAOhGiJmkIA4B.jpg", overview: "A team of space marines known as the Rapid Response Tactical Squad, led by Sarge, is sent to a science facility on Mars after somebody reports a security breach. There, they learn that the alert came after a test subject, a mass murderer purposefully injected with alien DNA, broke free and began killing people. Dr. Grimm, who is related to team member Reaper, informs them all that the chromosome can mutate humans into monsters -- and is highly infectious.", vote_average: 5.189, vote_count: 2418, genre_ids: [28, 27, 878], runtime: 105, popularity: 5.2002, original_language: "en" },
  1248: { id: 1248, title: "Hannibal Rising", release_date: "2007-02-06", poster_path: "/7FTDMQoac0uqJUquZk4KenDzLMZ.jpg", backdrop_path: "/am6ZfhUTUmcjPjjA4GIkLEJ33TN.jpg", overview: "The story of the early, murderous roots of the cannibalistic killer, Hannibal Lecter – from his hard-scrabble Lithuanian childhood, where he witnesses the repulsive lengths to which hungry soldiers will go to satiate themselves, through his sojourn in France, where as a medical student he hones his appetite for the kill.", vote_average: 6.265, vote_count: 2394, genre_ids: [80, 53, 27], runtime: 121, popularity: 1.0832, original_language: "en" },
  28355: { id: 28355, title: "Case 39", release_date: "2009-08-13", poster_path: "/b16EjFeHd2AwoYXWUne7DA346pU.jpg", backdrop_path: "/1i1Jfc9e15uRM3fGp7Detsjsapw.jpg", overview: "In her many years as a social worker, Emily Jenkins believes she has seen it all, until she meets 10-year-old Lilith and the girl's cruel parents. Emily's worst fears are confirmed when the parents try to harm the child, and so Emily assumes custody of Lilith while she looks for a foster family. However, Emily soon finds that dark forces surround the seemingly innocent girl, and the more she tries to protect Lilith, the more horrors she encounters.", vote_average: 6.32, vote_count: 2371, genre_ids: [27, 9648, 53], runtime: 109, popularity: 3.6369, original_language: "en" },
