  11470: { id: 11470, title: "Jason X", release_date: "2001-11-09", poster_path: "/ggOND0hfoE0f3K857joSzEeIchb.jpg", backdrop_path: "/fR5Hkf4OH6aLExl2qP2ucMV2Xdt.jpg", overview: "In the year 2455, Old Earth is now a contaminated planet abandoned for centuries -- a brown world of violent storms, toxic landmasses and poisonous seas. Yet humans have returned to the deadly place that they once fled, not to live, but to research the ancient, rusting artifacts of the long-gone civilizations. But it's not the harmful environment that could prove fatal to the intrepid, young explorers who have just landed on Old Earth. For them, it's Friday the 13th, and Jason lives!", vote_average: 4.9, vote_count: 1499, genre_ids: [27, 878], runtime: 91, popularity: 4.2435, original_language: "en" },
  25769: { id: 25769, title: "Carriers", release_date: "2009-09-04", poster_path: "/jxjnjHtHXgvjdhkwpelE9ZwVMg6.jpg", backdrop_path: "/uYxAGovHS4mCGsIeSZCTtwOQ5Po.jpg", overview: "A deadly virus has spread across the globe. Contagion is everywhere, no one is safe, and no one can be trusted. Four friends race through the back roads of the American West on their way to a secluded utopian beach in the Gulf of Mexico where they could peacefully wait out the pandemic. Their plans take a grim turn when their car breaks down on an isolated road starting a chain of events that will seal their fates.", vote_average: 6.053, vote_count: 1488, genre_ids: [28, 18, 27, 878, 53], runtime: 84, popularity: 3.8588, original_language: "en" },
