  357435: { id: 357435, title: "Lucky Day", release_date: "1991-03-10", poster_path: "/zTzuutfgCOAIhwZGc2t1HqRJYyt.jpg", backdrop_path: "/4NIeD6gIFy5jCDT8lNCgder86Ig.jpg", overview: "When 30-year-old Allison Campbell wins a $2 million lottery, her family life turns upside down not just because of her winnings but because Allison is mentally handicapped. Kari, her younger sister, has been caring for Alison for 10 years. Problems arise when the girls' mother, Katherine, decides she wants Allison to live with her.", vote_average: 7.667, vote_count: 3, genre_ids: [18, 10770], runtime: 94, popularity: 0.6952, original_language: "en" },
