  612392: { id: 612392, title: "My Favorite Shapes by Julio Torres", release_date: "2019-08-10", poster_path: "/v1Bx5clsiLnAmHPOqRIMOnFmKrY.jpg", backdrop_path: "/dqXW5kXQeok9AOaAu6WzBW1DkB5.jpg", overview: "In this multimedia comedy show, Torres explores his favorite shapes, which include a plexiglass square, a triangle, an oval that wishes he were a circle, a self-conscious cactus and a Ferrero Rocher chocolate that Julio is mad at because she left her little skirt at home. The objects are presented via an industrial conveyer belt and serve as a jumping-off point for fantastical stories, anecdotes and jokes.", vote_average: 7.1, vote_count: 19, genre_ids: [35, 10770], runtime: 57, popularity: 0.7975, original_language: "en" },
  567104: { id: 567104, title: "Let's Dance", release_date: "2018-12-06", poster_path: "/2LlpkPEgW07GfekHxKQsHIJhZdq.jpg", backdrop_path: null, overview: "Justin Peck, the New York City Ballet's resident choreographer,  created a series of dances for 2018's best actors. The scenarios put everyday characters in familiar situations: packed into a subway car, stuck in a doctor's office, caught in downpour. But once they start moving, the actors turn our common experiences into welcome moments of enchantment.", vote_average: 6.1, vote_count: 9, genre_ids: [10402, 18], runtime: 12, popularity: 1.2673, original_language: "xx" },
