  82507: { id: 82507, title: "Sinister", release_date: "2012-03-29", poster_path: "/nzx10sca3arCeYBAomHan4Q6wa1.jpg", backdrop_path: "/jovIEk4cAxWmA2dBcPrfhn3jzYN.jpg", overview: "True-crime writer Ellison Oswalt is in a slump; he hasn't had a best seller in more than 10 years and is becoming increasingly desperate for a hit. So, when he discovers the existence of a snuff film showing the deaths of a family, he vows to solve the mystery. He moves his own family into the victims' home and gets to work. However, when old film footage and other clues hint at the presence of a supernatural force, Ellison learns that living in the house may be fatal.", vote_average: 6.874, vote_count: 5999, genre_ids: [27, 53, 9648], runtime: 110, popularity: 7.5021, original_language: "en" },
