  1004519: { id: 1004519, title: "The Complete Walk: Romeo and Juliet", release_date: "2016-10-03", poster_path: "/fde3r78cejP8dP56bftzGTZRVF1.jpg", backdrop_path: "/pRP3PsLWuvh0w9aO42X6WfTEAdx.jpg", overview: "To commemorate the 400th anniversary of the Bard's death, Shakespeare's Globe has assembled an all-star cast to make 37 short films – one for each play – and here's the twist: each lavish 10 minute vignette is made on location in the real setting of each plot. The films have been directed by a selection of young directors and blend existing Shakespeare's Globe footage with new material shot in locations that capture the breadth of the Bard's imagination, including the Pyramids of Dahshur in Egypt, the rocks of Elsinore, Denmark, and the historic Jewish Ghetto of Venice, Italy. “Romeo and Juliet”, which starred Jessie Buckley as Juliet, was filmed at Juliet's Tomb, Verona.", vote_average: 5.7, vote_count: 3, genre_ids: [18], runtime: 3, popularity: 0.5158, original_language: "en" },
  674494: { id: 674494, title: "A Battle in Waterloo", release_date: "2019-08-12", poster_path: "/xZr6tL6hw19XiQddZc804X39m8B.jpg", backdrop_path: "/rwW9GDUVl68HNb2V30wuvdseG3Y.jpg", overview: "During the Battle of Waterloo, a soldier's wife searches for her missing husband in the nearby forest and must resort to extraordinary measures to survive.", vote_average: 6, vote_count: 3, genre_ids: [18, 10752, 36], runtime: 12, popularity: 0.6369, original_language: "en" },
  1517065: { id: 1517065, title: "How to Shoot a Ghost", release_date: "2025-09-01", poster_path: "/snUGvh5T2n6XfCTfw2Sqfj7kK8h.jpg", backdrop_path: "/fY4b2egpnVeopFh41wV6xoMLceg.jpg", overview: "Two newly dead young people meet in the streets of Athens, amid the pulsing cityscape and the ghosts of history. One a translator, the other a photographer, they were outsiders in life; in death they struggle with the residue of their longings and mistakes. They wander the city together, finding consolation in the difficult beauty of existence and its aftermath.", vote_average: 6, vote_count: 1, genre_ids: [14], runtime: 27, popularity: 0.3942, original_language: "en" },
