  8676: { id: 8676, title: "Fool's Gold", release_date: "2008-02-07", poster_path: "/f4djEBW3nyGRPLTcDlWYyaO43mx.jpg", backdrop_path: "/6vsZR4066s6ZbaAAqDdzDbC4kgH.jpg", overview: "Treasure hunter Ben \"Finn\" Finnegan has sunk his marriage to Tess and his trusty boat in his obsessive quest to find the legendary Queen's Dowry. When he finds a vital clue that may finally pinpoint the treasure's whereabouts, he drags Tess and her boss, billionaire Nigel Honeycutt, along on the hunt. But Finn is not the only one interested in the gold; his former mentor-turned-enemy Moe Fitch, hired by rapper-turned-gangster Bigg Bunny, will stop at nothing to beat him to it.", vote_average: 5.8, vote_count: 1575, genre_ids: [12, 10749, 35], runtime: 112, popularity: 4.5385, original_language: "en" },
  1819: { id: 1819, title: "You, Me and Dupree", release_date: "2006-07-13", poster_path: "/rtqbg1CKR4dFdmHxmsiM3u9n71I.jpg", backdrop_path: "/muMAXHW2RknY5kA9VCmFhVHLkYh.jpg", overview: "After standing in as best man for his longtime friend Carl Petersen, Randy Dupree loses his job, becomes a barfly and attaches himself to the newlywed couple almost permanently -- as their houseguest. But the longer Dupree camps out on their couch, the closer he gets to Carl's bride, Molly, leaving the frustrated groom wondering when his pal will be moving out.", vote_average: 5.617, vote_count: 1427, genre_ids: [35, 10749], runtime: 108, popularity: 2.3214, original_language: "en" },
  353069: { id: 353069, title: "Mother's Day", release_date: "2016-04-28", poster_path: "/1TGkhTsbkm2v1nMGJW0eTOFBjAd.jpg", backdrop_path: "/3wRjFLgFbMcA05oIRD3jL58pBCm.jpg", overview: "Sandy is a stressed-out, single mom who learns that her ex-husband is marrying a younger woman. Her friend Jesse's parents don't know that she has a family or that  her sister, Gabi is married to a woman. Jesse's friend, Kristin, is juggling motherhood of a toddler, a patient boyfriend who keeps proposing, and searching for her biological mother. Bradley is a widower who's trying to raise two daughters on his own, while Miranda is too busy with her career to worry about children. When their respective problems intersect and start coming to a head, the Mother's Day holiday takes on a special meaning for all.", vote_average: 5.984, vote_count: 1313, genre_ids: [35, 18, 10749], runtime: 118, popularity: 4.0079, original_language: "en" },
  49022: { id: 49022, title: "Something Borrowed", release_date: "2011-05-05", poster_path: "/66VZu75VeLGc6tcAypqyGzWcPeN.jpg", backdrop_path: "/pKh2qMYoC5vXaRiU0qBK3IPXk76.jpg", overview: "Though Rachel is a successful attorney and a loyal, generous friend, she is still single. After one drink too many at her 30th-birthday celebration, Rachel unexpectedly falls into bed with her longtime crush, Dex -- who happens to be engaged to her best friend, Darcy. Ramifications of the liaison threaten to destroy the women's lifelong friendship, while Ethan, Rachel's confidant, harbors a potentially explosive secret of his own.", vote_average: 6.236, vote_count: 1088, genre_ids: [35, 18, 10749], runtime: 112, popularity: 3.1638, original_language: "en" },
