  1022848: { id: 1022848, title: "The Jon Brion Show", release_date: "1999-01-01", poster_path: null, backdrop_path: null, overview: "The concept of the show is that Brion will play accompaniment to his guest, sometimes inviting other performers on stage to assist. Like the regular Friday night shows that Brion performed at the club Largo in Los Angeles at the time, the performance is largely improvised. Those Largo performances, displaying the depth of Brion’s pop knowledge and musicianship, were huge successes. And in this instance, with Smith, the result is one amazing musical moment after another.", vote_average: 0, vote_count: 0, genre_ids: [10402], runtime: 43, popularity: 0.5205, original_language: "en" },
