  466272: { id: 466272, title: "Once Upon a Time... in Hollywood", release_date: "2019-07-24", poster_path: "/8j58iEBw9pOXFD2L0nt0ZXeHviB.jpg", backdrop_path: "/kKTPv9LKKs5L3oO1y5FNObxAPWI.jpg", overview: "Los Angeles, 1969. TV star Rick Dalton, a struggling actor specializing in westerns, and stuntman Cliff Booth, his best friend, try to survive in a constantly changing movie industry. Dalton is the neighbor of the young and promising actress and model Sharon Tate, who has just married the prestigious Polish director Roman Polanski…", vote_average: 7.421, vote_count: 14760, genre_ids: [35, 18, 53], runtime: 162, popularity: 13.6852, original_language: "en" },
