  284582: { id: 284582, title: "Madonna: The Immaculate Collection", release_date: "1990-11-13", poster_path: "/amb5JRLn3hfAK4kRTFe1vK87LXI.jpg", backdrop_path: "/f2Clh7KOcO4PKQV5cZSCP29N3SN.jpg", overview: "The Immaculate Collection is the first commercially released greatest videos compilation by singer Madonna. Released on November 13, 1990 to accompany the audio CD, it contained hits spanning 1983-1990. The collection won \"Best Long Form Video\" category at the 1991 MTV Video Music Awards. Includes the following videos: 1. Lucky Star 2. Borderline 3. Like a Virgin 4. Material Girl 5. Papa Don't Preach 6. Open Your Heart 7. La Isla Bonita 8. Like a Prayer 9. Express Yourself 10. Cherish 11. Oh Father 12. Vogue 13. Vogue (1990 MTV Awards Show Performance)", vote_average: 8.667, vote_count: 63, genre_ids: [10402], runtime: 60, popularity: 1.1183, original_language: "en" },
  41682: { id: 41682, title: "Christopher Columbus: The Discovery", release_date: "1992-08-20", poster_path: "/2VUr81cOU0jsZtzBs2EoVHcDJDW.jpg", backdrop_path: "/9qlCxh3I50mfLc3oWoFr3I8pKH8.jpg", overview: "Genoan navigator Christopher Columbus has a dream to find an alternative route to sail to the Indies, by traveling west instead of east, across the unchartered Ocean sea. After failing to find backing from the Portugese, he goes to the Spanish court to ask Queen Isabella and King Ferdinand for help. After surviving a grilling from the Head of the Spanish Inquisition Tomas de Torquemada, he eventually gets the blessing from Queen Isabella and sets sail in three ships to travel into the unknown. Along the way he must deal with sabotage from Portugese spies and mutiny from a rebellious crew.", vote_average: 4.81, vote_count: 58, genre_ids: [36, 12], runtime: 120, popularity: 1.2842, original_language: "en" },
