  744539: { id: 744539, title: "Fast Times at Ridgemont High: A Virtual Table Read", release_date: "2020-09-17", poster_path: "/92QLyEbstJeGyDDz67c80NO9uWa.jpg", backdrop_path: null, overview: "A virtual table read of the classic 1982 hit Fast Times at Ridgemont High. The all-star cast includes Jennifer Aniston, Dane Cook, Morgan Freeman, Jimmy Kimmel, Shia LaBeouf, John Legend, Ray Liotta, CORE co-founder Sean Penn, Brad Pitt and Julia Roberts.  This virtual special featured a series of memorable moments, including LaBeouf's hilariously accurate portrayal of Jeff Spicoli enjoyed by Penn himself, Morgan Freeman's dramatic narration, Julia Roberts (Stacy Hamilton) and Aniston's (Linda Barrett) adorable friendship, and a comical reenactment between Aniston (Linda) and Pitt (Brad Hamilton) as their characters shared a flirtatious scene in a daydream sequence.  This event benefited CORE’s COVID-19 relief efforts to protect vulnerable communities as well as our friends at Reform Alliance.", vote_average: 5.4, vote_count: 16, genre_ids: [35], runtime: 60, popularity: 1.3022, original_language: "en" },
