  1883: { id: 1883, title: "Malcolm X", release_date: "1992-11-18", poster_path: "/o2s9ow0uRRm1BcF3teznk5twd90.jpg", backdrop_path: "/kPdAZIqPgegqbv4QF1FshbVXNrx.jpg", overview: "A tribute to the controversial black activist and leader of the struggle for black liberation. He hit bottom during his imprisonment in the '50s, he became a Black Muslim and then a leader in the Nation of Islam. His assassination in 1965 left a legacy of self-determination and racial pride.", vote_average: 7.551, vote_count: 1884, genre_ids: [18, 36], runtime: 202, popularity: 4.7631, original_language: "en" },
