  9208: { id: 9208, title: "Broken Arrow", release_date: "1996-02-09", poster_path: "/iBPMwYYJFvdCBkXrwV75peo5Lz2.jpg", backdrop_path: "/446lXnrT0vSIkeClW8bCN8KrnxN.jpg", overview: "When rogue stealth-fighter pilot Vic Deakins deliberately drops off the radar while on maneuvers, the Air Force ends up with two stolen nuclear warheads -- and Deakins's co-pilot, Riley Hale, is the military's only hope for getting them back. Traversing the deserted canyons of Utah, Hale teams with park ranger Terry Carmichael to put Deakins back in his box.", vote_average: 6.064, vote_count: 1654, genre_ids: [28, 53], runtime: 108, popularity: 5.9402, original_language: "en" },
  7364: { id: 7364, title: "Sahara", release_date: "2005-04-06", poster_path: "/kyY1onYxkKBDlJsheRsVbMaoQEM.jpg", backdrop_path: "/yV2XwKndgi2JI4R7U1eoLNyT5KF.jpg", overview: "Seasoned adventurer and treasure hunter Dirk Pitt, a former Navy SEAL, sets out for the African desert with his wisecracking buddy Al in search of a confederate ironclad battleship rumored to have vanished long ago, the main draw being the treasure supposedly hidden within the lost vessel. When the daring duo come across Dr. Eva Rojas, a beautiful scientist who is juggling an escape from a warlord and a mission to stop the spread of a powerful plague, their desert expedition begins to heat up.", vote_average: 5.914, vote_count: 1635, genre_ids: [28, 12, 35, 18, 9648], runtime: 124, popularity: 6.1467, original_language: "en" },
  9702: { id: 9702, title: "Bound by Honor", release_date: "1993-02-05", poster_path: "/gvP6R6juhe2IpCG7QGDgjyUvm0g.jpg", backdrop_path: "/9xjUZjuYyehv2qnqMH0oR9nSTft.jpg", overview: "Based on the true life experiences of poet Jimmy Santiago Baca, the film focuses on half-brothers Paco and Cruz, and their bi-racial cousin Miklo. It opens in 1972, as the three are members of an East L.A. gang known as the \"Vatos Locos\", and the story focuses on how a violent crime and the influence of narcotics alter their lives. Miklo is incarcerated and sent to San Quentin, where he makes a \"home\" for himself. Cruz becomes an exceptional artist, but a heroin addiction overcomes him with tragic results. Paco becomes a cop and an enemy to his \"carnal\", Miklo.", vote_average: 8.141, vote_count: 1513, genre_ids: [80, 18, 53], runtime: 190, popularity: 8.4245, original_language: "en" },
  2100: { id: 2100, title: "The Last Castle", release_date: "2001-10-19", poster_path: "/pYnUfauPVK6g8IRO2REYl4TUZ2p.jpg", backdrop_path: "/mYnCnyGxdtXo2PDhhyFT0er9sp5.jpg", overview: "A court-martialed general rallies together 1200 inmates to rise against the system that put him away.", vote_average: 7.174, vote_count: 1410, genre_ids: [28, 18, 53], runtime: 131, popularity: 4.5041, original_language: "en" },
  2085: { id: 2085, title: "Romeo Must Die", release_date: "2000-03-22", poster_path: "/zKrnaTWW63y4Q1XLrdZQyQmcRWd.jpg", backdrop_path: "/hq5bbmRj65ald90E3PlWyzOtl7D.jpg", overview: "Two warring gang families (one African-American, the other Chinese) maneuver for bragging rights to the Oakland, California, docks. Hang Sing and Trish O'Day uncover a trail of deceit that leaves most of the warring factions dead … or worse!", vote_average: 6.264, vote_count: 1326, genre_ids: [28, 80, 53], runtime: 115, popularity: 5.7759, original_language: "en" },
  9923: { id: 9923, title: "Domino", release_date: "2005-10-14", poster_path: "/pZdIfYkM5kV5BaUDYzwzgmpUxno.jpg", backdrop_path: "/n6KcrQTZSdh8giDiYxe2EymRy1.jpg", overview: "The story of the life of Domino Harvey, who abandoned her career as a Ford model to become a bounty hunter.", vote_average: 5.915, vote_count: 1281, genre_ids: [28, 80, 18, 53], runtime: 127, popularity: 3.436, original_language: "en" },
  8012: { id: 8012, title: "Get Shorty", release_date: "1995-10-20", poster_path: "/r82SdPhg4fnIcLt0ogIjQxqjdcO.jpg", backdrop_path: "/wiZT8DVmAZNwmqd8G3QjWZ1mpLB.jpg", overview: "Chili Palmer is a Miami mobster who gets sent to L.A. to collect a bad debt from Harry Zimm, a Hollywood producer who specializes in cheesy horror films. When Chili meets Harry's leading lady, the romantic sparks fly. After pitching his own life story as a movie idea, Chili learns that being a mobster and being a Hollywood producer really aren't all that different.", vote_average: 6.505, vote_count: 1204, genre_ids: [35, 53, 80], runtime: 105, popularity: 3.7666, original_language: "en" },
