  581859: { id: 581859, title: "Da 5 Bloods", release_date: "2020-06-12", poster_path: "/yx4cp1ljJMDSFeEex0Zjv45b55E.jpg", backdrop_path: "/Aq5Zhj9iaTF6BEKNk05dlUxeHKa.jpg", overview: "Four African-American Vietnam veterans return to Vietnam. They are in search of the remains of their fallen squad leader and the promise of buried treasure. These heroes battle forces of humanity and nature while confronted by the lasting ravages of the immorality of the Vietnam War.", vote_average: 6.45, vote_count: 1162, genre_ids: [10752, 18], runtime: 155, popularity: 2.7138, original_language: "en" },
  10329: { id: 10329, title: "Congo", release_date: "1995-06-09", poster_path: "/hPNSToNIIpRO6y5Rh973leqQqNr.jpg", backdrop_path: "/dT8Fhrh3eVazbuSSIarFPXniQh4.jpg", overview: "Eight people embark on an expedition into the Congo, a mysterious expanse of unexplored Africa, where human greed and the laws of nature have gone berserk.", vote_average: 5.595, vote_count: 978, genre_ids: [28, 12, 878], runtime: 109, popularity: 3.9033, original_language: "en" },
  11088: { id: 11088, title: "Heist", release_date: "2001-11-09", poster_path: "/lBRaTXBY617wPkpKsrthj5GeRrD.jpg", backdrop_path: "/1acmRn1cnPnavQGQCrIJOERd6vX.jpg", overview: "Joe Moore has a job he loves. He's a thief. His job goes sour when he gets caught on security camera tape. His fence, Bergman, reneges on the money he's owed, and his wife may be betraying him with the fence's young lieutenant. Moore and his partner, Bobby Blane, and their utility man, Pinky Pincus, find themselves broke, betrayed, and blackmailed. Moore is forced to commit his crew to do one last big job.", vote_average: 6.329, vote_count: 610, genre_ids: [28, 80, 18, 53], runtime: 107, popularity: 2.677, original_language: "en" },
