  20649: { id: 20649, title: "Clockers", release_date: "1995-09-15", poster_path: "/c79uqLJleho2a7OQayfrW5Ypphf.jpg", backdrop_path: "/xhYs4yaBnDNM3utncVzLmFVpAmK.jpg", overview: "Strike is a young city drug pusher under the tutelage of drug lord Rodney Little. When a night manager at a fast-food restaurant is found with four bullets in his body, Strike’s older brother turns himself in as the killer. Detective Rocco Klein doesn’t buy the story, however, setting out to find the truth, and it seems that all the fingers point toward Strike & Rodney.", vote_average: 6.709, vote_count: 351, genre_ids: [80, 18, 9648], runtime: 128, popularity: 2.5568, original_language: "en" },
  426375: { id: 426375, title: "Malicious", release_date: "2018-06-23", poster_path: "/ms6V9gUMcw6T6ENgUCU7SL5x7dl.jpg", backdrop_path: "/5Iw2ArIWqy5PQnGgLi2ZTEtdrgp.jpg", overview: "A young college professor and his pregnant wife unwittingly release a malevolent entity with murderous intentions.", vote_average: 5.6, vote_count: 183, genre_ids: [53, 27], runtime: 90, popularity: 1.6039, original_language: "en" },
  34152: { id: 34152, title: "Crooklyn", release_date: "1994-05-13", poster_path: "/iFqe07F78SO0SIBzWcK4I5MwNvP.jpg", backdrop_path: "/mIKuvEhBvDf9LGxE9x6m0hDR9Au.jpg", overview: "From Spike Lee comes this vibrant semi-autobiographical portrait of a school-teacher, her stubborn jazz-musician husband and their five kids living in '70s Brooklyn.", vote_average: 6.8, vote_count: 156, genre_ids: [35, 18], runtime: 114, popularity: 2.3619, original_language: "en" },
