  54271: { id: 54271, title: "The Big Bang", release_date: "2011-02-03", poster_path: "/hDBDk1wWOQ7PYSaGKbv8dEsFVYB.jpg", backdrop_path: "/cTEin0cexPJVpuCpybdbZYrYnD0.jpg", overview: "A private detective is hired to find a missing stripper but the job turns complicated when everyone he questions ends up dead. From the mean streets of Los Angeles to the desolate desert of New Mexico, Cruz must contend with a brutal Russian Boxer, three brash LAPD detectives, an aged billionaire looking for the Big Bang, and the billionaire's stunningly gorgeous wife. The solution to the mystery will cost ten lives, net $30 million and just might explain - well - everything.", vote_average: 5.3, vote_count: 145, genre_ids: [28, 9648, 53], runtime: 101, popularity: 1.765, original_language: "en" },
  15250: { id: 15250, title: "This Christmas", release_date: "2007-11-27", poster_path: "/dBuLAw4mRlO83LPA2s4zOlVesUe.jpg", backdrop_path: "/qUTY0w0ZQ15siNdu3Nfa88T5gqV.jpg", overview: "This year Christmas with the Whitfields promises to be one they will never forget. All the siblings have come home for the first time in years and they've brought plenty of baggage with them. As the Christmas tree is trimmed and the lights are hung, secrets are revealed and family bonds are tested. As their lives converge, they join together and help each other discover the true meaning of family.", vote_average: 6.6, vote_count: 140, genre_ids: [35, 18, 10749], runtime: 117, popularity: 2.0689, original_language: "en" },
  33796: { id: 33796, title: "Mountains of the Moon", release_date: "1990-02-16", poster_path: "/uWWrigxf4yU1WmaTkxg3qYNMezG.jpg", backdrop_path: "/xCCqXJQx9Yr1qc2IABO1fwJT2lR.jpg", overview: "The story of Captain Richard Francis Burton's and Lt. John Hanning Speke's expedition to find the source of the Nile river in the name of Queen Victoria's British Empire.", vote_average: 6.506, vote_count: 85, genre_ids: [12, 18, 36], runtime: 136, popularity: 1.8823, original_language: "en" },
  739010: { id: 739010, title: "LX 2048", release_date: "2020-09-25", poster_path: "/u5VqBL0TtNmV1kxwoQ2L2dWPLiM.jpg", backdrop_path: "/zSDVhorpnrd5IvafeOpelOUnb8X.jpg", overview: "In the near future, the sun has become so toxic people can no longer leave their houses in daytime, and normal life is conducted mostly inside the virtual realm. Against this dystopian backdrop, a dying man seeks to ensure the future well-being of his family, while coping with what it means to be human in this new reality.", vote_average: 5.078, vote_count: 77, genre_ids: [878, 18], runtime: 103, popularity: 1.4534, original_language: "en" },
