  25334: { id: 25334, title: "Wondrous Oblivion", release_date: "2004-04-23", poster_path: "/icOESDabUE6UTaS9vXV7t1IGLfH.jpg", backdrop_path: "/phifQtHo3WfVXBKYWDsIVrg4jFG.jpg", overview: "David Wiseman is eleven years old and mad about cricket. He has all the kit but none of the skill. When a Jamaican family moves in next door the father starts giving cricket lessons to David, and becomes close to David's mother. But this is 1960's London, and when the locals start making life difficult for the new arrivals, David has to choose between fitting and and standing up for his new friends", vote_average: 6.614, vote_count: 22, genre_ids: [18], runtime: 106, popularity: 0.817, original_language: "en" },
  50296: { id: 50296, title: "First Time Felon", release_date: "1997-09-06", poster_path: "/9FFUIycnveVyGrUWuK3HzPzKF4M.jpg", backdrop_path: "/xHK1N3Zf98CeleVswvdRneC7mRA.jpg", overview: "Inspired by the true story of Greg Yance. In the film, Yance (Epps) is a hood who goes to jail for possession of drugs. He is given a choice: 5 years in jail or a couple of months in boot camp. He chooses boot camp and finds out it is tougher than he thought it would be. He braves it through and comes home a better man. He then has to deal with the real world, and never gives up no matter what the odds.", vote_average: 6.85, vote_count: 20, genre_ids: [18], runtime: 110, popularity: 1.2034, original_language: "en" },
  124868: { id: 124868, title: "The Winner", release_date: "1996-09-13", poster_path: "/2YvqSuIbQQTn4otgrwMKXHesEfa.jpg", backdrop_path: "/ltSjFAKdkpHMuUBtXnKRnyGMo7e.jpg", overview: "A long lucky streak makes a nice guy the target of opportunists like his brother, his girlfriend, and some guys from New Jersey.", vote_average: 4.639, vote_count: 18, genre_ids: [53, 35, 80], runtime: 92, popularity: 1.4451, original_language: "en" },
