  113137: { id: 113137, title: "The Book of Stars", release_date: "1999-06-06", poster_path: "/gFENT62A46UcwmzxT6rYd3CXn7g.jpg", backdrop_path: "/fdKhGNviYV7iV10SBXZMZtpCtpE.jpg", overview: "An emotionally crippled woman (Mary Stuart Masterson) turns to prostitution to help care for her sister (Jena Malone), who has cystic fibrosis.", vote_average: 4.636, vote_count: 11, genre_ids: [18], runtime: 111, popularity: 0.849, original_language: "en" },
  74942: { id: 74942, title: "Soul of the Game", release_date: "1996-04-20", poster_path: "/pApMIEzKnU04bQr0hyO23JVMVjR.jpg", backdrop_path: "/a91sLXmP3C6Tks6RCIPuiUAABLq.jpg", overview: "In 1945, the world of baseball is divided between the Majors and the Negro Leagues - but the time has come for change. One team will be the first to sign a black player and only one player will be the first to take the field. The Brooklyn Dodgers want to make the deal that will make history. But the man they choose will have to be more than a great player -  he has to have the charisma of a star. It soon comes down to three powerful and extraordinary players: legendary pitcher Satchel Paige; the greatest hitter in baseball Josh Gibson; and a rookie by the name of Jackie Robinson. Three player - three friends - three champions. Together they are unbeatable - but only one will cross the home plate into history.", vote_average: 5, vote_count: 10, genre_ids: [36, 18, 10770], runtime: 94, popularity: 1.2849, original_language: "en" },
  219986: { id: 219986, title: "Perfect Witness", release_date: "1989-10-28", poster_path: "/4um0oxAAS4EqRv6YNfcjVYAIaRL.jpg", backdrop_path: "/6WuzOKhjbffEmKuG5m2OJlzKBFr.jpg", overview: "An innocent man is thrust into a political power struggle in this drama. After witnessing a mob killing, New York restaurant owner Sam Paxton (Aidan Quinn) reports the crime. Overzealous attorneys (Brian Dennehy and Stockard Channing) put pressure on Paxton to testify in court, but Paxton is in a tough spot when the mob starts threatening his family. Paxton now faces an impossible choice: testify and put his family at risk … or go to jail.", vote_average: 7.2, vote_count: 5, genre_ids: [53, 80, 18, 10770], runtime: 103, popularity: 1.157, original_language: "en" },
  243462: { id: 243462, title: "The Exonerated", release_date: "2006-03-06", poster_path: "/r79HQKs7lhonFQfAjqpagQ5UFTM.jpg", backdrop_path: null, overview: "Six people tell their stories on a single subject - how they got wrongfully convicted to death penalty, but later got exonerated.", vote_average: 7.6, vote_count: 5, genre_ids: [18, 10770, 80], runtime: 95, popularity: 1.3819, original_language: "fr" },
  55932: { id: 55932, title: "Pros & Cons", release_date: "1999-01-01", poster_path: "/ougm7anCKlsuVv9D9F9PkebgkUO.jpg", backdrop_path: null, overview: "Framed for crimes they didn't commit, two small-timers are headed up the river without a paddle. Now, the only thing that can bail them out is a case of mistaken identity. It's the hysterical prison comedy that's so funny, it's criminal!", vote_average: 3.6, vote_count: 5, genre_ids: [35, 80, 18], runtime: 104, popularity: 1.3744, original_language: "en" },
  110734: { id: 110734, title: "Profoundly Normal", release_date: "2003-02-09", poster_path: "/imLGsrFkojb5kgUNguaaxeKFNyM.jpg", backdrop_path: null, overview: "Donna Lee Shelby, a mentally challenged girl who lives in Forest Haven, an institution for the developmentally disabled, meets Ricardo Thornton, a fellow resident. When Forest Haven is closed by a court order, Donna and Ricardo venture into the real world on their own.", vote_average: 5.333, vote_count: 3, genre_ids: [18, 10749, 10770], runtime: 96, popularity: 1.1835, original_language: "en" },
  545197: { id: 545197, title: "Strange Justice", release_date: "1999-08-29", poster_path: "/QdYKqVqYyn11Xecj4XIM3aka00.jpg", backdrop_path: null, overview: "In this historical drama, U.S. Supreme Court Justice Thurgood Marshall announces his retirement. The White House nominates Clarence Thomas as Marshall's replacement. But Thomas's confirmation hearings are rocked by charges that he sexually harassed Anita Hill, a former assistant. As their conflict plays out in public, a White House aide runs a behind-the-scenes campaign to discredit Hill.", vote_average: 7, vote_count: 2, genre_ids: [18, 10770], runtime: 95, popularity: 1.1622, original_language: "en" },
