  340366: { id: 340366, title: "Question Bridge: Black Males", release_date: "2012-01-01", poster_path: "/gE23qeeMy7dPsIV53Xr0TkMvTmw.jpg", backdrop_path: null, overview: "multiple forms: a gallery installation, a website, a book, and a curriculum. It presents diverse experiences of Black men through a video question-and-answer exchange, a “question bridge,” to break down stereotypes of Black male identity perpetuated by America’s white dominant culture. Thomas and his collaborators traveled across the United States, recording questions from nearly 160 men, bringing the questions to others to answer, and filming additional questions from those respondents that other participants, in turn, could later address. The project enables a large group of men to speak to each other across geographic, economic, political, and generational divisions.", vote_average: 0, vote_count: 0, genre_ids: [], runtime: 180, popularity: 0.2394, original_language: "en" },
