  12197: { id: 12197, title: "Reprise", release_date: "2006-09-08", poster_path: "/9GdptmzKh5Sx1KFiABJeUEt9eS.jpg", backdrop_path: "/l9OZmtjVoFhicaY0PtdmTRKiaSR.jpg", overview: "Fueled by literary aspirations and youthful exuberance, two competitive friends endure the pangs of love, depression, and burgeoning careers.", vote_average: 7.141, vote_count: 248, genre_ids: [18], runtime: 107, popularity: 1.7173, original_language: "no" },
  162394: { id: 162394, title: "Procter", release_date: "2002-08-30", poster_path: "/7dECTHB0or1EyZ0VunZ6NHaMvdy.jpg", backdrop_path: "/2osHlaJP90Ri9jHJcNXTwILOd5B.jpg", overview: "When Charles Procter witnesses a stranger burn to death he doesn’t expect to become part of the gruesome event. Then he discovers a video camera has captured him at the scene. What he discovers on the tape is more disturbing than the stranger’s death.", vote_average: 5.679, vote_count: 14, genre_ids: [18, 9648], runtime: 18, popularity: 0.2092, original_language: "en" },
