  487921: { id: 487921, title: "Sweet Things", release_date: "2017-02-04", poster_path: "/zuuRq3xD1nSng52uzDrioALICWE.jpg", backdrop_path: "/3ETICWwWsWvv7waiE8nPgjMXFPs.jpg", overview: "A woman finally gets the job she's been waiting for, but a sweet offer never comes without a bitter aftertaste.", vote_average: 6.6, vote_count: 10, genre_ids: [18], runtime: 8, popularity: 0.1583, original_language: "no" },
