  484603: { id: 484603, title: "Twigson the Explorer", release_date: "2017-11-17", poster_path: "/4YyKcdmxMdhihp56X8ix9bD6jjH.jpg", backdrop_path: "/tMFT2wMVp0YsidcL6wJ0dfnpJfY.jpg", overview: "Lillebror moves with Twigson and his family to the western part of Norway, but he dreams of even bigger expeditions, like going to the North Pole.", vote_average: 6.4, vote_count: 7, genre_ids: [12, 10751], runtime: 74, popularity: 0.697, original_language: "no" },
  1091489: { id: 1091489, title: "Cake Bomb", release_date: "2023-02-07", poster_path: "/qCEaszM7atcNbSLSQcKOe0Z3yeK.jpg", backdrop_path: "/loGy6Lh06REU34MZ3FIM0G2Nv58.jpg", overview: "Two different, fashionable women are having lunch in a London restaurant. They seem to be doing this on a regular. They start talking about trainees and why women are more adept at doing their \"profession\" than men. This women versus men dialogue becomes our key dialogue for the short. The two women turn out to be part of a \"spy\" organization. While the two talk, a dashing male agent comes in the restaurant. He takes a seat by the bar. The two women explain who he is, a smug member of their opposition all-male program. Young trainees start the process of building a bomb that is being put in a birthday cake. Later, the waitress brings the birthday cake to the man with a candle on it. What happens next? Something sinister or is it just a training lesson?", vote_average: 6.2, vote_count: 4, genre_ids: [35], runtime: 6, popularity: 0.3155, original_language: "en" },
  542465: { id: 542465, title: "Phoenix", release_date: "2018-10-12", poster_path: "/rS1NipCnrEwwz8WbVDu6oaWHhaa.jpg", backdrop_path: "/m9WvRRisVLFBCl55k4yKMxDi879.jpg", overview: "From a young age, Jill has acted as the responsible adult in her small family. She cares for her loving but mentally unstable mother and her younger brother. The news that their estranged father will be visiting on Jill's birthday gives the children much needed hope. When the family is struck by tragedy, Jill keeps it a secret.", vote_average: 6.8, vote_count: 4, genre_ids: [18], runtime: 85, popularity: 1.0306, original_language: "no" },
  549526: { id: 549526, title: "Dog Eat Dog", release_date: "2018-06-10", poster_path: "/1IhggqPmhsNKZ2RMDq5rO8l4UR4.jpg", backdrop_path: "/y5xxWD5IUWY9a0OinM9BSJpJFKj.jpg", overview: "Silje wants to leave her boyfriend, but when she finds him in a half-hearted attempt to hang himself she has to reconsider, in fear of acting reckless.", vote_average: 7.6, vote_count: 4, genre_ids: [35, 18], runtime: 25, popularity: 0.574, original_language: "no" },
  715438: { id: 715438, title: "The Affected", release_date: "2021-06-07", poster_path: "/qfSnX3cRSACoX6QX6cud8TNPdwa.jpg", backdrop_path: "/g5LKdlmdQEss7a2AIThECt3MakD.jpg", overview: "Minutes before a plane's departure, a situation develops. A passenger refuses to sit down to prevent the deportation of another man. The pilot then finds himself having to take a political stand, the last thing he wants to do.", vote_average: 10, vote_count: 1, genre_ids: [35], runtime: 13, popularity: 0.5334, original_language: "no" },
  1401459: { id: 1401459, title: "Fjord", release_date: "2026-08-19", poster_path: "/ttCNqwbCoHnfbuQyrlMdr4QG6c0.jpg", backdrop_path: "/ronUH8vKXQI8hazM7FJvUZtMAY.jpg", overview: "The Gheorghius – Catholic and Romanian - settle in a Norwegian village, the mother’s birthplace. They quickly bond with the Halbergs, who live in the neighbouring house near the bay. Despite their very different upbringings, the children of both families soon become close friends. Until the Gheorghius are suspected of hurting their own children…", vote_average: 0, vote_count: 0, genre_ids: [18], runtime: 146, popularity: 2.2458, original_language: "ro" },
