  9477: { id: 9477, title: "King Arthur", release_date: "2004-07-07", poster_path: "/iKLZEAnjzr51Ij7TJtNejc5CN3i.jpg", backdrop_path: "/zmtOyU6pE6PbyMJiNqiISMOIRS5.jpg", overview: "The story of the Arthurian legend, based on the 'Sarmatian hypothesis' which contends that the legend has a historical nucleus in the Sarmatian heavy cavalry troops stationed in Britain, and that the Roman-British military commander, Lucius Artorius Castus is the historical person behind the legend.", vote_average: 6.303, vote_count: 2911, genre_ids: [12, 10752, 36, 28, 18], runtime: 126, popularity: 6.4297, original_language: "en" },
