  83678: { id: 83678, title: "The Glass-Blower's Children", release_date: "1998-02-27", poster_path: "/mRSEJtlganNQ3kAtFnr0TOk28Ay.jpg", backdrop_path: "/mAjn2ddIjHCNNJmaZZeh0eGoQVf.jpg", overview: "Based on the novel by Maria Gripe, this is the story of two children, Klas and Klara, growing up in the poor Swedish countryside of the mid-19th century. Their father Albert is a glass-blower, famous for his beautiful vases, but still unable to earn enough money for his wife Sofia and the children. At a spring fair a distinguished gentleman arrives and buys all of Albert's glassware. After this nothing will be the same again. Klas and Klara are kidnapped and taken to a strange castle...", vote_average: 5.688, vote_count: 16, genre_ids: [18, 10751], runtime: 110, popularity: 0.6434, original_language: "sv" },
