  125926: { id: 125926, title: "Åke and His World", release_date: "1984-10-26", poster_path: "/l31fLIvqpPkjxcNp3JvaIHqkz2Z.jpg", backdrop_path: "/ivusTVc8FfuieH95ADOmMLPfwIJ.jpg", overview: "Åke and his world is a long, lyrical study of a Swedish country doctor of the 1930s. Åke is the doctor's six-year-old son, from whose point of view the film is told. His best friend is Kalle Nubb. Åke is very frightened of the janitor Bergström as well as the lunatic Anne-Marie.", vote_average: 6.3, vote_count: 15, genre_ids: [18], runtime: 99, popularity: 0.7455, original_language: "sv" },
