  62429: { id: 62429, title: "Peter-No-Tail in Americat", release_date: "1985-12-14", poster_path: "/zs4HsWp79Hdh1M5mc4atmtxIAW9.jpg", backdrop_path: "/o8UW5D6JQ1sIJgW2z0lKJ6QyilT.jpg", overview: "Peter-No-Tail (Pelle Svanslös) is a cat who was born without a tail. He compensates this by studying hard and, much to the dismay of his arch-rival Magnus (Måns), he receives a fancy university degree very few cats in the university town Uppsala, Sweden have obtained. Peter is visited by his American relative Pelle Swanson who invites him to visit his new home country America - in the movie called Americat. There everything is bigger and everything seems possible.", vote_average: 6, vote_count: 12, genre_ids: [16, 10751], runtime: 78, popularity: 1.1489, original_language: "sv" },
