  493913: { id: 493913, title: "Gordon & Paddy", release_date: "2017-12-22", poster_path: "/5XTn061asrm0qRZ5HOQsmkCfMOI.jpg", backdrop_path: "/eOpSMver6GEHLMbWz3ktI34yoXH.jpg", overview: "The forest’s police chief Gordon is about to retire and he needs to find a new assistant. Paddy, a clever mouse with a great sense of smell seems to be the right candidate. Together they have to solve Gordon’s last case – the mystery of squirrel’s missing nuts. Could it be the fox that took them? Gordon and Paddy will soon find out.", vote_average: 6.2, vote_count: 10, genre_ids: [16, 9648, 10751], runtime: 62, popularity: 0.7405, original_language: "sv" },
